window.MEDICAL_DATA = {"manifest":{"id":"medical","title":"Medical Emergencies Review — Medical, Behavioral & Geriatric","subtitle":"The Ultimate Provider Course Reviewer","version":"1.0.0","edition":"Aligned with current GINA, ADA, AHA/ASA stroke, and DSM-5-TR guidance; scoped to the NREMT Paramedic Medical/OB-GYN domain","description":"A comprehensive, self-contained study reviewer for adult medical, behavioral, and geriatric emergencies. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, high-yield flashcards, exam-style quiz questions with rationales, realistic scenarios, and comparison tables. Designed for EMTs, paramedics, and nursing/allied-health students preparing for licensing-style cognitive exams (Prometric-administered, NREMT-aligned).","icon":"stethoscope","color":"#2563eb","accentColor":"#e06090","estimatedHours":10,"difficulty":"Intermediate","certification":"EMT/Paramedic licensing exam preparation (Prometric-administered, NREMT-aligned)","examLink":"https://www.nremt.org/","audience":["EMT","Paramedic","Nursing Student","Allied Health Student"],"prerequisites":["BLS provider competency","Basic patient assessment (see EMPACT reviewer)"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Neurological Emergencies I — Stroke & TIA","section":"Neurological","difficulty":"Intermediate"},{"id":"c02","number":2,"title":"Neurological Emergencies II — Seizures & Altered Mental Status","section":"Neurological","difficulty":"Intermediate"},{"id":"c03","number":3,"title":"Endocrine Emergencies — Hypoglycemia, DKA & HHS","section":"Endocrine","difficulty":"Advanced"},{"id":"c04","number":4,"title":"Respiratory Medical Emergencies — Asthma & COPD","section":"Respiratory","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Obstetric Medical Emergencies — Preeclampsia & Eclampsia","section":"Medical/OB","difficulty":"Intermediate"},{"id":"c06","number":6,"title":"Behavioral Emergencies I — Assessment & De-escalation","section":"Behavioral","difficulty":"Beginner to Intermediate"},{"id":"c07","number":7,"title":"Behavioral Emergencies II — Psychotic & Mood Disorders","section":"Behavioral","difficulty":"Intermediate"},{"id":"c08","number":8,"title":"Behavioral Emergencies III — Personality, Substance-Related & High-Risk Presentations","section":"Behavioral","difficulty":"Advanced"},{"id":"c09","number":9,"title":"Geriatric Emergencies I — Delirium vs. Dementia & Atypical Presentations","section":"Geriatric","difficulty":"Intermediate"},{"id":"c10","number":10,"title":"Geriatric Emergencies II — Polypharmacy, Falls & Elder Abuse Recognition","section":"Geriatric","difficulty":"Intermediate"},{"id":"c11","number":11,"title":"Toxicological & Environmental Medical Presentations","section":"Toxicology","difficulty":"Intermediate"},{"id":"c12","number":12,"title":"Sepsis, GI/Renal Emergencies & General Medical Red Flags","section":"Medical","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Neurological Emergencies I — Stroke & TIA","shortTitle":"Stroke & TIA","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Distinguish stroke from TIA and explain why prehospital care treats both as time-critical.","Differentiate ischemic from hemorrhagic stroke and its field-relevant implications.","Apply a validated prehospital stroke scale to recognize likely stroke.","Recognize findings suggestive of a large-vessel occlusion (LVO) stroke.","Describe field priorities: last-known-well time, glucose check, and rapid transport/notification."],"summary":[{"title":"Stroke vs. TIA — Same Urgency, Different Duration","content":"A stroke is an acute disruption of blood flow to the brain causing neurologic deficit; a transient ischemic attack (TIA) produces the same type of deficit but resolves completely, classically within minutes to an hour, without lasting tissue injury on imaging. Because a TIA cannot be reliably distinguished from an evolving stroke in the field — and because TIA carries a significant short-term risk of a subsequent completed stroke — both are treated with the same urgency: rapid recognition, rapid transport, and rapid hospital notification."},{"title":"Ischemic vs. Hemorrhagic Stroke","content":"Ischemic stroke (the large majority of strokes) results from a clot or other obstruction blocking blood flow; hemorrhagic stroke results from bleeding into or around brain tissue. The two cannot be reliably distinguished in the field by symptoms alone — both cause focal neurologic deficits — which is why field care focuses on rapid recognition and transport rather than attempting to guess the stroke type, leaving that determination to hospital imaging."},{"title":"Validated Prehospital Stroke Scales","content":"The Cincinnati Prehospital Stroke Scale (CPSS) checks three findings — facial droop, arm drift, and speech abnormality — and is widely taught as the entry-level prehospital screening tool. Other validated scales add sensitivity for detecting a large-vessel occlusion (LVO), which may change the destination decision in systems with endovascular-capable centers: the Los Angeles Prehospital Stroke Screen (LAPSS), RACE (Rapid Arterial oCclusion Evaluation), and FAST-ED (which adds eye deviation and denial/neglect to the FAST components). Current stroke guidance continues to endorse using a validated scale for prehospital stroke recognition and LVO screening, with the specific scale and any destination threshold set by the local EMS system."},{"title":"Recognizing Possible Large-Vessel Occlusion","content":"Findings that raise suspicion for LVO stroke — beyond a simple facial droop/arm drift/speech finding — include gaze deviation toward one side, severe unilateral weakness affecting both the face and arm together, and neglect/denial of the deficit (the patient not recognizing or acknowledging a weak limb). Systems with access to an endovascular-capable stroke center may use an LVO-screening scale to decide whether to bypass a closer, non-endovascular-capable hospital, per local protocol."},{"title":"Field Priorities","content":"Once stroke is suspected: determine and document the last-known-well time precisely (this drives eligibility for time-sensitive hospital treatments), check blood glucose (hypoglycemia is a well-known stroke mimic and is rapidly correctable), perform a validated stroke scale, and transport rapidly with early hospital notification (a 'stroke alert') so the receiving facility can prepare. Avoid delaying transport for a full neurologic exam beyond the screening scale — time is the central variable in stroke outcome."}],"clinicalPearls":["TIA and stroke get the same field urgency — a resolved deficit does not rule out a serious ongoing process.","Field care cannot reliably distinguish ischemic from hemorrhagic stroke — treat both as time-critical and let hospital imaging sort it out.","Always check glucose in a suspected stroke patient — hypoglycemia is a correctable stroke mimic.","Last-known-well time is one of the single most important pieces of information you can gather and document."],"redFlags":["Any new focal neurologic deficit (facial droop, arm drift, speech abnormality), even if it has since resolved.","Gaze deviation, severe unilateral face+arm weakness, or neglect of a weak limb — possible LVO.","An unclear or unknown last-known-well time — document what is known and keep gathering it en route."],"commonMistakes":["Dismissing a resolved deficit (possible TIA) as no longer urgent.","Failing to check glucose before assuming a deficit is purely neurologic.","Delaying transport to complete an extensive neurologic exam instead of a rapid validated screening scale."],"memoryAids":["FAST: Face, Arm, Speech, Time.","TIA = stroke symptoms that resolved, not a stroke that didn't happen — same urgency.","Glucose first — a fast, correctable stroke mimic.","Time is brain — last-known-well time drives everything downstream."],"decisionTrees":[{"title":"Suspected Stroke Field Approach","content":"Focal neurologic deficit noted (current or recently resolved)\n  → Check blood glucose → treat hypoglycemia per protocol if present, reassess\n  → Determine and document last-known-well time precisely\n  → Perform validated prehospital stroke scale (e.g., CPSS ± LVO-screening scale per local protocol)\n  → Positive screen → early hospital notification ('stroke alert'), rapid transport per local destination protocol (nearest stroke center vs. EVT-capable center bypass, per LVO screen and system design)\n  → Continue serial reassessment en route; do not delay transport for an extensive exam"}],"references":["2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke","Cincinnati Prehospital Stroke Scale (CPSS); RACE and FAST-ED as examples of LVO-screening scales"]},"c02":{"id":"c02","title":"Neurological Emergencies II — Seizures & Altered Mental Status","shortTitle":"Seizures & AMS","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["List common causes of adult seizures and altered mental status.","Describe the postictal state and distinguish it from ongoing seizure activity.","Define status epilepticus and describe its field management priorities.","Apply a structured framework (AEIOU-TIPS) for reversible causes of altered mental status.","Describe field priorities for a seizing or newly altered adult patient."],"summary":[{"title":"Not All Seizures Are Life-Threatening","content":"Most adult seizures are brief, self-limited events that stop on their own within a couple of minutes. Common causes include idiopathic epilepsy (a known seizure disorder, often with medication non-compliance as a trigger), hypoglycemia, head trauma, intoxication or withdrawal (especially alcohol withdrawal), fever (more classically pediatric but relevant in adults with underlying infection), stroke, and structural brain lesions. Field management for a brief, self-terminating seizure focuses on protecting the patient from injury and airway compromise during the event, not stopping a seizure that has already stopped."},{"title":"The Postictal State","content":"The postictal state is a period of transient confusion, drowsiness, and sometimes agitation that follows a seizure, typically resolving gradually over minutes without specific intervention. It is a normal, expected part of the seizure process, not a separate emergency — but a patient who does not gradually improve, or whose mental status worsens rather than clears, should prompt reconsideration of other causes (ongoing subclinical seizure activity, structural injury, or a coexisting problem like hypoglycemia)."},{"title":"Status Epilepticus","content":"Status epilepticus — a seizure lasting 5 minutes or longer, or repeated seizures without return to baseline between them — is a time-critical emergency distinct from an ordinary brief seizure. It carries real risk of ongoing neuronal injury and cardiorespiratory compromise the longer it continues. Field priorities are airway protection/positioning, oxygen, glucose check, and rapid transport; benzodiazepine administration for status epilepticus follows local ALS protocol."},{"title":"AEIOU-TIPS: A Framework for Altered Mental Status","content":"AEIOU-TIPS is a widely taught mnemonic for reversible causes of altered mental status: Alcohol, Epilepsy/seizure (postictal), Insulin (hypo/hyperglycemia), Overdose/opioids, Uremia (metabolic), Trauma/temperature, Infection, Psychiatric, Stroke/shock. Its main clinical value is prompting a glucose check and a search for a reversible cause before assuming an irreversible or purely psychiatric explanation for a change in mental status."},{"title":"Field Priorities","content":"For an actively seizing patient: protect the airway with positioning and suction as needed (never place anything in the mouth), protect from injury, time the seizure, and check glucose as soon as feasible. For a newly altered but non-seizing patient: check glucose immediately, work through reversible causes, and gather a focused history (medications, known seizure disorder, substance use, recent illness or head injury) from bystanders or family. Any seizure activity lasting 5 minutes or longer, or that does not resolve with usual measures, should prompt escalation as status epilepticus per local protocol."}],"clinicalPearls":["A brief seizure that has already stopped by EMS arrival does not need seizure-stopping medication — protect and reassess.","The postictal state should gradually improve — if it doesn't, look for another cause.","5 minutes is the threshold for status epilepticus — treat it as a time-critical emergency.","Check glucose in every altered or postictal patient — it's fast, safe, and can immediately explain the presentation."],"redFlags":["Seizure activity lasting 5 minutes or longer, or repeated seizures without return to baseline (status epilepticus).","Postictal confusion that worsens instead of gradually improving.","New focal neurologic deficit after a seizure that doesn't resolve as the postictal state clears (consider Todd's paralysis vs. stroke, but don't assume)."],"commonMistakes":["Placing an object in the mouth of a seizing patient.","Assuming all confusion after a seizure is 'just postictal' without checking glucose.","Waiting well past 5 minutes of continuous seizure activity before escalating care."],"memoryAids":["AEIOU-TIPS: reversible causes of altered mental status.","5 minutes = status epilepticus.","Postictal should get better, not worse — a worsening trend means look further.","Protect, don't restrain, don't put anything in the mouth."],"decisionTrees":[{"title":"Seizure and Altered Mental Status Field Approach","content":"Seizure activity or altered mental status noted\n  → If actively seizing: protect airway/position, protect from injury, time the seizure, check glucose\n     <5 minutes, self-terminates → postictal care, monitor for gradual improvement, transport\n     ≥5 minutes or repeated without return to baseline → Status epilepticus → time-critical emergency, escalate per local ALS protocol, rapid transport\n  → If altered but not seizing: check glucose immediately, treat hypoglycemia if present\n     Work through AEIOU-TIPS for reversible causes; gather focused history from bystanders/family\n  → Reassess mental status trend — gradual improvement is reassuring, no improvement or worsening warrants continued investigation and rapid transport"}],"references":["General EMS/paramedic teaching on seizure classification and status epilepticus (5-minute threshold widely adopted in current EMS education)","AEIOU-TIPS mnemonic — standard EMS teaching framework for altered mental status"]},"c03":{"id":"c03","title":"Endocrine Emergencies — Hypoglycemia, DKA & HHS","shortTitle":"Hypoglycemia, DKA & HHS","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["Recognize the field presentation of hypoglycemia and describe its treatment.","Describe the diagnostic framework for diabetic ketoacidosis (DKA).","Describe the diagnostic framework for hyperosmolar hyperglycemic state (HHS).","Differentiate DKA from HHS on field-relevant grounds.","Explain euglycemic DKA and why a normal glucose does not rule out DKA."],"summary":[{"title":"Hypoglycemia — Fast to Recognize, Fast to Fix","content":"Hypoglycemia presents with a spectrum from mild symptoms (shakiness, diaphoresis, hunger, anxiety) to severe presentations (confusion, combativeness, seizure, unresponsiveness) as glucose falls further. It is common, rapidly correctable, and a well-known mimic of stroke, seizure, and behavioral emergencies — which is why a glucose check is a near-universal first step for any altered patient. Field treatment is oral glucose in an awake, cooperative patient with intact airway reflexes, or IV dextrose / IM glucagon per protocol for a patient who cannot safely take oral glucose."},{"title":"Diabetic Ketoacidosis (DKA)","content":"DKA is a hyperglycemic emergency defined by three features together: hyperglycemia (glucose ≥200 mg/dL, or a prior history of diabetes even without meeting this threshold), ketosis (elevated ketones — beta-hydroxybutyrate ≥3.0 mmol/L or urine ketones 2+ or greater), and metabolic acidosis (pH <7.3 and/or bicarbonate <18 mEq/L). Classic field findings include polyuria/polydipsia leading up to the event, nausea/vomiting, abdominal pain, deep rapid (Kussmaul) respirations as a compensatory response to the acidosis, a fruity (acetone) breath odor, and dehydration. DKA is most classically associated with type 1 diabetes but can occur in type 2 diabetes as well, often precipitated by infection, missed insulin doses, or new-onset diabetes."},{"title":"Euglycemic DKA","content":"Approximately 10% of DKA presentations occur with a glucose under 200 mg/dL — euglycemic DKA — most classically associated with SGLT2-inhibitor diabetes medications, but also seen with reduced oral intake, pregnancy, or partial insulin treatment before presentation. This means a normal or only mildly elevated glucose does not rule out DKA if the clinical picture otherwise fits (Kussmaul respirations, fruity breath, vomiting/abdominal pain, known diabetes) — glucose alone is an incomplete screening tool for this condition."},{"title":"Hyperosmolar Hyperglycemic State (HHS)","content":"HHS is a hyperglycemic emergency defined by severe hyperglycemia (often glucose >600 mg/dL), significant hyperosmolality (>320 mOsm/kg), minimal or absent ketosis, and near-normal pH/bicarbonate — distinguishing it from DKA's acidosis-driven picture. HHS is more typically seen in older adults with type 2 diabetes, often with a slower onset over days, profound dehydration, and a more prominent altered-mental-status/obtundation picture than DKA, reflecting the severe hyperosmolar state's direct effect on the brain. Some patients present with mixed features of both DKA and HHS."},{"title":"Field Management","content":"For both DKA and HHS: supportive care (oxygen as needed, IV access and isotonic fluids per protocol, cardiac monitoring), careful attention to mental status and airway protection given the risk of vomiting, and rapid transport — definitive treatment (insulin, careful fluid/electrolyte correction) happens in the hospital. Field providers should always check glucose in any patient with altered mental status, vomiting, abdominal pain, or unexplained rapid breathing, since DKA/HHS can mimic other conditions and the reverse is also true (do not assume every diabetic patient with altered mental status is hypoglycemic without checking)."}],"clinicalPearls":["Hypoglycemia is common, fast, and correctable — check glucose early in any altered patient.","DKA = hyperglycemia (or known diabetes) + ketosis + acidosis, together — not any one feature alone.","About 10% of DKA is euglycemic (glucose <200 mg/dL) — don't rule out DKA on a normal glucose alone if the clinical picture fits.","HHS = severe hyperglycemia + hyperosmolality + minimal ketosis + near-normal pH — a different mechanism than DKA's acidosis."],"redFlags":["Kussmaul respirations, fruity breath odor, vomiting/abdominal pain in a known or new diabetic patient — think DKA even with a near-normal glucose.","Profound dehydration with severe altered mental status/obtundation in an older type 2 diabetic — think HHS.","Any diabetic patient with altered mental status — check glucose rather than assuming the direction of the abnormality."],"commonMistakes":["Ruling out DKA because the glucose is 'not that high,' without considering euglycemic DKA.","Assuming every altered diabetic patient is hypoglycemic without checking glucose.","Treating DKA/HHS field management as identical to a simple hypoglycemia treat-and-reassess — both need IV fluids and rapid transport, not just glucose correction."],"memoryAids":["DKA: hyperglycemia + ketosis + acidosis, all together.","Kussmaul + fruity breath = think DKA.","HHS: sky-high glucose, sky-high osmolality, minimal ketones.","10% of DKA hides behind a normal-ish glucose — euglycemic DKA is real."],"decisionTrees":[{"title":"Suspected Diabetic Emergency Field Approach","content":"Altered mental status, vomiting, abdominal pain, or unexplained rapid breathing in a known or possible diabetic\n  → Check blood glucose immediately\n  → Low glucose → treat hypoglycemia per protocol (oral glucose if awake/cooperative; IV dextrose or IM glucagon per protocol if not) → reassess\n  → High or near-normal glucose with Kussmaul respirations, fruity breath, vomiting/abdominal pain, dehydration → suspect DKA (consider euglycemic DKA even if glucose is only mildly elevated) → supportive care, IV fluids per protocol, rapid transport\n  → Very high glucose with severe dehydration, minimal respiratory compensation, and profound altered mental status in an older type 2 diabetic → suspect HHS → supportive care, IV fluids per protocol, rapid transport\n  → All suspected DKA/HHS: monitor airway closely given vomiting risk, transport for definitive hospital treatment"}],"references":["ADA Standards of Care in Diabetes—2026, Section 16 (Diabetes Care in the Hospital)","2024 ADA Consensus Report: Hyperglycemic Crises in Adults With Diabetes"]},"c04":{"id":"c04","title":"Respiratory Medical Emergencies — Asthma & COPD","shortTitle":"Asthma & COPD","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Describe current GINA 2025 stepwise asthma management framework.","Contrast current asthma-control framing with legacy 'phase 1-4' severity language.","Distinguish chronic bronchitis from emphysema on classic exam presentation.","Explain why the 'hypoxic drive' teaching is outdated and describe current oxygen guidance for COPD.","Describe field management priorities for acute asthma and COPD exacerbations."],"summary":[{"title":"Current Asthma Framework: Control-Based, Not Severity-Labeled","content":"GINA 2025 organizes asthma treatment around a dual-track, ICS (inhaled corticosteroid)-formoterol-centered stepwise approach (Steps 1-4), graded primarily by how well symptoms are controlled rather than a fixed severity label assigned once. This represents a shift away from the older 'intermittent / mild-moderate-severe persistent' classification language that many EMS courses historically taught. For field purposes, what matters most is recognizing the acute presentation and its severity in the moment (mild, moderate, severe, or life-threatening/respiratory failure), not classifying the patient's long-term asthma control category."},{"title":"Legacy 'Phase 1-4' Language — Historical, Not Current Guideline Terminology","content":"Some EMS exam banks use a legacy four-phase asthma framework: phase 1 (resolves spontaneously or with bronchodilators within 1-2 hours), phase 2 (does not respond to bronchodilators alone, needs anti-inflammatory treatment), phase 3 and 4 progressing toward severe, treatment-refractory presentations and respiratory failure. This framework is a simplified historical teaching tool, not current GINA terminology — it is presented here as vocabulary you may encounter on an exam, while the clinically current framework is GINA's step-based, control-oriented approach."},{"title":"Chronic Bronchitis vs. Emphysema","content":"Both fall under the umbrella of COPD, and many patients have features of both. Chronic bronchitis is strongly associated with cigarette-smoke exposure, presents with a chronic productive cough, and classically produces a stockier, sometimes cyanotic appearance sometimes nicknamed 'blue bloater.' Emphysema classically produces a thin, barrel-chested appearance with pursed-lip breathing, sometimes nicknamed 'pink puffer,' reflecting different degrees of air-trapping, gas-exchange impairment, and compensatory work of breathing between the two classic (and overlapping, in practice) presentations."},{"title":"The 'Hypoxic Drive' Myth","content":"The traditional teaching that COPD patients rely on hypoxia (rather than CO2) to drive their respiratory effort, and that supplemental oxygen will therefore cause respiratory arrest, is an outdated oversimplification not supported by current evidence. Oxygen-induced hypercapnia in COPD, when it occurs, results primarily from ventilation-perfusion mismatch and increased dead space — not loss of respiratory drive. Current guidance is titrated oxygen therapy targeting an SpO2 of roughly 88-92% in acute COPD exacerbation: enough to avoid dangerous hypoxia, without unnecessary over-oxygenation. Deliberately withholding oxygen from a hypoxic COPD patient out of fear of 'hypoxic drive' creates a real risk of harmful, prolonged tissue hypoxia and is not current best practice."},{"title":"Field Management","content":"For acute asthma exacerbation: assess severity (ability to speak in full sentences, accessory muscle use, wheeze intensity — note that a 'silent chest' with minimal air movement is more ominous than a loud wheeze), administer bronchodilator therapy per protocol, and escalate rapidly for signs of impending respiratory failure (altered mental status, exhaustion, decreasing wheeze with worsening distress). For acute COPD exacerbation: titrated oxygen to target saturation, bronchodilator therapy per protocol, and monitoring for signs of respiratory failure requiring ventilatory support. Both conditions can progress quickly from distress to failure — reassess frequently."}],"clinicalPearls":["GINA 2025 uses a control-based step framework (Steps 1-4), not the older 'intermittent/mild/moderate/severe persistent' labels.","The legacy 'asthma phase 1-4' bank language is historical/simplified vocabulary, not current guideline terminology.","A silent chest (minimal air movement) is more dangerous than a loud wheeze — it means too little air is moving to make noise.","'Hypoxic drive' is an outdated myth — titrate COPD oxygen to 88-92% SpO2, don't withhold it out of fear."],"redFlags":["A silent chest or rapidly decreasing wheeze with worsening distress — signals near-complete airway obstruction, not improvement.","Inability to speak in full sentences, accessory muscle use, or altered mental status in an asthma/COPD exacerbation.","Withholding oxygen from a hypoxic COPD patient — this itself is a red flag in provider practice, not a safety measure."],"commonMistakes":["Reassurance from a quieting wheeze without checking for exhaustion/impending failure (same pattern as pediatric respiratory failure).","Applying the outdated binary 'true/false hypoxic drive' framing instead of titrated-target oxygen guidance.","Confusing the legacy 'phase 1-4' asthma language with GINA's current step-based framework."],"memoryAids":["Steps, not stages — GINA 2025 is step-based and control-oriented.","Blue bloater = chronic bronchitis; pink puffer = emphysema.","88-92% is the COPD oxygen target — titrate, don't withhold.","Silent chest is scarier than loud wheeze."],"decisionTrees":[{"title":"Acute Asthma/COPD Exacerbation Field Approach","content":"Respiratory distress with wheeze/known asthma or COPD history\n  → Assess severity: ability to speak in full sentences, accessory muscle use, wheeze intensity (silent chest = more severe, not less)\n  → Mild-moderate distress → bronchodilator therapy per protocol, position of comfort, monitor closely\n  → Severe distress or signs of impending failure (altered mental status, exhaustion, silent chest) → escalate rapidly, prepare for ventilatory support, rapid transport\n  → If known/suspected COPD: apply titrated oxygen targeting ~88-92% SpO2 — do not withhold oxygen from a hypoxic patient\n  → Reassess frequently; a quieting wheeze with worsening distress is a warning sign, not reassurance"}],"references":["GINA 2025 Global Strategy for Asthma Management and Prevention","Current EMS/respiratory literature on oxygen-induced hypercapnia in COPD and titrated oxygen targets"]},"c05":{"id":"c05","title":"Obstetric Medical Emergencies — Preeclampsia & Eclampsia","shortTitle":"Preeclampsia & Eclampsia","estimatedStudyTime":25,"difficulty":"Intermediate","learningObjectives":["Define preeclampsia and identify its core diagnostic features.","Define eclampsia and describe how it differs from preeclampsia.","Recognize field-relevant warning signs of worsening preeclampsia.","Describe field management priorities for a pregnant patient with suspected preeclampsia or an active eclamptic seizure.","Identify positioning and general supportive care considerations specific to pregnancy."],"summary":[{"title":"Preeclampsia — Hypertension Plus Proteinuria in Pregnancy","content":"Preeclampsia is a pregnancy-specific condition defined by new-onset hypertension (typically after 20 weeks of gestation) plus proteinuria, or hypertension plus evidence of other organ dysfunction (e.g., liver involvement, low platelets, kidney impairment, pulmonary edema, or new headache/visual disturbance) even without proteinuria. It is a systemic condition, not simply 'high blood pressure in pregnancy' — the field-relevant point is that it reflects a broader process that can progress toward severe complications, including eclampsia."},{"title":"Eclampsia — Preeclampsia Plus Seizures or Coma","content":"Eclampsia is defined as preeclampsia with the addition of new seizures or coma that cannot be attributed to another cause. It represents a severe progression of the same underlying process and is a true obstetric emergency. Eclamptic seizures are generally managed like any other seizure in terms of airway protection and injury prevention, but with pregnancy-specific considerations for positioning and the recognition that magnesium sulfate (not typically a benzodiazepine alone) is the definitive treatment used in the hospital/ALS setting for eclamptic seizures, per local protocol."},{"title":"Warning Signs of Worsening Preeclampsia","content":"Field-relevant warning signs that preeclampsia may be worsening toward severe disease or eclampsia include: severe or persistent headache, visual disturbances (blurred vision, seeing spots, temporary vision loss), right upper quadrant or epigastric pain (suggesting liver involvement), sudden significant swelling (especially of the face and hands), and markedly elevated blood pressure. Any of these in a pregnant patient (typically past 20 weeks) should prompt treating the situation as a potential obstetric emergency rather than a routine complaint."},{"title":"Field Management — Preeclampsia","content":"For a pregnant patient with suspected preeclampsia (hypertension with any of the warning signs above): position the patient in a left lateral tilt or with manual uterine displacement if late in pregnancy (to avoid aortocaval compression from the gravid uterus reducing venous return), minimize stimulation (bright lights, loud noise) since these can precipitate seizure in severe preeclampsia, monitor blood pressure closely, and transport promptly to an appropriate facility with obstetric capability."},{"title":"Field Management — Eclamptic Seizure","content":"For an active eclamptic seizure: protect the airway and the patient from injury (standard seizure precautions), position in left lateral tilt if feasible once the seizure allows, minimize stimulation, and transport rapidly — magnesium sulfate administration for eclampsia follows local ALS protocol. After the seizure, continue to monitor for a repeat seizure and for signs of ongoing severe preeclampsia, and maintain left lateral positioning during transport when possible."}],"clinicalPearls":["Preeclampsia = hypertension + proteinuria (or hypertension + other organ dysfunction) after 20 weeks — a systemic condition, not just high blood pressure.","Eclampsia = preeclampsia + new seizures or coma not attributable to another cause.","Severe headache, visual changes, and right upper quadrant/epigastric pain in a pregnant patient are obstetric red flags, not routine complaints.","Left lateral positioning helps prevent aortocaval compression in a pregnant patient late in pregnancy."],"redFlags":["New severe headache or visual disturbance in a pregnant patient past 20 weeks.","Right upper quadrant or epigastric pain in a pregnant patient with hypertension.","Any new seizure activity in a pregnant or recently pregnant patient — treat as possible eclampsia until proven otherwise."],"commonMistakes":["Treating a pregnant patient's headache or visual complaint as routine without considering preeclampsia.","Transporting a late-pregnancy patient supine without left lateral tilt/uterine displacement.","Managing an eclamptic seizure exactly like a standard seizure without positioning/stimulation considerations specific to pregnancy."],"memoryAids":["Preeclampsia: pressure + protein (or pressure + organ trouble).","Eclampsia: preeclampsia plus a seizure.","Headache, vision changes, RUQ pain in pregnancy = red flags, not routine.","Tilt left to protect the vena cava."],"decisionTrees":[{"title":"Suspected Preeclampsia/Eclampsia Field Approach","content":"Pregnant patient (typically >20 weeks) with hypertension and/or seizure\n  → Hypertension + proteinuria (or other organ dysfunction: headache, visual changes, RUQ/epigastric pain, edema) → suspect preeclampsia → left lateral positioning, minimize stimulation, monitor BP closely, transport to obstetric-capable facility\n  → New seizure or coma in a patient with preeclampsia (or unexplained pregnancy-associated seizure) → suspect eclampsia → protect airway/injury per standard seizure precautions, left lateral positioning once feasible, minimize stimulation, rapid transport (magnesium sulfate per local ALS protocol)\n  → Continue monitoring for repeat seizure and worsening signs during transport"}],"references":["Standard obstetric emergency teaching on preeclampsia/eclampsia definitions and field management (hypertensive disorders of pregnancy)"]},"c06":{"id":"c06","title":"Behavioral Emergencies I — Assessment & De-escalation","shortTitle":"Behavioral Assessment & De-escalation","estimatedStudyTime":25,"difficulty":"Beginner to Intermediate","learningObjectives":["Describe the general approach to assessing a patient in behavioral crisis.","List the SEA-3 framework components for behavioral assessment.","Describe de-escalation techniques appropriate for prehospital behavioral emergencies.","Recognize when scene safety concerns should take priority over immediate patient contact.","Define abandonment in the context of behavioral-health patient care."],"summary":[{"title":"Scene Safety First, Always","content":"Behavioral emergencies carry a scene-safety dimension that other medical calls may not: agitated, psychotic, or intoxicated patients can become unpredictably violent. Before approaching, assess for weapons, exits, and the patient's affect from a distance; involve law enforcement per local protocol when there is any credible safety concern. This is not optional caution — provider safety is a prerequisite for being able to help the patient at all."},{"title":"SEA-3: A Structured Behavioral Assessment Framework","content":"SEA-3 is a widely taught framework organizing behavioral assessment around: Safety (scene and patient safety), Emotional state (the patient's observable mood/affect), Appearance (grooming, hygiene, dress as clues to functioning), Activity (psychomotor activity — agitation, retardation, restlessness), and Speech (rate, volume, coherence, content). Working through these systematically, rather than fixating only on the chief complaint, produces a more complete picture and helps identify risk (e.g., disorganized speech plus poor grooming plus psychomotor agitation together paint a different risk picture than any single finding alone)."},{"title":"De-escalation Technique","content":"Core de-escalation principles: approach calmly and non-confrontationally, use open-ended questions rather than rapid-fire closed questions, maintain a non-threatening posture and appropriate distance, avoid sudden movements, speak in a calm and even tone, and avoid arguing with or directly challenging delusional content. The goal is to reduce the patient's perceived threat level and build enough cooperation to complete an assessment and safely transport, not to resolve the underlying psychiatric condition in the field."},{"title":"Physical Restraint — Last Resort, Not First Response","content":"Premature physical restraint escalates risk for both patient and provider and should be avoided as a first response. Restraint is reserved for situations where de-escalation has failed and the patient poses an immediate danger to self or others, and should follow local protocol regarding technique, monitoring, and documentation. Chemical or physical restraint decisions and technique are governed by local protocol and are not detailed further in this reviewer beyond this recognition-level framing."},{"title":"Abandonment and Duty to Act","content":"Abandonment is terminating patient care without ensuring that an equal or higher level of care continues — a legally and ethically significant concept in EMS generally, with particular relevance in behavioral emergencies where a patient may refuse care or attempt to leave. Providers must understand the difference between a competent patient exercising the right to refuse care (with proper informed-refusal documentation) and inappropriately discontinuing care for a patient who lacks capacity to refuse or who is being handed off improperly. This distinction is a common exam topic and a real clinical/legal issue in the field."}],"clinicalPearls":["Scene safety comes before patient contact in behavioral emergencies — assess from a distance first.","SEA-3: Safety, Emotional state, Appearance, Activity, Speech.","De-escalate with calm, open-ended questions and non-threatening posture — don't argue with delusional content.","Abandonment = terminating care without ensuring an equal-or-higher level of care continues."],"redFlags":["Visible weapons or an unpredictable, escalating patient — involve law enforcement before approaching.","Disorganized speech, poor grooming, and psychomotor agitation together — a higher-risk combination than any single finding.","A patient attempting to leave or refusing care whose capacity to make that decision is in question."],"commonMistakes":["Approaching an agitated patient without first assessing scene safety from a distance.","Arguing with or directly challenging a patient's delusional content during de-escalation.","Jumping to physical restraint before attempting de-escalation techniques."],"memoryAids":["SEA-3: Safety, Emotional state, Appearance, Activity, Speech.","Distance first, approach second.","Restraint is last resort, not first response.","Abandonment = leaving without an equal-or-higher level of care taking over."],"decisionTrees":[{"title":"Behavioral Emergency Field Approach","content":"Dispatched to a behavioral emergency\n  → Assess scene safety from a distance first: weapons, exits, patient affect\n  → Safety concern present → involve law enforcement per local protocol before approaching\n  → Scene safe → approach calmly, apply SEA-3 assessment (Safety, Emotional state, Appearance, Activity, Speech)\n  → Apply de-escalation technique: open-ended questions, non-threatening posture, calm tone, avoid arguing with delusional content\n  → De-escalation successful → complete assessment, transport with continued calm approach\n  → De-escalation fails, immediate danger to self/others → restraint per local protocol as last resort, with appropriate monitoring/documentation\n  → Patient refuses care → assess capacity, follow informed-refusal protocol; do not terminate care without ensuring appropriate continuity (avoid abandonment)"}],"references":["SEA-3 behavioral assessment framework — standard EMS/paramedic behavioral-emergency teaching","Standard EMS legal/ethical teaching on abandonment and duty to act"]},"c07":{"id":"c07","title":"Behavioral Emergencies II — Psychotic & Mood Disorders","shortTitle":"Psychotic & Mood Disorders","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Distinguish a delusion from a hallucination.","Recognize common presentations of psychotic disorders relevant to prehospital care.","Describe mood disorder presentations (major depressive episode, manic episode) relevant to field recognition.","Recognize panic disorder and PTSD presentations and distinguish them from other emergencies.","Apply a structured suicide-risk recognition approach appropriate to the EMT/paramedic scope."],"summary":[{"title":"Delusion vs. Hallucination","content":"A delusion is a fixed, false belief that persists despite clear evidence against it (e.g., a conviction of being surveilled or persecuted without any factual basis). A hallucination is a false sensory perception with no external stimulus (e.g., hearing voices that aren't there, seeing things that aren't present) — it involves the senses, while a delusion involves belief. Both can occur in psychotic disorders, and distinguishing them matters for accurate recognition-level vocabulary, though field management (calm, non-confrontational approach, avoid arguing with the content) is similar for both."},{"title":"Psychotic Disorder Presentations","content":"Psychotic symptoms — delusions, hallucinations, disorganized speech/behavior, diminished emotional expression — can occur in primary psychotic disorders (such as schizophrenia), as part of a mood disorder with psychotic features, or secondary to a medical cause (substance intoxication/withdrawal, delirium, or another organic process). Prehospital providers are not expected to differentiate the underlying diagnosis — the priority is safe assessment, ruling out or recognizing an organic/reversible cause (glucose, vital signs, evidence of trauma or substance use) when feasible, and safe transport."},{"title":"Mood Disorder Presentations","content":"A major depressive episode presents with persistent low mood, loss of interest/pleasure, changes in sleep/appetite, low energy, and in more severe cases, suicidal ideation — field-relevant because it is a leading risk factor for suicide risk assessment. A manic episode presents with elevated or irritable mood, decreased need for sleep, rapid/pressured speech, grandiosity, and risky or impulsive behavior — field-relevant because impaired judgment during mania can create acute safety risks (reckless behavior, financial/legal risk-taking, occasionally aggression when the patient's grandiose beliefs are challenged)."},{"title":"Panic Disorder and PTSD","content":"Panic disorder presents with recurrent, discrete episodes of intense fear accompanied by physical symptoms (tachycardia, dyspnea, chest tightness, dizziness, a sense of impending doom) that can closely mimic a cardiac or respiratory emergency — field providers should still rule out true medical emergencies (ECG, vitals, glucose) rather than assuming panic disorder based on history alone, since panic attacks and genuine medical emergencies can coexist or be mistaken for one another. PTSD (post-traumatic stress disorder) involves re-experiencing symptoms, avoidance, negative mood/cognition changes, and hyperarousal following a traumatic event, and can be triggered or worsened by reminders of the trauma — including, sometimes, aspects of the EMS encounter itself (uniforms, restraint, physical contact), which is a reason to explain actions calmly before performing them when feasible."},{"title":"Suicide Risk Recognition","content":"At the EMT/paramedic level, the goal is risk recognition, not risk stratification or diagnosis. Direct, non-judgmental questioning about suicidal thoughts does not increase risk and is appropriate when clinically indicated — asking does not 'put the idea in their head.' Any patient expressing suicidal ideation, especially with a specific plan, access to lethal means, or a prior attempt history, should be treated as a high-risk presentation requiring careful scene safety consideration, a calm and supportive approach, and transport for evaluation; local protocol governs specifics such as means restriction and involuntary-hold criteria."}],"clinicalPearls":["Delusion = false belief; hallucination = false sensory perception. Different phenomena, similar calm non-confrontational approach.","Prehospital providers don't need to diagnose the underlying psychotic condition — focus on safe assessment and ruling out reversible/organic causes when feasible.","Panic attacks can look exactly like cardiac emergencies — rule out true medical causes rather than assuming panic disorder from history alone.","Asking directly about suicidal ideation does not increase risk — it's an appropriate, necessary question when indicated."],"redFlags":["Suicidal ideation with a specific plan, access to lethal means, or a prior attempt history.","New psychotic symptoms with an unclear cause — don't assume purely psychiatric without considering an organic/reversible cause.","Chest pain/dyspnea in a patient with known panic disorder — still rule out a true cardiac/respiratory emergency."],"commonMistakes":["Confusing delusions and hallucinations as interchangeable terms.","Assuming a patient's chest pain/dyspnea is 'just a panic attack' without appropriate medical rule-out.","Avoiding direct questions about suicidal ideation out of a mistaken belief that asking increases risk."],"memoryAids":["Delusion = belief; hallucination = perception.","Rule out the body before you settle on the mind — especially for panic-like presentations.","Asking about suicide doesn't cause it — silence doesn't prevent it.","Mania: less sleep needed, more risk taken."],"decisionTrees":[{"title":"Psychotic/Mood Disorder Field Recognition Approach","content":"Patient with psychotic symptoms, mood symptoms, or panic-like presentation\n  → Assess scene safety and vital signs/glucose first — rule out organic/reversible causes when feasible\n  → Panic-like presentation (chest tightness, dyspnea, tachycardia, fear) → still perform medical rule-out (ECG, vitals, glucose) rather than assuming panic disorder from history alone\n  → Psychotic symptoms present → calm, non-confrontational approach, avoid arguing with delusional/hallucinatory content, transport for evaluation\n  → Mood symptoms present → assess for suicidal ideation directly and non-judgmentally when indicated\n  → Suicidal ideation with plan/means/prior attempt → treat as high-risk, apply scene safety considerations, calm supportive approach, transport per local protocol"}],"references":["DSM-5-TR — definitions of delusion, hallucination, major depressive episode, manic episode, panic disorder, PTSD","Standard EMS teaching on suicide risk recognition (recognition-level, not diagnostic)"]},"c08":{"id":"c08","title":"Behavioral Emergencies III — Personality, Substance-Related & High-Risk Presentations","shortTitle":"Personality, Substance & High-Risk","estimatedStudyTime":30,"difficulty":"Advanced","learningObjectives":["Describe the DSM-5-TR personality disorder cluster framework at a recognition level.","Recognize delirium tremens (DTs) and its timing relative to alcohol cessation.","Describe field-relevant recognition of substance intoxication and withdrawal presentations.","Recognize eating-disorder-related cardiac risk as a field-relevant medical concern.","Apply appropriate scene-safety and de-escalation adaptations for high-risk substance-related presentations."],"summary":[{"title":"Personality Disorder Clusters — Recognition Vocabulary, Not a Field Diagnostic Tool","content":"DSM-5-TR groups personality disorders into three clusters. Cluster A ('odd/eccentric'): paranoid, schizoid, and schizotypal — patients may appear suspicious, socially detached, or odd in thinking/behavior. Cluster B ('dramatic/emotional/erratic'): antisocial, borderline, histrionic, and narcissistic — patients may show intense emotional reactivity, impulsivity, attention-seeking behavior, or disregard for others' rights. Cluster C ('anxious/fearful'): avoidant, dependent, and obsessive-compulsive — patients may show excessive anxiety, dependency, or rigid perfectionism. This framework is exam-relevant recognition vocabulary — field providers are not expected to diagnose a specific personality disorder, only to recognize that a patient's presentation may reflect a longstanding pattern rather than an acute crisis alone, and to maintain calm, consistent, non-judgmental care regardless."},{"title":"Delirium Tremens (DTs)","content":"Delirium tremens is a severe, life-threatening alcohol withdrawal syndrome, classically beginning 48-96 hours after the last drink (later than milder withdrawal symptoms, which can start within hours). Features include severe confusion/disorientation, autonomic instability (tachycardia, hypertension, fever, diaphoresis), tremor, and often visual/tactile hallucinations. DTs carries meaningful mortality risk if untreated and is a true medical emergency requiring prompt recognition, supportive care (IV access, monitoring), and transport — it is not simply 'bad withdrawal' to be managed with reassurance alone."},{"title":"Substance Intoxication and Withdrawal — Field Recognition","content":"Field providers should recognize general patterns rather than memorize every substance: stimulant intoxication (agitation, tachycardia, hypertension, diaphoresis, dilated pupils) can look similar to severe anxiety or psychosis and carries cardiac risk; opioid intoxication (respiratory depression, pinpoint pupils, altered mental status) is a respiratory/airway emergency; alcohol or sedative withdrawal can progress from mild tremor/anxiety to seizures and DTs; and any of these can coexist with trauma, psychiatric illness, or an unrelated medical emergency, so vital signs and glucose remain part of the assessment regardless of a presumed substance cause."},{"title":"Eating Disorder Cardiac Risk","content":"Patients with eating disorders (particularly anorexia nervosa and bulimia nervosa) carry a field-relevant risk of cardiac arrhythmia from electrolyte disturbances (e.g., hypokalemia from purging behaviors or malnutrition) — this is a genuine medical risk, not merely a psychiatric consideration, and any cardiac symptom (palpitations, syncope, chest discomfort) in a patient with a known or suspected eating disorder should be evaluated with the same seriousness as in any other patient, including ECG monitoring where available."},{"title":"Scene Safety and De-escalation Adaptations","content":"High-risk presentations — active substance intoxication, personality-disorder-associated impulsivity or emotional intensity, or a patient in DTs with autonomic instability and hallucinations — call for the same core de-escalation principles as other behavioral emergencies (calm approach, open-ended questions, avoid arguing with hallucinatory/delusional content) plus heightened vigilance for rapid changes in presentation, since intoxicated or withdrawing patients can deteriorate quickly and unpredictably. Consistent, calm, non-judgmental care — regardless of the underlying condition — reduces escalation risk across all of these presentations."}],"clinicalPearls":["Personality disorder clusters (A: odd/eccentric, B: dramatic/emotional/erratic, C: anxious/fearful) are recognition vocabulary, not a field diagnostic checklist.","DTs classically starts 48-96 hours after the last drink — later than milder withdrawal — and is a life-threatening emergency, not simple withdrawal.","Opioid intoxication is a respiratory emergency (pinpoint pupils, respiratory depression); stimulant intoxication is a cardiac-risk emergency (tachycardia, hypertension).","Eating-disorder patients carry real cardiac arrhythmia risk from electrolyte disturbance — take cardiac symptoms seriously."],"redFlags":["Severe confusion, autonomic instability, and hallucinations 48-96+ hours after last alcohol use — think DTs.","Pinpoint pupils with respiratory depression and altered mental status — think opioid intoxication.","Cardiac symptoms (palpitations, syncope, chest discomfort) in a patient with known/suspected eating disorder — evaluate seriously, don't dismiss as anxiety."],"commonMistakes":["Attempting to diagnose a specific personality disorder in the field rather than focusing on calm, consistent care.","Treating DTs as simple withdrawal requiring only reassurance rather than as a life-threatening emergency.","Dismissing eating-disorder-related cardiac symptoms as purely psychiatric/anxiety-related."],"memoryAids":["Cluster A odd, Cluster B dramatic, Cluster C anxious.","DTs: 48-96 hours, not day one.","Pinpoint pupils = opioids = breathing problem; wide pupils + fast heart = stimulants = cardiac risk.","Eating disorder + cardiac symptom = real medical risk, evaluate fully."],"decisionTrees":[{"title":"High-Risk Behavioral/Substance Presentation Field Approach","content":"Patient with substance-related, personality-disorder-associated, or eating-disorder-related presentation\n  → Assess scene safety and vital signs/glucose regardless of presumed cause\n  → Alcohol withdrawal 48-96+ hours out with confusion, autonomic instability, hallucinations → suspect DTs → treat as life-threatening emergency, supportive care, monitoring, transport\n  → Pinpoint pupils, respiratory depression, altered mental status → suspect opioid intoxication → airway/ventilation priority\n  → Agitation, tachycardia, hypertension, diaphoresis, dilated pupils → suspect stimulant intoxication → monitor for cardiac risk\n  → Known/suspected eating disorder with cardiac symptoms → evaluate seriously (ECG/monitoring if available), do not dismiss as anxiety\n  → Personality-disorder-associated presentation → maintain calm, consistent, non-judgmental care; do not attempt field diagnosis of a specific disorder\n  → All high-risk presentations: apply core de-escalation principles with heightened vigilance for rapid deterioration"}],"references":["DSM-5-TR — personality disorder cluster framework","Standard EMS teaching on delirium tremens timing/features and substance intoxication/withdrawal recognition"]},"c09":{"id":"c09","title":"Geriatric Emergencies I — Delirium vs. Dementia & Atypical Presentations","shortTitle":"Delirium vs. Dementia","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Distinguish delirium from dementia on onset, course, and reversibility.","Apply the default assumption that acute confusion in a geriatric patient is delirium until proven otherwise.","Recognize common reversible causes of geriatric delirium.","Describe why geriatric patients often present atypically for common conditions.","Explain why baseline cognitive/functional status matters for accurate field assessment."],"summary":[{"title":"Delirium vs. Dementia — The Core Distinction","content":"Delirium is an acute-onset, fluctuating disturbance in attention and awareness that develops over hours to days and is often reversible once the underlying cause is treated. Dementia is a chronic, progressive decline in cognitive function that develops over months to years and is generally not reversible. The two can coexist (a patient with baseline dementia can also develop superimposed delirium from an acute illness), which is part of why the distinction matters clinically — a sudden worsening in a known dementia patient is not simply 'their dementia getting worse today,' it should prompt a delirium workup."},{"title":"Default Assumption: Acute Confusion Is Delirium Until Proven Otherwise","content":"An acutely confused geriatric patient with a normal cognitive baseline (per family/caregiver report) should be treated as delirium until proven otherwise — this drives an active search for a reversible cause rather than passive acceptance of confusion as 'just old age' or an assumed new dementia diagnosis made in the field. This default assumption is one of the most important field teaching points in geriatric care, since missing a reversible cause of delirium can have serious consequences."},{"title":"Common Reversible Causes of Delirium","content":"Common and field-relevant reversible causes include infection (especially urinary tract infection and pneumonia, which can present with confusion as the primary or only symptom in older adults), medication effects (polypharmacy, new medications, or drug interactions), hypoglycemia, hypoxia, electrolyte disturbances, dehydration, urinary retention or constipation (surprisingly common precipitants), pain, and unfamiliar environment/sensory deprivation (e.g., a patient without their usual glasses or hearing aids). A glucose check and a focused search for these causes are core field priorities in any acutely confused older patient."},{"title":"Atypical Presentations in Geriatric Patients","content":"Older adults frequently present atypically for common conditions: a myocardial infarction may present without chest pain (instead as confusion, weakness, or shortness of breath alone — 'silent MI'); infection may present without fever (blunted febrile response); an acute abdomen may present with minimal pain despite significant pathology. This means a lower threshold of suspicion and a broader differential are warranted for geriatric patients whose presentation seems 'too mild' for what turns out to be a serious underlying process."},{"title":"Why Baseline Matters","content":"As with children with special healthcare needs, the single most useful reference point for an older adult is their own personal cognitive and functional baseline, reported by a caregiver or family member — not a generic 'normal for age' assumption. A patient who is 'confused' by an unfamiliar provider's standard may actually be at their unchanged baseline, while a patient who seems 'fine' to a stranger may actually be significantly altered from their usual sharp baseline. Always ask what's normal for this specific patient before deciding what's abnormal today."}],"clinicalPearls":["Delirium: acute, fluctuating, often reversible. Dementia: chronic, progressive, generally not reversible.","Acute confusion in a geriatric patient = delirium until proven otherwise — actively search for a reversible cause.","UTI and pneumonia can present as confusion alone in older adults, without the 'typical' symptoms.","Older adults can have a heart attack without chest pain, an infection without fever, or an acute abdomen without much pain."],"redFlags":["New, acute confusion in a patient with a previously normal cognitive baseline.","Sudden worsening of confusion in a known dementia patient — treat as possible superimposed delirium, not just dementia progression.","A 'mild' presentation in a geriatric patient that doesn't add up — consider atypical presentation of a serious condition."],"commonMistakes":["Assuming all confusion in an older patient is 'just dementia' or 'just old age' without investigating.","Failing to check glucose and consider infection/medication causes in an acutely confused older patient.","Ruling out MI, infection, or acute abdomen in a geriatric patient based on the absence of 'typical' symptoms."],"memoryAids":["Delirium: sudden and fixable. Dementia: slow and not.","New confusion = delirium until proven otherwise.","UTI can look like confusion, not burning — in the elderly.","No chest pain doesn't mean no heart attack in an older patient."],"decisionTrees":[{"title":"Geriatric Acute Confusion Field Approach","content":"Geriatric patient with new or worsening confusion\n  → Establish baseline cognitive/functional status from caregiver/family — do not assume based on the patient's presentation to a stranger alone\n  → Confusion is new or represents an acute change from baseline → treat as delirium until proven otherwise\n  → Check glucose immediately\n  → Search for reversible causes: infection (UTI, pneumonia), medication effects, hypoxia, electrolyte disturbance, dehydration, urinary retention/constipation, pain, unfamiliar environment/sensory deprivation\n  → Consider atypical presentations of serious conditions (silent MI, afebrile infection, painless acute abdomen) even with mild-seeming symptoms\n  → Transport for evaluation; do not dismiss acute confusion as simply 'dementia' or 'old age' in the field"}],"references":["Standard geriatric emergency medicine teaching on delirium vs. dementia and atypical presentation in older adults"]},"c10":{"id":"c10","title":"Geriatric Emergencies II — Polypharmacy, Falls & Elder Abuse Recognition","shortTitle":"Polypharmacy, Falls & Elder Abuse","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Explain why polypharmacy increases risk for older adults.","Describe field priorities when assessing a geriatric fall.","Distinguish a mechanical fall from a fall with an underlying medical cause.","Recognize general findings that may raise concern for elder abuse or neglect.","Describe the EMS provider's role (recognize and report, not investigate) regarding elder abuse."],"summary":[{"title":"Polypharmacy — More Medications, More Risk","content":"Polypharmacy (typically defined as taking five or more medications) is common in older adults and increases risk of adverse drug interactions, side effects, and confusion about proper dosing/adherence. Certain medication classes carry particular fall and bleeding risk relevant to EMS: sedatives/hypnotics and some psychiatric medications increase fall risk through sedation or impaired balance; anticoagulants and antiplatelet medications increase bleeding risk after even minor trauma, including head injury. Gathering an accurate medication list (bring bottles when possible) is a high-value field task, particularly for anticoagulant use in any geriatric trauma or head injury."},{"title":"Geriatric Falls — Not Just a Mechanical Event","content":"A fall in an older adult is never assumed to be purely mechanical (simply tripping) without consideration of an underlying cause — falls can be the presenting symptom of a medical emergency (arrhythmia, stroke, hypoglycemia, orthostatic hypotension, infection, or medication effect). Field assessment of a geriatric fall should include: the circumstances of the fall (witnessed vs. unwitnessed, any warning symptoms beforehand such as dizziness or palpitations, ability to recall the event), vital signs and glucose, a search for injury (including occult injury, since older adults may have blunted pain response), and medication review (especially anticoagulants, given increased head-injury bleeding risk even from a low-energy fall)."},{"title":"Anticoagulant Use and Head Injury","content":"A geriatric patient on an anticoagulant (or antiplatelet medication) who sustains even a seemingly minor head injury carries meaningfully elevated risk of intracranial hemorrhage, and this risk can present with delayed onset of symptoms. This is a field-relevant red flag independent of how the patient appears immediately after the fall — a normal initial neurologic exam does not exclude a developing bleed, and this history should be clearly communicated during hospital handoff."},{"title":"Recognizing Possible Elder Abuse or Neglect","content":"General, non-diagnostic findings that may raise concern for elder abuse or neglect include: injuries inconsistent with the stated mechanism, poor hygiene or evidence of neglect (malnutrition, dehydration, unaddressed medical needs, unsanitary living conditions), unexplained or patterned bruising, a caregiver who is reluctant to leave the patient alone with EMS or answers all questions on the patient's behalf, and signs of financial exploitation noted incidentally. As with pediatric maltreatment, no single finding is diagnostic — the EMS role is recognition and objective documentation, not investigation or accusation."},{"title":"The EMS Role: Recognize and Report","content":"As with suspected child maltreatment, EMS providers are mandatory reporters of suspected elder abuse or neglect in essentially all jurisdictions. The role is to provide standard medical care, document objectively (exact observations, quotes, scene details) rather than draw conclusions, maintain calm and non-accusatory communication with all parties, and report reasonable suspicion through the appropriate channel per local law and agency policy — not to confront a caregiver or attempt to determine what happened."}],"clinicalPearls":["Polypharmacy = 5+ medications — a real risk factor for interactions, falls, and bleeding, not just a documentation detail.","A geriatric fall is a symptom to investigate, not just an event to treat — ask what happened before the fall.","Anticoagulant use plus head injury, even minor, is a red flag independent of the initial exam — bleeds can develop with delay.","Elder abuse recognition, like child maltreatment: recognize and report, don't investigate or accuse."],"redFlags":["Any anticoagulant/antiplatelet use in a geriatric patient with head injury, regardless of initial exam findings.","A fall with preceding symptoms (dizziness, palpitations, chest discomfort) suggesting a medical cause rather than a purely mechanical trip.","Injuries inconsistent with the stated mechanism, poor hygiene/neglect signs, or a caregiver unwilling to allow private conversation with the patient."],"commonMistakes":["Assuming every geriatric fall is purely mechanical without asking about preceding symptoms.","Failing to ask about or document anticoagulant use in a geriatric head injury.","Confronting a caregiver directly about suspected elder abuse instead of documenting objectively and reporting through appropriate channels."],"memoryAids":["5+ meds = polypharmacy, a real risk factor.","Why did they fall, not just that they fell.","Blood thinner plus bumped head is a red flag no matter how they look right now.","Recognize and report, don't investigate or accuse — same rule as pediatric maltreatment."],"decisionTrees":[{"title":"Geriatric Fall and Elder Abuse Recognition Field Approach","content":"Geriatric patient after a fall\n  → Ask about circumstances: witnessed/unwitnessed, preceding symptoms (dizziness, palpitations, chest discomfort), ability to recall the event\n  → Check vital signs and glucose\n  → Review medications, specifically asking about anticoagulant/antiplatelet use\n  → Search for injury including occult injury, given possible blunted pain response\n  → Any anticoagulant use + head injury (even minor) → treat as elevated intracranial hemorrhage risk regardless of initial exam, communicate clearly at handoff\n  → During assessment, note any findings raising concern for abuse/neglect (injury-mechanism inconsistency, neglect signs, unexplained bruising, controlling caregiver behavior)\n  → Provide standard care, document objectively, maintain calm non-accusatory communication, report reasonable suspicion of abuse/neglect through appropriate channel per local law/policy"}],"references":["Standard geriatric emergency medicine teaching on polypharmacy, fall assessment, and elder abuse recognition"]},"c11":{"id":"c11","title":"Toxicological & Environmental Medical Presentations","shortTitle":"Toxicology & Environmental","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Recognize common adult toxidrome patterns.","Describe field priorities for a suspected acute poisoning or overdose.","Recognize field presentations of heat-related illness across its severity spectrum.","Recognize field presentations of hypothermia across its severity spectrum.","Describe field management priorities for environmental emergencies in adults."],"summary":[{"title":"Toxidrome Recognition","content":"A toxidrome is a recognizable cluster of signs and symptoms associated with a category of toxic exposure, useful because it lets a provider act on a pattern even without knowing the exact substance. Opioid toxidrome: respiratory depression, pinpoint pupils, altered mental status. Sympathomimetic (stimulant) toxidrome: agitation, tachycardia, hypertension, diaphoresis, dilated pupils. Anticholinergic toxidrome: altered mental status, dilated pupils, dry flushed skin, tachycardia, urinary retention ('hot as a hare, dry as a bone, red as a beet, blind as a bat, mad as a hatter'). Cholinergic toxidrome: excessive secretions (salivation, lacrimation, urination, defecation, GI upset), bradycardia, muscle twitching — associated with organophosphate exposure."},{"title":"Field Priorities for Suspected Poisoning/Overdose","content":"Ensure scene safety first, especially for exposures involving unknown chemicals or gases. Identify the substance, amount, and time of exposure when possible, and bring containers/pills to the hospital. Support airway, breathing, and circulation as the priority over identifying the exact substance. Check glucose in any altered patient regardless of a presumed toxic cause. Recognize toxidrome patterns to guide urgency and specific interventions (e.g., naloxone for suspected opioid toxicity per protocol) even without a confirmed substance identity."},{"title":"Heat-Related Illness Spectrum","content":"Heat illness exists on a spectrum. Heat cramps: painful muscle spasms during/after exertion in heat, generally with normal mental status — treat with rest, fluids, and gentle stretching. Heat exhaustion: heavy sweating, weakness, nausea, headache, and normal-to-mildly-altered mental status, with core temperature usually elevated but not extreme — treat with cooling, rest, and fluids (oral if tolerated and alert). Heat stroke: the life-threatening endpoint, defined by significantly elevated core temperature plus altered mental status (confusion, seizure, or coma) — this is a true emergency requiring aggressive cooling and rapid transport; the presence of sweating does not rule out heat stroke, since some heat stroke patients still sweat, especially with exertional causes."},{"title":"Hypothermia Spectrum","content":"Hypothermia is also a spectrum by core temperature. Mild hypothermia: shivering, mild confusion, intact coordination. Moderate hypothermia: shivering may stop, worsening confusion, muscle rigidity, slowed heart rate/breathing. Severe hypothermia: absent shivering, significantly altered or unresponsive mental status, risk of cardiac arrhythmia (including a heart especially prone to arrhythmia with rough handling) and cardiac arrest. Field management is gentle handling (rough movement can trigger arrhythmia in a severely hypothermic heart), passive/active external rewarming as appropriate to severity, and rapid transport — a severely hypothermic patient in apparent cardiac arrest should still receive resuscitation efforts per protocol, since hypothermia can mimic death and patients have survived prolonged downtime with good neurologic outcome after rewarming."},{"title":"General Environmental Emergency Priorities","content":"Across heat and cold emergencies: remove the patient from the ongoing environmental extreme, support ABCs, treat per the severity spectrum above, and transport promptly with a lower threshold for more severe classifications, since patients can deteriorate along the spectrum. Field temperature assessment (when available) helps classify severity and guide treatment intensity, but the overall clinical picture (mental status, specific symptoms) remains central when precise temperature measurement isn't available."}],"clinicalPearls":["Toxidromes let you act on a pattern without knowing the exact substance — recognize the cluster, not just one finding.","Sweating does not rule out heat stroke — altered mental status plus significantly elevated temperature is the defining combination.","Handle a severely hypothermic patient gently — rough movement can trigger a fatal arrhythmia.","A hypothermic cardiac arrest patient may still be resuscitatable — hypothermia can mimic death; don't presume futility based on presentation alone."],"redFlags":["Altered mental status plus significantly elevated core temperature — heat stroke until proven otherwise, regardless of sweating.","Absent shivering with altered mental status in a cold-exposed patient — possible severe hypothermia.","Pinpoint pupils with respiratory depression — treat as an airway emergency, not just an overdose to observe."],"commonMistakes":["Ruling out heat stroke because the patient is still sweating.","Handling a severely hypothermic patient roughly, risking arrhythmia.","Withholding resuscitation efforts from a hypothermic cardiac arrest patient based on presentation alone."],"memoryAids":["Opioid: pinpoint pupils, slow breathing. Stimulant: wide pupils, fast everything.","Anticholinergic: hot, dry, red, blind, mad.","Cholinergic: wet everywhere (SLUDGE-type secretions).","Not dead until warm and dead — don't presume futility in hypothermic arrest."],"decisionTrees":[{"title":"Suspected Toxic Exposure and Environmental Emergency Field Approach","content":"Suspected toxic exposure or environmental emergency\n  → Ensure scene safety\n  → Toxic exposure: identify substance/amount/time if possible, support ABCs, recognize toxidrome pattern to guide urgency and specific treatment (e.g., naloxone for opioid toxidrome per protocol), check glucose regardless of presumed cause\n  → Heat-related illness: assess mental status and estimate severity (cramps → exhaustion → stroke); heat stroke (altered mental status + high temp, sweating does not exclude) = aggressive cooling + rapid transport\n  → Cold-related illness: assess mental status and shivering status to estimate severity (mild → moderate → severe); handle gently, especially if severe; rewarm appropriately; transport rapidly\n  → Hypothermic cardiac arrest: do not presume futility — provide resuscitation per protocol given hypothermia's protective/mimicking effect"}],"references":["Standard EMS/toxicology teaching on toxidrome recognition","Standard EMS environmental emergency teaching on heat illness and hypothermia severity spectrums"]},"c12":{"id":"c12","title":"Sepsis, GI/Renal Emergencies & General Medical Red Flags","shortTitle":"Sepsis, GI/Renal & Red Flags","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Recognize prehospital signs suggestive of sepsis.","Describe field priorities for suspected sepsis.","Recognize field presentations of common GI emergencies (GI bleeding, bowel obstruction).","Recognize field presentations of acute renal colic and describe its distinguishing features.","Apply a general 'red flag' framework for recognizing a medical patient who is sicker than they initially appear."],"summary":[{"title":"Recognizing Sepsis in the Field","content":"Sepsis is a life-threatening response to infection that can progress rapidly to septic shock. Field-relevant recognition combines a suspected or known infection source (e.g., cough/productive sputum, dysuria, wound with surrounding redness/warmth) with signs of systemic illness: fever or hypothermia (both can indicate sepsis — a very low temperature in the setting of infection is not reassuring), tachycardia, tachypnea, altered mental status, and — as sepsis progresses toward septic shock — hypotension and poor perfusion (delayed capillary refill, cool/mottled skin, or paradoxically warm/flushed skin in early distributive shock). Sepsis is time-sensitive: outcomes worsen with delayed recognition and treatment, similar in urgency to stroke or trauma."},{"title":"Field Management for Suspected Sepsis","content":"Field priorities are early recognition (using the pattern above rather than waiting for a formal score), supportive care (oxygen as needed, IV access and fluids per protocol, cardiac monitoring), and rapid transport with early hospital notification, since early antibiotics and fluid resuscitation in the hospital setting are time-sensitive. Older adults and patients with altered mental status can present with sepsis atypically (e.g., confusion as the primary sign, without a dramatic fever), reinforcing the geriatric atypical-presentation principle from earlier in this course."},{"title":"GI Emergencies — Bleeding and Obstruction","content":"GI bleeding presents as hematemesis (vomiting blood, which may look like coffee grounds if partially digested), melena (black, tarry, foul-smelling stool from upper GI bleeding), or hematochezia (bright red blood per rectum, typically lower GI bleeding, though a brisk upper GI bleed can also present this way). Significant GI bleeding can cause hypovolemic shock — assess perfusion (not just visible blood volume) and treat shock per protocol. Bowel obstruction presents with colicky abdominal pain, distension, vomiting (which may become feculent in advanced cases), and absence of bowel movements/flatus — this is a surgical emergency requiring prompt transport, with supportive care (IV fluids, antiemetics per protocol) rather than oral intake."},{"title":"Renal Colic","content":"Acute renal colic (kidney stone) classically presents with sudden, severe, colicky flank pain that may radiate to the groin, often with nausea/vomiting and hematuria, and the patient is often unable to find a comfortable position (in contrast to peritoneal irritation, where patients typically lie still). While renal colic is usually not immediately life-threatening, it should not be assumed without considering more dangerous mimics presenting with similar flank/back pain — most notably a ruptured or dissecting abdominal aortic aneurysm (AAA), especially in an older patient with vascular risk factors, and pyelonephritis with systemic infection signs."},{"title":"General 'Sicker Than They Look' Red Flags","content":"Across all medical complaints, certain findings should raise the index of suspicion regardless of the specific diagnosis: any altered mental status, tachycardia or tachypnea out of proportion to the apparent severity of complaint, pain out of proportion to exam findings (a classic teaching point for conditions like mesenteric ischemia or compartment syndrome), inability to find a comfortable position, and a patient or family stating 'this feels different/worse than usual' for someone with a known chronic condition. These general red flags exist precisely because atypical and subtle presentations of serious illness are common, and a systematic red-flag mindset catches what a single vital sign or complaint-specific checklist might miss."}],"clinicalPearls":["Both fever and hypothermia can indicate sepsis — a low temperature with infection is not reassuring.","Sepsis is time-sensitive, like stroke or trauma — early recognition and rapid transport matter.","Melena = upper GI bleed (black, tarry); hematochezia = usually lower GI bleed (bright red), though a brisk upper bleed can look the same.","Pain out of proportion to exam findings is a classic red flag for a more dangerous underlying process."],"redFlags":["Suspected infection plus altered mental status, tachycardia/tachypnea, or hypotension — think sepsis, not 'just an infection.'","Colicky flank pain in an older patient with vascular risk factors — don't assume renal colic without considering AAA.","Pain out of proportion to exam findings, or a patient unable to find a comfortable position."],"commonMistakes":["Reassurance from a normal or low temperature in a patient with suspected infection.","Assuming flank pain is always renal colic without considering AAA in an at-risk patient.","Underestimating GI bleeding severity by focusing on visible blood volume rather than perfusion status."],"memoryAids":["Fever OR hypothermia plus infection signs = think sepsis either way.","Melena is black and from up high; hematochezia is red and usually from down low.","Flank pain in an older vascular-risk patient — rule out AAA before settling on 'just a stone.'","Pain that doesn't match the exam is a red flag, not a reassurance."],"decisionTrees":[{"title":"Sepsis and General Medical Red Flag Field Approach","content":"Suspected infection or vague/serious-seeming medical complaint\n  → Suspected infection source + fever OR hypothermia + tachycardia/tachypnea/altered mental status → suspect sepsis → supportive care (O2, IV fluids per protocol, monitoring), rapid transport, early hospital notification\n  → GI bleeding (hematemesis, melena, hematochezia) → assess perfusion (not just visible blood), treat shock per protocol, rapid transport\n  → Bowel obstruction pattern (colicky pain, distension, vomiting, no BM/flatus) → supportive care, no oral intake, prompt transport\n  → Flank pain → consider renal colic, but rule out AAA (especially older/vascular-risk patient) and pyelonephritis (systemic infection signs) before settling on a benign cause\n  → Any general red flag present (altered mental status, vital signs out of proportion, pain out of proportion, inability to find comfortable position, 'feels different than usual') → raise index of suspicion regardless of specific diagnosis, transport promptly"}],"references":["Standard EMS sepsis-recognition teaching (early recognition and rapid transport, paralleling stroke/trauma time-sensitivity)","Standard EMS teaching on GI bleeding, bowel obstruction, and renal colic recognition and AAA mimicry"]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What is a TIA?","answer":"A transient ischemic attack — stroke-like neurologic deficit that resolves completely, classically within minutes to an hour, without lasting tissue injury.","category":"Stroke"},{"id":"c01_fc02","question":"Why is a TIA treated with the same urgency as a stroke in the field?","answer":"It cannot be reliably distinguished from an evolving stroke in the field, and it carries a significant short-term risk of a subsequent completed stroke.","category":"Stroke"},{"id":"c01_fc03","question":"What are the two broad categories of stroke?","answer":"Ischemic (clot/obstruction blocking blood flow) and hemorrhagic (bleeding into or around brain tissue).","category":"Stroke"},{"id":"c01_fc04","question":"Can ischemic and hemorrhagic stroke be reliably distinguished by field symptoms alone?","answer":"No — both cause focal neurologic deficits; the distinction is made by hospital imaging.","category":"Stroke"},{"id":"c01_fc05","question":"What three findings does the Cincinnati Prehospital Stroke Scale (CPSS) check?","answer":"Facial droop, arm drift, and speech abnormality.","category":"Stroke Scales"},{"id":"c01_fc06","question":"Name two prehospital stroke scales beyond CPSS that add sensitivity for detecting large-vessel occlusion (LVO).","answer":"LAPSS (Los Angeles Prehospital Stroke Screen) and RACE (Rapid Arterial oCclusion Evaluation); FAST-ED is another example.","category":"Stroke Scales"},{"id":"c01_fc07","question":"What does FAST-ED add to the standard FAST components?","answer":"Eye deviation and denial/neglect.","category":"Stroke Scales"},{"id":"c01_fc08","question":"What findings raise suspicion for a large-vessel occlusion (LVO) stroke?","answer":"Gaze deviation toward one side, severe unilateral weakness affecting both face and arm together, and neglect/denial of the deficit.","category":"Stroke"},{"id":"c01_fc09","question":"Why might an LVO-screening scale change the destination decision?","answer":"In systems with an endovascular-capable stroke center, a positive LVO screen may justify bypassing a closer, non-endovascular-capable hospital, per local protocol.","category":"Stroke"},{"id":"c01_fc10","question":"Why is checking blood glucose a field priority in suspected stroke?","answer":"Hypoglycemia is a well-known, rapidly correctable stroke mimic.","category":"Field Management"},{"id":"c01_fc11","question":"Why is the last-known-well time so important to document precisely?","answer":"It drives eligibility for time-sensitive hospital treatments.","category":"Field Management"},{"id":"c01_fc12","question":"What is a 'stroke alert'?","answer":"Early hospital notification of a suspected stroke patient so the receiving facility can prepare.","category":"Field Management"},{"id":"c01_fc13","question":"Should transport be delayed to complete an extensive neurologic exam in suspected stroke?","answer":"No — use a rapid validated screening scale and prioritize rapid transport; time is the central variable in stroke outcome.","category":"Field Management"},{"id":"c01_fc14","question":"What is the 2026 guideline governing stroke management referenced in this course?","answer":"The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke.","category":"Guidelines"}]},"c02":{"chapter":"c02","cards":[{"id":"c02_fc01","question":"Are most adult seizures life-threatening?","answer":"No — most are brief, self-limited events that stop on their own within a couple of minutes.","category":"Seizures"},{"id":"c02_fc02","question":"List common causes of adult seizures.","answer":"Idiopathic epilepsy (often with medication non-compliance), hypoglycemia, head trauma, intoxication/withdrawal (especially alcohol withdrawal), fever/infection, stroke, structural brain lesions.","category":"Seizures"},{"id":"c02_fc03","question":"What is the postictal state?","answer":"A period of transient confusion, drowsiness, and sometimes agitation following a seizure, typically resolving gradually over minutes without specific intervention.","category":"Seizures"},{"id":"c02_fc04","question":"Is the postictal state itself an emergency?","answer":"No — it's a normal, expected part of the seizure process, but should gradually improve.","category":"Seizures"},{"id":"c02_fc05","question":"What should worsening (rather than gradually improving) postictal confusion prompt?","answer":"Reconsideration of other causes: ongoing subclinical seizure activity, structural injury, or a coexisting problem like hypoglycemia.","category":"Seizures"},{"id":"c02_fc06","question":"What defines status epilepticus?","answer":"A seizure lasting 5 minutes or longer, or repeated seizures without return to baseline between them.","category":"Seizures"},{"id":"c02_fc07","question":"Is status epilepticus a time-critical emergency?","answer":"Yes — it carries real risk of ongoing neuronal injury and cardiorespiratory compromise the longer it continues.","category":"Seizures"},{"id":"c02_fc08","question":"What are the field priorities for an actively seizing patient?","answer":"Protect the airway (positioning, suction as needed, nothing in the mouth), protect from injury, time the seizure, check glucose as feasible.","category":"Field Management"},{"id":"c02_fc09","question":"What does AEIOU-TIPS help a provider recall?","answer":"Reversible causes of altered mental status: Alcohol, Epilepsy/postictal, Insulin (hypo/hyperglycemia), Overdose, Uremia/metabolic, Trauma/temperature, Infection, Psychiatric, Stroke/shock.","category":"AMS"},{"id":"c02_fc10","question":"What is the main clinical value of the AEIOU-TIPS framework?","answer":"Prompting a glucose check and a search for a reversible cause before assuming an irreversible or purely psychiatric explanation.","category":"AMS"},{"id":"c02_fc11","question":"What should be checked immediately in a newly altered, non-seizing patient?","answer":"Blood glucose.","category":"AMS"},{"id":"c02_fc12","question":"What history elements are useful to gather from bystanders/family for an altered patient?","answer":"Medications, known seizure disorder, substance use, recent illness or head injury.","category":"AMS"},{"id":"c02_fc13","question":"Should something be placed in the mouth of a seizing patient?","answer":"No — never place anything in the mouth during a seizure.","category":"Field Management"},{"id":"c02_fc14","question":"What is the field priority once seizure activity is identified as status epilepticus?","answer":"Escalate per local ALS protocol with rapid transport; benzodiazepine administration follows local protocol.","category":"Field Management"}]},"c03":{"chapter":"c03","cards":[{"id":"c03_fc01","question":"What are early/mild symptoms of hypoglycemia?","answer":"Shakiness, diaphoresis, hunger, anxiety.","category":"Hypoglycemia"},{"id":"c03_fc02","question":"What are severe symptoms of hypoglycemia?","answer":"Confusion, combativeness, seizure, unresponsiveness.","category":"Hypoglycemia"},{"id":"c03_fc03","question":"What is the field treatment for hypoglycemia in an awake, cooperative patient?","answer":"Oral glucose.","category":"Hypoglycemia"},{"id":"c03_fc04","question":"What is the field treatment for hypoglycemia in a patient who cannot safely take oral glucose?","answer":"IV dextrose or IM glucagon per protocol.","category":"Hypoglycemia"},{"id":"c03_fc05","question":"What three features together define DKA?","answer":"Hyperglycemia (glucose ≥200 mg/dL or known diabetes), ketosis (beta-hydroxybutyrate ≥3.0 mmol/L or urine ketones ≥2+), and metabolic acidosis (pH <7.3 and/or bicarbonate <18 mEq/L).","category":"DKA"},{"id":"c03_fc06","question":"What are classic field findings of DKA?","answer":"Polyuria/polydipsia, nausea/vomiting, abdominal pain, Kussmaul respirations, fruity (acetone) breath odor, dehydration.","category":"DKA"},{"id":"c03_fc07","question":"What are Kussmaul respirations, and why do they occur in DKA?","answer":"Deep, rapid respirations that occur as a compensatory response to the metabolic acidosis.","category":"DKA"},{"id":"c03_fc08","question":"What common precipitants trigger DKA?","answer":"Infection, missed insulin doses, or new-onset diabetes.","category":"DKA"},{"id":"c03_fc09","question":"What is euglycemic DKA?","answer":"DKA presenting with a glucose under 200 mg/dL — occurs in about 10% of DKA cases.","category":"DKA"},{"id":"c03_fc10","question":"What medication class is most classically associated with euglycemic DKA?","answer":"SGLT2 inhibitors.","category":"DKA"},{"id":"c03_fc11","question":"Does a normal glucose rule out DKA?","answer":"No — if the clinical picture fits (Kussmaul respirations, fruity breath, vomiting/abdominal pain, known diabetes), DKA should still be suspected.","category":"DKA"},{"id":"c03_fc12","question":"What four features together define HHS?","answer":"Severe hyperglycemia (often >600 mg/dL), significant hyperosmolality (>320 mOsm/kg), minimal or absent ketosis, and near-normal pH/bicarbonate.","category":"HHS"},{"id":"c03_fc13","question":"How does HHS's typical patient and onset differ from DKA's?","answer":"HHS is more typical in older adults with type 2 diabetes, with a slower onset over days, profound dehydration, and more prominent altered mental status/obtundation than DKA.","category":"HHS"},{"id":"c03_fc14","question":"What is the field management priority for both DKA and HHS?","answer":"Supportive care (oxygen as needed, IV access and isotonic fluids per protocol, cardiac monitoring), airway protection given vomiting risk, and rapid transport — definitive treatment happens in the hospital.","category":"Field Management"}]},"c04":{"chapter":"c04","cards":[{"id":"c04_fc01","question":"What treatment framework does GINA 2025 use for asthma?","answer":"A dual-track, ICS-formoterol-centered stepwise approach (Steps 1-4), graded by symptom control rather than a fixed severity label.","category":"Asthma"},{"id":"c04_fc02","question":"What older asthma classification language has GINA 2025 moved away from?","answer":"The 'intermittent / mild-moderate-severe persistent' severity classification.","category":"Asthma"},{"id":"c04_fc03","question":"What does the legacy 'phase 1' asthma classification describe?","answer":"Asthma that resolves spontaneously or with bronchodilators within 1-2 hours.","category":"Asthma"},{"id":"c04_fc04","question":"What does the legacy 'phase 2' asthma classification describe?","answer":"Asthma that does not respond to bronchodilators alone and needs anti-inflammatory treatment.","category":"Asthma"},{"id":"c04_fc05","question":"Is the legacy 'phase 1-4' asthma framework current GINA terminology?","answer":"No — it is a simplified historical teaching tool, not current guideline language.","category":"Asthma"},{"id":"c04_fc06","question":"What is chronic bronchitis classically associated with?","answer":"Cigarette-smoke exposure; presents with chronic productive cough and a stockier, sometimes cyanotic appearance ('blue bloater').","category":"COPD"},{"id":"c04_fc07","question":"What appearance does emphysema classically produce?","answer":"A thin, barrel-chested appearance with pursed-lip breathing ('pink puffer').","category":"COPD"},{"id":"c04_fc08","question":"What is the 'hypoxic drive' myth?","answer":"The outdated teaching that COPD patients rely on hypoxia to drive breathing and that oxygen will cause respiratory arrest.","category":"COPD"},{"id":"c04_fc09","question":"What actually causes oxygen-induced hypercapnia in COPD?","answer":"Primarily ventilation-perfusion mismatch and increased dead space, not loss of respiratory drive.","category":"COPD"},{"id":"c04_fc10","question":"What is the current SpO2 target for titrated oxygen therapy in acute COPD exacerbation?","answer":"Roughly 88-92%.","category":"COPD"},{"id":"c04_fc11","question":"Should oxygen be withheld from a hypoxic COPD patient out of fear of hypoxic drive?","answer":"No — this creates real risk of harmful, prolonged tissue hypoxia and is not current best practice.","category":"COPD"},{"id":"c04_fc12","question":"Why is a 'silent chest' more concerning than a loud wheeze in asthma?","answer":"It means too little air is moving to produce noise, signaling near-complete airway obstruction rather than improvement.","category":"Asthma"},{"id":"c04_fc13","question":"What findings suggest severe asthma distress requiring rapid escalation?","answer":"Inability to speak in full sentences, accessory muscle use, altered mental status, or a silent chest.","category":"Field Management"},{"id":"c04_fc14","question":"What is the field management priority for both asthma and COPD exacerbations?","answer":"Severity assessment, bronchodilator therapy per protocol, titrated oxygen (for COPD), and frequent reassessment for signs of impending respiratory failure.","category":"Field Management"}]},"c05":{"chapter":"c05","cards":[{"id":"c05_fc01","question":"What defines preeclampsia?","answer":"New-onset hypertension after 20 weeks of gestation plus proteinuria, or hypertension plus evidence of other organ dysfunction even without proteinuria.","category":"Preeclampsia"},{"id":"c05_fc02","question":"Is preeclampsia simply 'high blood pressure in pregnancy'?","answer":"No — it is a systemic condition that can progress toward severe complications, including eclampsia.","category":"Preeclampsia"},{"id":"c05_fc03","question":"What defines eclampsia?","answer":"Preeclampsia plus new seizures or coma that cannot be attributed to another cause.","category":"Eclampsia"},{"id":"c05_fc04","question":"What medication is the definitive hospital/ALS treatment for eclamptic seizures?","answer":"Magnesium sulfate (not typically a benzodiazepine alone), per local protocol.","category":"Eclampsia"},{"id":"c05_fc05","question":"What warning signs suggest worsening preeclampsia toward severe disease?","answer":"Severe/persistent headache, visual disturbances, right upper quadrant or epigastric pain, sudden significant swelling, markedly elevated blood pressure.","category":"Preeclampsia"},{"id":"c05_fc06","question":"Why does right upper quadrant or epigastric pain matter in a hypertensive pregnant patient?","answer":"It suggests liver involvement, a warning sign of worsening preeclampsia.","category":"Preeclampsia"},{"id":"c05_fc07","question":"Why is left lateral positioning used for a pregnant patient late in pregnancy?","answer":"To avoid aortocaval compression from the gravid uterus, which reduces venous return.","category":"Field Management"},{"id":"c05_fc08","question":"Why should stimulation (bright lights, loud noise) be minimized in severe preeclampsia?","answer":"Stimulation can precipitate a seizure in severe preeclampsia.","category":"Field Management"},{"id":"c05_fc09","question":"What is the field management for a pregnant patient with suspected preeclampsia?","answer":"Left lateral tilt/uterine displacement, minimize stimulation, monitor BP closely, transport to an obstetric-capable facility.","category":"Field Management"},{"id":"c05_fc10","question":"What is the field management for an active eclamptic seizure?","answer":"Protect airway/from injury (standard seizure precautions), left lateral positioning once feasible, minimize stimulation, rapid transport.","category":"Field Management"},{"id":"c05_fc11","question":"After an eclamptic seizure resolves, what should ongoing care include?","answer":"Monitoring for repeat seizure and worsening signs, maintaining left lateral positioning during transport when possible.","category":"Field Management"},{"id":"c05_fc12","question":"How should a new seizure in a pregnant patient be treated until proven otherwise?","answer":"As possible eclampsia.","category":"Eclampsia"},{"id":"c05_fc13","question":"At what gestational point does preeclampsia typically develop?","answer":"Typically after 20 weeks of gestation.","category":"Preeclampsia"},{"id":"c05_fc14","question":"Should a pregnant patient's severe headache or visual disturbance be treated as routine?","answer":"No — these are obstetric red flags that should prompt evaluation for preeclampsia, not be dismissed as routine.","category":"Preeclampsia"}]},"c06":{"chapter":"c06","cards":[{"id":"c06_fc01","question":"What should be assessed before approaching a patient in behavioral crisis?","answer":"Scene safety from a distance — weapons, exits, and the patient's affect.","category":"Scene Safety"},{"id":"c06_fc02","question":"What should happen when a credible safety concern is present on a behavioral call?","answer":"Involve law enforcement per local protocol before approaching.","category":"Scene Safety"},{"id":"c06_fc03","question":"What does SEA-3 stand for?","answer":"Safety, Emotional state, Appearance, Activity, Speech.","category":"Assessment"},{"id":"c06_fc04","question":"What is assessed under 'Appearance' in SEA-3?","answer":"Grooming, hygiene, and dress as clues to functioning.","category":"Assessment"},{"id":"c06_fc05","question":"What is assessed under 'Activity' in SEA-3?","answer":"Psychomotor activity — agitation, retardation, restlessness.","category":"Assessment"},{"id":"c06_fc06","question":"What is assessed under 'Speech' in SEA-3?","answer":"Rate, volume, coherence, and content.","category":"Assessment"},{"id":"c06_fc07","question":"What type of questions are preferred during de-escalation?","answer":"Open-ended questions rather than rapid-fire closed questions.","category":"De-escalation"},{"id":"c06_fc08","question":"Should a provider argue with or challenge a patient's delusional content during de-escalation?","answer":"No — avoid arguing with or directly challenging delusional content.","category":"De-escalation"},{"id":"c06_fc09","question":"What is the goal of de-escalation in the field?","answer":"Reduce the patient's perceived threat level and build enough cooperation to complete an assessment and safely transport — not to resolve the underlying condition.","category":"De-escalation"},{"id":"c06_fc10","question":"When is physical restraint appropriate?","answer":"Only as a last resort, after de-escalation has failed and the patient poses an immediate danger to self or others, per local protocol.","category":"De-escalation"},{"id":"c06_fc11","question":"What is abandonment?","answer":"Terminating patient care without ensuring that an equal or higher level of care continues.","category":"Legal/Ethical"},{"id":"c06_fc12","question":"What distinction is important when a patient refuses care?","answer":"Whether the patient competently exercises the right to refuse (with proper informed-refusal documentation) versus lacking capacity to refuse.","category":"Legal/Ethical"},{"id":"c06_fc13","question":"Why is disorganized speech plus poor grooming plus psychomotor agitation together more concerning than any single finding?","answer":"The combination paints a higher-risk overall picture than any one SEA-3 finding alone.","category":"Assessment"},{"id":"c06_fc14","question":"What is the primary purpose of assessing scene safety from a distance in a behavioral emergency?","answer":"Provider safety is a prerequisite for being able to help the patient at all.","category":"Scene Safety"}]},"c07":{"chapter":"c07","cards":[{"id":"c07_fc01","question":"What is a delusion?","answer":"A fixed, false belief that persists despite clear evidence against it.","category":"Psychotic"},{"id":"c07_fc02","question":"What is a hallucination?","answer":"A false sensory perception with no external stimulus (e.g., hearing or seeing something that isn't there).","category":"Psychotic"},{"id":"c07_fc03","question":"What is the key difference between a delusion and a hallucination?","answer":"A delusion involves belief; a hallucination involves sensory perception.","category":"Psychotic"},{"id":"c07_fc04","question":"What causes can produce psychotic symptoms?","answer":"Primary psychotic disorders (e.g., schizophrenia), mood disorders with psychotic features, or an organic/medical cause (substance intoxication/withdrawal, delirium).","category":"Psychotic"},{"id":"c07_fc05","question":"Are prehospital providers expected to diagnose the underlying cause of psychotic symptoms?","answer":"No — the priority is safe assessment, ruling out organic/reversible causes when feasible, and safe transport.","category":"Psychotic"},{"id":"c07_fc06","question":"What are core features of a major depressive episode?","answer":"Persistent low mood, loss of interest/pleasure, changes in sleep/appetite, low energy, and possibly suicidal ideation.","category":"Mood Disorders"},{"id":"c07_fc07","question":"What are core features of a manic episode?","answer":"Elevated or irritable mood, decreased need for sleep, rapid/pressured speech, grandiosity, and risky or impulsive behavior.","category":"Mood Disorders"},{"id":"c07_fc08","question":"Why is mania field-relevant beyond the mood change itself?","answer":"Impaired judgment during mania can create acute safety risks — reckless behavior, risk-taking, occasionally aggression if grandiose beliefs are challenged.","category":"Mood Disorders"},{"id":"c07_fc09","question":"What symptoms characterize a panic attack?","answer":"Recurrent, discrete episodes of intense fear with tachycardia, dyspnea, chest tightness, dizziness, and a sense of impending doom.","category":"Panic/PTSD"},{"id":"c07_fc10","question":"Should a patient's chest pain/dyspnea be assumed to be 'just a panic attack' based on history alone?","answer":"No — true medical emergencies should still be ruled out (ECG, vitals, glucose), since panic attacks can mimic or coexist with real medical emergencies.","category":"Panic/PTSD"},{"id":"c07_fc11","question":"What are core features of PTSD?","answer":"Re-experiencing symptoms, avoidance, negative mood/cognition changes, and hyperarousal following a traumatic event.","category":"Panic/PTSD"},{"id":"c07_fc12","question":"Why might aspects of the EMS encounter itself trigger or worsen PTSD symptoms?","answer":"Uniforms, restraint, or physical contact can serve as trauma reminders — explaining actions calmly before performing them can help.","category":"Panic/PTSD"},{"id":"c07_fc13","question":"Does asking a patient directly about suicidal thoughts increase their risk?","answer":"No — direct, non-judgmental questioning does not increase risk and is appropriate when clinically indicated.","category":"Suicide Risk"},{"id":"c07_fc14","question":"What factors make a suicidal patient a high-risk presentation?","answer":"A specific plan, access to lethal means, or a prior attempt history.","category":"Suicide Risk"}]},"c08":{"chapter":"c08","cards":[{"id":"c08_fc01","question":"What personality disorders fall under DSM-5-TR Cluster A?","answer":"Paranoid, schizoid, and schizotypal — characterized as 'odd/eccentric.'","category":"Personality Disorders"},{"id":"c08_fc02","question":"What personality disorders fall under DSM-5-TR Cluster B?","answer":"Antisocial, borderline, histrionic, and narcissistic — characterized as 'dramatic/emotional/erratic.'","category":"Personality Disorders"},{"id":"c08_fc03","question":"What personality disorders fall under DSM-5-TR Cluster C?","answer":"Avoidant, dependent, and obsessive-compulsive — characterized as 'anxious/fearful.'","category":"Personality Disorders"},{"id":"c08_fc04","question":"Are field providers expected to diagnose a specific personality disorder?","answer":"No — this is recognition-level exam vocabulary; field care focuses on calm, consistent, non-judgmental care regardless of diagnosis.","category":"Personality Disorders"},{"id":"c08_fc05","question":"When does delirium tremens (DTs) classically begin relative to the last drink?","answer":"48-96 hours after the last drink — later than milder withdrawal symptoms.","category":"Substance-Related"},{"id":"c08_fc06","question":"What are the features of DTs?","answer":"Severe confusion/disorientation, autonomic instability (tachycardia, hypertension, fever, diaphoresis), tremor, and often visual/tactile hallucinations.","category":"Substance-Related"},{"id":"c08_fc07","question":"Is DTs a life-threatening condition?","answer":"Yes — it carries meaningful mortality risk if untreated and requires prompt recognition and supportive care.","category":"Substance-Related"},{"id":"c08_fc08","question":"What is the classic presentation of stimulant intoxication?","answer":"Agitation, tachycardia, hypertension, diaphoresis, dilated pupils.","category":"Substance-Related"},{"id":"c08_fc09","question":"What is the classic presentation of opioid intoxication?","answer":"Respiratory depression, pinpoint pupils, altered mental status — a respiratory/airway emergency.","category":"Substance-Related"},{"id":"c08_fc10","question":"Should vital signs and glucose still be checked even when a substance cause seems obvious?","answer":"Yes — substance-related presentations can coexist with trauma, psychiatric illness, or an unrelated medical emergency.","category":"Substance-Related"},{"id":"c08_fc11","question":"What cardiac risk is associated with eating disorders?","answer":"Arrhythmia from electrolyte disturbances (e.g., hypokalemia from purging behaviors or malnutrition).","category":"Eating Disorders"},{"id":"c08_fc12","question":"How seriously should cardiac symptoms be taken in a patient with a known/suspected eating disorder?","answer":"With the same seriousness as in any other patient — this is a genuine medical risk, not merely psychiatric.","category":"Eating Disorders"},{"id":"c08_fc13","question":"Why do high-risk substance-related presentations require heightened vigilance beyond standard de-escalation?","answer":"Intoxicated or withdrawing patients can deteriorate quickly and unpredictably.","category":"Scene Safety"},{"id":"c08_fc14","question":"What common thread reduces escalation risk across personality-disorder, substance-related, and DTs presentations?","answer":"Consistent, calm, non-judgmental care regardless of the underlying condition.","category":"Scene Safety"}]},"c09":{"chapter":"c09","cards":[{"id":"c09_fc01","question":"What is delirium?","answer":"An acute-onset, fluctuating disturbance in attention and awareness that develops over hours to days and is often reversible.","category":"Delirium vs. Dementia"},{"id":"c09_fc02","question":"What is dementia?","answer":"A chronic, progressive decline in cognitive function that develops over months to years and is generally not reversible.","category":"Delirium vs. Dementia"},{"id":"c09_fc03","question":"Can delirium and dementia coexist?","answer":"Yes — a patient with baseline dementia can also develop superimposed delirium from an acute illness.","category":"Delirium vs. Dementia"},{"id":"c09_fc04","question":"How should acute confusion in a geriatric patient with a normal baseline be treated by default?","answer":"As delirium until proven otherwise, prompting an active search for a reversible cause.","category":"Delirium vs. Dementia"},{"id":"c09_fc05","question":"What should a sudden worsening of confusion in a known dementia patient prompt?","answer":"A delirium workup, not just an assumption that 'their dementia is getting worse today.'","category":"Delirium vs. Dementia"},{"id":"c09_fc06","question":"What infections classically present with confusion as a primary or only symptom in older adults?","answer":"Urinary tract infection (UTI) and pneumonia.","category":"Delirium Causes"},{"id":"c09_fc07","question":"List common reversible causes of geriatric delirium.","answer":"Infection, medication effects/polypharmacy, hypoglycemia, hypoxia, electrolyte disturbance, dehydration, urinary retention/constipation, pain, unfamiliar environment/sensory deprivation.","category":"Delirium Causes"},{"id":"c09_fc08","question":"What surprisingly common conditions can precipitate delirium?","answer":"Urinary retention and constipation.","category":"Delirium Causes"},{"id":"c09_fc09","question":"What is a 'silent MI'?","answer":"A myocardial infarction presenting without chest pain — instead as confusion, weakness, or shortness of breath alone, more common in older adults.","category":"Atypical Presentations"},{"id":"c09_fc10","question":"How might infection present atypically in an older adult?","answer":"Without fever, due to a blunted febrile response.","category":"Atypical Presentations"},{"id":"c09_fc11","question":"How might an acute abdomen present atypically in an older adult?","answer":"With minimal pain despite significant underlying pathology.","category":"Atypical Presentations"},{"id":"c09_fc12","question":"Why does baseline cognitive/functional status matter more than a generic 'normal for age' assumption?","answer":"A patient's own personal baseline, reported by a caregiver, is the most useful reference point for determining what's actually abnormal today.","category":"Baseline Assessment"},{"id":"c09_fc13","question":"What should be checked immediately in an acutely confused geriatric patient?","answer":"Blood glucose.","category":"Field Management"},{"id":"c09_fc14","question":"Why is a lower threshold of suspicion warranted for 'mild-seeming' geriatric presentations?","answer":"Because atypical presentations can mask serious underlying conditions (silent MI, afebrile infection, painless acute abdomen).","category":"Atypical Presentations"}]},"c10":{"chapter":"c10","cards":[{"id":"c10_fc01","question":"What is polypharmacy?","answer":"Typically defined as taking five or more medications; increases risk of adverse drug interactions, side effects, and dosing confusion.","category":"Polypharmacy"},{"id":"c10_fc02","question":"What medication classes carry particular fall risk?","answer":"Sedatives/hypnotics and some psychiatric medications, through sedation or impaired balance.","category":"Polypharmacy"},{"id":"c10_fc03","question":"What medication classes carry particular bleeding risk after trauma?","answer":"Anticoagulants and antiplatelet medications.","category":"Polypharmacy"},{"id":"c10_fc04","question":"Why is gathering an accurate medication list a high-value field task?","answer":"It reveals fall/bleeding risk factors, particularly anticoagulant use, that directly affect clinical decision-making.","category":"Polypharmacy"},{"id":"c10_fc05","question":"Should a geriatric fall be assumed to be purely mechanical?","answer":"No — falls can be the presenting symptom of a medical emergency (arrhythmia, stroke, hypoglycemia, orthostatic hypotension, infection, medication effect).","category":"Falls"},{"id":"c10_fc06","question":"What should be asked about the circumstances of a geriatric fall?","answer":"Witnessed vs. unwitnessed, any preceding warning symptoms (dizziness, palpitations), and ability to recall the event.","category":"Falls"},{"id":"c10_fc07","question":"Why might occult injury be more likely to be missed in older adults?","answer":"Older adults may have a blunted pain response.","category":"Falls"},{"id":"c10_fc08","question":"Why is anticoagulant use plus head injury a significant red flag, even if minor?","answer":"It carries meaningfully elevated risk of intracranial hemorrhage that can present with delayed onset of symptoms.","category":"Falls"},{"id":"c10_fc09","question":"Does a normal initial neurologic exam exclude a developing intracranial bleed in an anticoagulated patient after head injury?","answer":"No — a normal initial exam does not exclude a developing bleed, and this history must be clearly communicated at handoff.","category":"Falls"},{"id":"c10_fc10","question":"What general findings may raise concern for elder abuse or neglect?","answer":"Injury-mechanism inconsistency, poor hygiene/neglect signs, unexplained/patterned bruising, a controlling caregiver, signs of financial exploitation.","category":"Elder Abuse"},{"id":"c10_fc11","question":"Is any single finding diagnostic of elder abuse?","answer":"No — as with pediatric maltreatment, no single finding is diagnostic; the EMS role is recognition and objective documentation.","category":"Elder Abuse"},{"id":"c10_fc12","question":"Are EMS providers mandatory reporters of suspected elder abuse?","answer":"Yes, in essentially all jurisdictions.","category":"Elder Abuse"},{"id":"c10_fc13","question":"What is the EMS provider's role regarding suspected elder abuse?","answer":"Provide standard care, document objectively, maintain calm non-accusatory communication, and report reasonable suspicion through appropriate channels — not to investigate or confront.","category":"Elder Abuse"},{"id":"c10_fc14","question":"What caregiver behavior may raise concern during an elder abuse assessment?","answer":"Reluctance to leave the patient alone with EMS or answering all questions on the patient's behalf.","category":"Elder Abuse"}]},"c11":{"chapter":"c11","cards":[{"id":"c11_fc01","question":"What is a toxidrome?","answer":"A recognizable cluster of signs and symptoms associated with a category of toxic exposure, allowing action on a pattern without knowing the exact substance.","category":"Toxicology"},{"id":"c11_fc02","question":"What is the opioid toxidrome?","answer":"Respiratory depression, pinpoint pupils, altered mental status.","category":"Toxicology"},{"id":"c11_fc03","question":"What is the sympathomimetic (stimulant) toxidrome?","answer":"Agitation, tachycardia, hypertension, diaphoresis, dilated pupils.","category":"Toxicology"},{"id":"c11_fc04","question":"What is the anticholinergic toxidrome mnemonic and meaning?","answer":"'Hot as a hare, dry as a bone, red as a beet, blind as a bat, mad as a hatter' — altered mental status, dilated pupils, dry flushed skin, tachycardia, urinary retention.","category":"Toxicology"},{"id":"c11_fc05","question":"What is the cholinergic toxidrome, and what is it associated with?","answer":"Excessive secretions (salivation, lacrimation, urination, defecation, GI upset), bradycardia, muscle twitching — associated with organophosphate exposure.","category":"Toxicology"},{"id":"c11_fc06","question":"What is the field priority order for a suspected poisoning/overdose?","answer":"Scene safety first, then support ABCs, identify substance/amount/time when possible, check glucose regardless of presumed cause.","category":"Field Management"},{"id":"c11_fc07","question":"What defines heat cramps?","answer":"Painful muscle spasms during/after exertion in heat, generally with normal mental status.","category":"Heat Illness"},{"id":"c11_fc08","question":"What defines heat exhaustion?","answer":"Heavy sweating, weakness, nausea, headache, normal-to-mildly-altered mental status, elevated but not extreme core temperature.","category":"Heat Illness"},{"id":"c11_fc09","question":"What defines heat stroke?","answer":"Significantly elevated core temperature plus altered mental status (confusion, seizure, or coma) — a life-threatening emergency.","category":"Heat Illness"},{"id":"c11_fc10","question":"Does the presence of sweating rule out heat stroke?","answer":"No — some heat stroke patients still sweat, especially with exertional causes.","category":"Heat Illness"},{"id":"c11_fc11","question":"What are features of mild hypothermia?","answer":"Shivering, mild confusion, intact coordination.","category":"Hypothermia"},{"id":"c11_fc12","question":"What are features of severe hypothermia?","answer":"Absent shivering, significantly altered/unresponsive mental status, risk of cardiac arrhythmia and arrest.","category":"Hypothermia"},{"id":"c11_fc13","question":"Why must a severely hypothermic patient be handled gently?","answer":"Rough movement can trigger a fatal arrhythmia in a severely hypothermic heart.","category":"Hypothermia"},{"id":"c11_fc14","question":"Should resuscitation be withheld from a hypothermic cardiac arrest patient based on presentation alone?","answer":"No — hypothermia can mimic death, and patients have survived prolonged downtime with good neurologic outcome after rewarming; provide resuscitation per protocol.","category":"Hypothermia"}]},"c12":{"chapter":"c12","cards":[{"id":"c12_fc01","question":"What is sepsis?","answer":"A life-threatening response to infection that can progress rapidly to septic shock.","category":"Sepsis"},{"id":"c12_fc02","question":"Can hypothermia (not just fever) indicate sepsis?","answer":"Yes — both fever and hypothermia can indicate sepsis; a low temperature with infection is not reassuring.","category":"Sepsis"},{"id":"c12_fc03","question":"What systemic signs suggest sepsis in a patient with a suspected infection source?","answer":"Fever or hypothermia, tachycardia, tachypnea, altered mental status, and (as it progresses) hypotension and poor perfusion.","category":"Sepsis"},{"id":"c12_fc04","question":"Why is sepsis considered time-sensitive, similar to stroke or trauma?","answer":"Outcomes worsen with delayed recognition and treatment, since early antibiotics and fluid resuscitation are time-sensitive interventions.","category":"Sepsis"},{"id":"c12_fc05","question":"How can sepsis present atypically in older adults?","answer":"Confusion may be the primary sign, without a dramatic fever.","category":"Sepsis"},{"id":"c12_fc06","question":"What is melena, and what does it suggest?","answer":"Black, tarry, foul-smelling stool, suggesting upper GI bleeding.","category":"GI Emergencies"},{"id":"c12_fc07","question":"What is hematochezia, and what does it typically suggest?","answer":"Bright red blood per rectum, typically lower GI bleeding (though a brisk upper GI bleed can also present this way).","category":"GI Emergencies"},{"id":"c12_fc08","question":"What should be assessed in significant GI bleeding beyond visible blood volume?","answer":"Perfusion status — significant GI bleeding can cause hypovolemic shock.","category":"GI Emergencies"},{"id":"c12_fc09","question":"What is the classic presentation pattern of bowel obstruction?","answer":"Colicky abdominal pain, distension, vomiting (possibly feculent in advanced cases), and absence of bowel movements/flatus.","category":"GI Emergencies"},{"id":"c12_fc10","question":"What is the field management for suspected bowel obstruction?","answer":"Supportive care (IV fluids, antiemetics per protocol), no oral intake, prompt transport — it's a surgical emergency.","category":"GI Emergencies"},{"id":"c12_fc11","question":"What is the classic presentation of acute renal colic?","answer":"Sudden, severe, colicky flank pain radiating to the groin, often with nausea/vomiting and hematuria, with the patient unable to find a comfortable position.","category":"Renal"},{"id":"c12_fc12","question":"What dangerous condition should be considered before assuming flank pain is simple renal colic, especially in an older patient?","answer":"Ruptured or dissecting abdominal aortic aneurysm (AAA).","category":"Renal"},{"id":"c12_fc13","question":"What is a classic teaching point about pain out of proportion to exam findings?","answer":"It's a red flag for a more dangerous underlying process (e.g., mesenteric ischemia, compartment syndrome).","category":"Red Flags"},{"id":"c12_fc14","question":"Why does a general 'red flag' mindset matter across all medical complaints?","answer":"Atypical and subtle presentations of serious illness are common, and a systematic red-flag approach catches what a single vital sign or complaint-specific checklist might miss.","category":"Red Flags"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"What defines a TIA (transient ischemic attack)?","options":["A. A stroke that leaves permanent deficits","B. Stroke-like neurologic deficit that resolves completely, classically within minutes to an hour","C. A minor headache with no neurologic findings","D. A seizure followed by confusion"],"correct":1,"rationale":"A TIA produces stroke-like focal neurologic deficit that resolves completely without lasting tissue injury, classically within minutes to an hour.","difficulty":"Easy"},{"id":"c01_q02","question":"Why is a TIA treated with the same field urgency as an ongoing stroke?","options":["A. It cannot be reliably distinguished from an evolving stroke in the field, and carries short-term risk of a completed stroke","B. TIAs are more dangerous than strokes","C. TIA is simply an outdated term for stroke","D. There is no urgency difference because TIAs are never serious"],"correct":0,"rationale":"Because a TIA can't be reliably distinguished from an evolving stroke in the field, and TIA patients face a meaningful short-term risk of a subsequent completed stroke, both are managed with the same urgency.","difficulty":"Medium"},{"id":"c01_q03","question":"What are the two broad categories of stroke?","options":["A. Ischemic and hemorrhagic","B. Acute and chronic","C. Central and peripheral","D. Primary and secondary"],"correct":0,"rationale":"Stroke is broadly categorized as ischemic (obstruction of blood flow) or hemorrhagic (bleeding into/around brain tissue).","difficulty":"Easy"},{"id":"c01_q04","question":"Can ischemic and hemorrhagic stroke be reliably distinguished in the field by symptoms alone?","options":["A. Yes, symptoms are always distinct","B. No — both cause focal neurologic deficits; imaging is needed to distinguish them","C. Only hemorrhagic stroke causes a facial droop","D. Only ischemic stroke causes speech abnormality"],"correct":1,"rationale":"Field symptoms cannot reliably distinguish the two stroke types; both produce focal neurologic deficits, and hospital imaging is required to differentiate them.","difficulty":"Medium"},{"id":"c01_q05","question":"What three findings does the Cincinnati Prehospital Stroke Scale (CPSS) assess?","options":["A. Facial droop, arm drift, speech abnormality","B. Blood pressure, heart rate, respiratory rate","C. Pupil size, gag reflex, grip strength","D. Gaze deviation, neglect, ataxia"],"correct":0,"rationale":"CPSS checks facial droop, arm drift, and speech abnormality as its three core findings.","difficulty":"Easy"},{"id":"c01_q06","question":"What is the purpose of an LVO-screening scale like RACE or FAST-ED?","options":["A. To diagnose the exact stroke type in the field","B. To add sensitivity for detecting a large-vessel occlusion, which may inform destination decisions","C. To replace blood glucose checks","D. To determine the patient's code status"],"correct":1,"rationale":"LVO-screening scales add sensitivity for detecting large-vessel occlusion strokes, which may influence a destination decision toward an endovascular-capable center per local protocol.","difficulty":"Medium"},{"id":"c01_q07","question":"What does FAST-ED add to the standard FAST components?","options":["A. Eye deviation and denial/neglect","B. Blood glucose and temperature","C. Pupil reactivity","D. Grip strength bilaterally"],"correct":0,"rationale":"FAST-ED extends FAST by adding eye (gaze) deviation and denial/neglect to improve LVO detection sensitivity.","difficulty":"Medium"},{"id":"c01_q08","question":"Which findings raise suspicion for a large-vessel occlusion (LVO) stroke?","options":["A. Isolated mild facial droop only","B. Gaze deviation, severe combined face+arm weakness, and neglect of the deficit","C. A resolved speech abnormality with normal exam otherwise","D. Isolated numbness without weakness"],"correct":1,"rationale":"Gaze deviation, severe unilateral face+arm weakness together, and neglect/denial of the deficit are findings that raise LVO suspicion beyond a basic FAST-positive screen.","difficulty":"Hard"},{"id":"c01_q09","question":"Why should blood glucose be checked in a suspected stroke patient?","options":["A. Hypoglycemia is a well-known, rapidly correctable stroke mimic","B. Glucose has no relevance to neurologic presentations","C. It replaces the need for a stroke scale","D. It is only relevant in diabetic patients"],"correct":0,"rationale":"Hypoglycemia can mimic a focal neurologic deficit and is rapidly correctable, making a glucose check a high-value field step in suspected stroke.","difficulty":"Medium"},{"id":"c01_q10","question":"Why is documenting the last-known-well time so important?","options":["A. It drives eligibility for time-sensitive hospital treatments","B. It is only used for billing purposes","C. It has no bearing on hospital treatment decisions","D. It replaces the need for a stroke scale"],"correct":0,"rationale":"Last-known-well time is a key driver of eligibility for time-sensitive interventions at the receiving hospital, making precise documentation a high priority.","difficulty":"Medium"},{"id":"c01_q11","question":"What is a 'stroke alert'?","options":["A. A patient-initiated emergency call","B. Early hospital notification of a suspected stroke patient so the receiving facility can prepare","C. A specific stroke medication","D. A type of cardiac monitor alarm"],"correct":1,"rationale":"A stroke alert is early notification to the receiving hospital, allowing the stroke team to prepare before patient arrival.","difficulty":"Easy"},{"id":"c01_q12","question":"Should transport be delayed to perform a full, extensive neurologic exam on a suspected stroke patient?","options":["A. Yes, always complete a full exam before transport","B. No — use a rapid validated screening scale and prioritize rapid transport, since time is central to stroke outcome","C. Only if the patient requests it","D. Only for hemorrhagic strokes"],"correct":1,"rationale":"Time is the central variable in stroke outcomes, so field care uses a rapid screening scale rather than delaying transport for an extensive exam.","difficulty":"Medium"},{"id":"c01_q13","question":"A patient had left-sided facial droop and slurred speech that fully resolved 20 minutes before EMS arrival. How should this be treated?","options":["A. As a non-urgent complaint since symptoms resolved","B. With the same urgency as an active stroke, given the possibility of TIA and risk of a subsequent stroke","C. Only urgent if the patient becomes symptomatic again","D. As a psychiatric complaint given full resolution"],"correct":1,"rationale":"A resolved deficit consistent with TIA still carries meaningful short-term stroke risk and should be treated with full stroke-protocol urgency.","difficulty":"Hard"},{"id":"c01_q14","question":"A stroke patient has gaze deviation to the right, severe right face and arm weakness, and does not acknowledge the weak arm. What should this presentation raise suspicion for?","options":["A. A simple TIA with no further workup needed","B. Possible large-vessel occlusion (LVO) stroke, potentially warranting an LVO-screening-based destination decision","C. A hypoglycemic event with no stroke involvement","D. A behavioral/psychiatric emergency"],"correct":1,"rationale":"Gaze deviation, combined severe face+arm weakness, and neglect of the deficit are classic LVO-suspicious findings that may change the transport destination decision per local protocol.","difficulty":"Hard"},{"id":"c01_q15","question":"Which guideline is the authoritative current source for stroke management referenced in this course?","options":["A. The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke","B. GINA 2025","C. DSM-5-TR","D. ADA Standards of Care 2026"],"correct":0,"rationale":"The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke is the current authoritative source, replacing the 2018/2019 guideline.","difficulty":"Easy"}]},"c02":{"chapter":"c02","questions":[{"id":"c02_q01","question":"Are most adult seizures life-threatening events requiring aggressive intervention?","options":["A. Yes, all seizures require immediate medication","B. No — most are brief, self-limited, and stop on their own","C. Only seizures in elderly patients are self-limited","D. Seizures are always a sign of stroke"],"correct":1,"rationale":"Most adult seizures are brief and self-terminating; field management for these focuses on protection, not stopping an already-resolved seizure.","difficulty":"Easy"},{"id":"c02_q02","question":"Which of the following is a common cause of adult seizures?","options":["A. Hypoglycemia","B. Normal blood pressure","C. Adequate sleep","D. Mild dehydration alone"],"correct":0,"rationale":"Hypoglycemia is a common and important cause of adult seizures, alongside epilepsy, head trauma, intoxication/withdrawal, infection, and stroke.","difficulty":"Easy"},{"id":"c02_q03","question":"What is the postictal state?","options":["A. A period of transient confusion/drowsiness following a seizure that typically resolves gradually","B. The seizure itself","C. A permanent neurologic deficit","D. A medication used to stop seizures"],"correct":0,"rationale":"The postictal state is a transient period of confusion or drowsiness after a seizure that generally resolves gradually without specific intervention.","difficulty":"Easy"},{"id":"c02_q04","question":"What should worsening postictal confusion (rather than gradual improvement) prompt?","options":["A. No action, since postictal confusion is always benign","B. Reconsideration of other causes: ongoing subclinical seizure, structural injury, or hypoglycemia","C. Immediate discharge from care","D. Assumption that the patient is malingering"],"correct":1,"rationale":"The postictal state should improve gradually; worsening confusion should prompt investigation of alternative or coexisting causes.","difficulty":"Medium"},{"id":"c02_q05","question":"What defines status epilepticus?","options":["A. Any seizure lasting more than 30 seconds","B. A seizure lasting 5 minutes or longer, or repeated seizures without return to baseline","C. Only seizures caused by epilepsy","D. A seizure that occurs during sleep"],"correct":1,"rationale":"Status epilepticus is defined as a seizure lasting 5 minutes or more, or repeated seizures without return to baseline between them.","difficulty":"Medium"},{"id":"c02_q06","question":"Why is status epilepticus considered a time-critical emergency?","options":["A. It carries risk of ongoing neuronal injury and cardiorespiratory compromise the longer it continues","B. It has no clinical significance beyond a brief seizure","C. It only affects patients with a prior seizure history","D. It resolves faster than a brief seizure"],"correct":0,"rationale":"The longer status epilepticus continues, the greater the risk of neuronal injury and cardiorespiratory compromise, making rapid recognition and escalation important.","difficulty":"Medium"},{"id":"c02_q07","question":"What are the correct field priorities for an actively seizing patient?","options":["A. Place a bite block in the mouth and restrain the limbs","B. Protect the airway/position, protect from injury, time the seizure, check glucose","C. Administer oral medication immediately","D. Perform chest compressions"],"correct":1,"rationale":"Correct seizure management is airway protection/positioning, injury protection, timing the seizure, and checking glucose — never placing objects in the mouth or restraining limbs.","difficulty":"Easy"},{"id":"c02_q08","question":"What does the AEIOU-TIPS mnemonic help a provider recall?","options":["A. Steps of CPR","B. Reversible causes of altered mental status","C. Categories of shock","D. Stroke scale components"],"correct":1,"rationale":"AEIOU-TIPS recalls reversible causes of altered mental status: Alcohol, Epilepsy, Insulin, Overdose, Uremia, Trauma/temperature, Infection, Psychiatric, Stroke/shock.","difficulty":"Medium"},{"id":"c02_q09","question":"What is the main clinical value of the AEIOU-TIPS framework?","options":["A. It replaces the need for any physical exam","B. It prompts a glucose check and search for a reversible cause before assuming an irreversible explanation","C. It is used only for pediatric patients","D. It is a stroke scale"],"correct":1,"rationale":"AEIOU-TIPS is valuable primarily because it prompts systematic consideration of reversible causes, starting with glucose, before assuming a fixed or purely psychiatric cause.","difficulty":"Medium"},{"id":"c02_q10","question":"What should be checked immediately in a newly altered, non-seizing adult patient?","options":["A. Blood glucose","B. Blood type","C. Recent dental history","D. Vaccination status"],"correct":0,"rationale":"Blood glucose is a fast, safe, high-value check that can immediately explain (and treat) altered mental status.","difficulty":"Easy"},{"id":"c02_q11","question":"Should an object be placed in the mouth of a seizing patient to prevent tongue-biting?","options":["A. Yes, always use a bite block","B. No — never place anything in the mouth during a seizure","C. Only for pediatric patients","D. Only if the patient requests it"],"correct":1,"rationale":"Placing objects in the mouth during a seizure is unnecessary and can cause injury; this is a common and important mistake to avoid.","difficulty":"Easy"},{"id":"c02_q12","question":"A patient seized for 2 minutes and stopped before EMS arrival, now in a gradually clearing postictal state. What is the appropriate management?","options":["A. Administer a benzodiazepine to stop the ongoing seizure","B. Protect and monitor, check glucose, and transport — no seizure-stopping medication is needed since the seizure has already resolved","C. Perform immediate advanced airway placement","D. Restrain the patient to prevent further seizure activity"],"correct":1,"rationale":"A brief seizure that has already terminated does not require abortive medication; management is supportive with glucose check and monitoring for gradual improvement.","difficulty":"Medium"},{"id":"c02_q13","question":"A patient has been continuously seizing for 7 minutes. What should this be treated as?","options":["A. A normal, self-limited seizure requiring no escalation","B. Status epilepticus — a time-critical emergency requiring escalation per local ALS protocol","C. A postictal state","D. A psychiatric emergency"],"correct":1,"rationale":"Seizure activity exceeding the 5-minute threshold is status epilepticus, requiring escalation and rapid transport.","difficulty":"Medium"},{"id":"c02_q14","question":"A patient remains altered and confused 45 minutes after an observed seizure, with no improvement. What should this prompt?","options":["A. Assumption this is normal, prolonged postictal state requiring no further evaluation","B. Investigation of other causes since postictal confusion should gradually improve, not persist unchanged","C. Immediate discharge since seizures are self-limited","D. Assumption the patient is intentionally faking symptoms"],"correct":1,"rationale":"Persistent, non-improving altered mental status well beyond the expected postictal window should prompt investigation for another or coexisting cause (e.g., ongoing subclinical seizure, structural injury, hypoglycemia).","difficulty":"Hard"},{"id":"c02_q15","question":"Why is a focused history from bystanders/family (medications, seizure history, substance use, recent illness/injury) valuable in an altered patient?","options":["A. It has no clinical value in the field","B. It can point toward a specific reversible cause and guide field management priorities","C. It replaces the need for a glucose check","D. It is only relevant for pediatric patients"],"correct":1,"rationale":"A focused collateral history can quickly point toward a likely cause (e.g., known epilepsy with medication non-compliance, or a substance use history), guiding field priorities alongside the AEIOU-TIPS framework.","difficulty":"Medium"}]},"c03":{"chapter":"c03","questions":[{"id":"c03_q01","question":"What are early/mild symptoms of hypoglycemia?","options":["A. Shakiness, diaphoresis, hunger, anxiety","B. Fever and rash","C. Chest pain and dyspnea","D. Joint pain and swelling"],"correct":0,"rationale":"Mild hypoglycemia classically presents with shakiness, diaphoresis, hunger, and anxiety before progressing to more severe neurologic symptoms.","difficulty":"Easy"},{"id":"c03_q02","question":"What is the field treatment for hypoglycemia in an awake, cooperative patient with intact airway reflexes?","options":["A. IM glucagon only","B. Oral glucose","C. Withhold treatment until hospital arrival","D. IV insulin"],"correct":1,"rationale":"Oral glucose is appropriate for an awake, cooperative patient who can safely swallow.","difficulty":"Easy"},{"id":"c03_q03","question":"What three features together define DKA?","options":["A. Hyperglycemia, ketosis, and metabolic acidosis","B. Hypoglycemia, ketosis, and alkalosis","C. Hyperglycemia alone","D. Fever, tachycardia, and hypertension"],"correct":0,"rationale":"DKA requires all three: hyperglycemia (or known diabetes), ketosis, and metabolic acidosis together.","difficulty":"Medium"},{"id":"c03_q04","question":"What glucose threshold is generally used to define hyperglycemia in DKA (absent a prior diabetes diagnosis)?","options":["A. ≥100 mg/dL","B. ≥140 mg/dL","C. ≥200 mg/dL","D. ≥600 mg/dL"],"correct":2,"rationale":"The DKA hyperglycemia criterion is glucose ≥200 mg/dL, or a prior history of diabetes even without meeting this threshold.","difficulty":"Medium"},{"id":"c03_q05","question":"What are Kussmaul respirations, and why do they occur in DKA?","options":["A. Shallow, slow breathing from CNS depression","B. Deep, rapid respirations as a compensatory response to metabolic acidosis","C. Irregular gasping unrelated to acid-base status","D. Normal breathing pattern with no clinical significance"],"correct":1,"rationale":"Kussmaul respirations are deep, rapid breaths that compensate for metabolic acidosis by blowing off CO2.","difficulty":"Medium"},{"id":"c03_q06","question":"What breath odor is classically associated with DKA?","options":["A. Ammonia","B. Fruity (acetone)","C. Rotten eggs","D. No characteristic odor"],"correct":1,"rationale":"A fruity, acetone-like breath odor is a classic finding in DKA due to ketone production.","difficulty":"Easy"},{"id":"c03_q07","question":"What percentage of DKA presentations occur with euglycemic DKA (glucose <200 mg/dL)?","options":["A. About 1%","B. About 10%","C. About 50%","D. About 90%"],"correct":1,"rationale":"Approximately 10% of DKA presentations are euglycemic, with glucose under 200 mg/dL.","difficulty":"Medium"},{"id":"c03_q08","question":"What medication class is most classically associated with euglycemic DKA?","options":["A. SGLT2 inhibitors","B. Beta-blockers","C. ACE inhibitors","D. Statins"],"correct":0,"rationale":"SGLT2-inhibitor diabetes medications are the classic association with euglycemic DKA.","difficulty":"Hard"},{"id":"c03_q09","question":"Does a normal or only mildly elevated glucose rule out DKA?","options":["A. Yes, DKA cannot occur without a very high glucose","B. No — if the clinical picture fits (Kussmaul respirations, fruity breath, vomiting/abdominal pain), DKA should still be suspected","C. Yes, but only in type 1 diabetics","D. Glucose has no relationship to DKA diagnosis"],"correct":1,"rationale":"Because of euglycemic DKA, a normal or mildly elevated glucose does not rule out DKA if other clinical features are present.","difficulty":"Hard"},{"id":"c03_q10","question":"What four features together define HHS?","options":["A. Severe hyperglycemia, significant hyperosmolality, minimal ketosis, near-normal pH/bicarbonate","B. Hypoglycemia, ketosis, acidosis, hypotension","C. Fever, tachycardia, hyperglycemia, ketosis","D. Normal glucose, high ketones, severe acidosis"],"correct":0,"rationale":"HHS is defined by severe hyperglycemia (often >600 mg/dL), hyperosmolality (>320 mOsm/kg), minimal ketosis, and near-normal pH/bicarbonate — distinguishing it from DKA's acidosis picture.","difficulty":"Medium"},{"id":"c03_q11","question":"Which patient population is HHS more typically seen in?","options":["A. Younger patients with type 1 diabetes and rapid onset","B. Older adults with type 2 diabetes and slower onset over days","C. Children with new-onset diabetes","D. HHS occurs equally across all diabetic populations and onset patterns"],"correct":1,"rationale":"HHS is more typical in older adults with type 2 diabetes, with a slower onset over days and profound dehydration.","difficulty":"Medium"},{"id":"c03_q12","question":"How does the mental status picture in HHS typically compare to DKA?","options":["A. HHS typically has a more prominent altered mental status/obtundation picture than DKA","B. DKA always causes more severe altered mental status than HHS","C. Neither condition affects mental status","D. Mental status changes are identical and cannot be distinguished"],"correct":0,"rationale":"HHS's severe hyperosmolar state has a direct effect on the brain, often producing more prominent altered mental status/obtundation than typical DKA.","difficulty":"Hard"},{"id":"c03_q13","question":"What is the field management priority for both DKA and HHS?","options":["A. Oral glucose administration","B. Supportive care (oxygen, IV access/isotonic fluids per protocol, cardiac monitoring), airway protection, and rapid transport","C. Withholding all fluids until hospital arrival","D. Immediate insulin administration in the field"],"correct":1,"rationale":"Field management for DKA/HHS is supportive — fluids, oxygen, monitoring, airway protection given vomiting risk, and rapid transport; definitive treatment (insulin, careful correction) happens in the hospital.","difficulty":"Medium"},{"id":"c03_q14","question":"A known diabetic patient presents with confusion. Should the provider assume hypoglycemia without checking glucose?","options":["A. Yes, all diabetic confusion is hypoglycemia","B. No — check glucose, since altered mental status could reflect hypoglycemia, DKA, or HHS","C. Yes, but only if the patient is elderly","D. No check is needed if the patient appears calm"],"correct":1,"rationale":"Altered mental status in a diabetic patient could reflect either direction of glucose abnormality (or DKA/HHS); a glucose check is required rather than assuming the direction.","difficulty":"Medium"},{"id":"c03_q15","question":"A type 2 diabetic patient on an SGLT2 inhibitor presents with vomiting, abdominal pain, and Kussmaul respirations, with a glucose of 180 mg/dL. What should this raise suspicion for?","options":["A. This cannot be DKA since the glucose is under 200 mg/dL","B. Euglycemic DKA, given the SGLT2-inhibitor use and fitting clinical picture despite a near-normal glucose","C. Simple gastroenteritis with no endocrine involvement","D. HHS, given the diabetes history"],"correct":1,"rationale":"SGLT2-inhibitor use plus a DKA-consistent clinical picture (vomiting, abdominal pain, Kussmaul respirations) despite a near-normal glucose is the classic presentation of euglycemic DKA.","difficulty":"Hard"}]},"c04":{"chapter":"c04","questions":[{"id":"c04_q01","question":"What treatment framework does GINA 2025 use for asthma management?","options":["A. A dual-track, ICS-formoterol-centered stepwise approach graded by symptom control","B. A fixed severity label assigned once at diagnosis","C. Treatment based solely on peak flow readings","D. No standardized framework exists"],"correct":0,"rationale":"GINA 2025 uses a dual-track, ICS-formoterol-centered stepwise approach (Steps 1-4) graded by symptom control rather than a fixed severity label.","difficulty":"Medium"},{"id":"c04_q02","question":"What classification language has GINA 2025 moved away from?","options":["A. The step-based framework","B. The 'intermittent / mild-moderate-severe persistent' severity classification","C. ICS-formoterol therapy","D. Symptom-control grading"],"correct":1,"rationale":"GINA 2025 shifted away from the older intermittent/mild/moderate/severe persistent severity labels toward a control-based step framework.","difficulty":"Medium"},{"id":"c04_q03","question":"What does the legacy 'phase 1' asthma classification (found in some exam banks) describe?","options":["A. Asthma that resolves spontaneously or with bronchodilators within 1-2 hours","B. Asthma requiring immediate intubation","C. Asthma unresponsive to all treatment","D. Asthma only occurring in children"],"correct":0,"rationale":"The legacy phase 1 classification describes asthma that resolves spontaneously or with bronchodilators within 1-2 hours.","difficulty":"Medium"},{"id":"c04_q04","question":"Is the legacy 'phase 1-4' asthma framework current GINA guideline terminology?","options":["A. Yes, it is the exact current terminology","B. No — it's a simplified historical teaching tool; current guideline language is GINA's step-based, control-oriented framework","C. It was never used in any EMS curriculum","D. It replaced GINA's framework in 2025"],"correct":1,"rationale":"The phase 1-4 framework is historical/simplified vocabulary that predates and differs from GINA's current step-based approach.","difficulty":"Hard"},{"id":"c04_q05","question":"What is chronic bronchitis classically associated with?","options":["A. Cigarette-smoke exposure, chronic productive cough, 'blue bloater' appearance","B. Viral infection only","C. Thin, barrel-chested appearance","D. Pursed-lip breathing as the defining feature"],"correct":0,"rationale":"Chronic bronchitis is strongly linked to cigarette-smoke exposure and classically produces a chronic productive cough with a stockier, sometimes cyanotic ('blue bloater') appearance.","difficulty":"Medium"},{"id":"c04_q06","question":"What appearance does emphysema classically produce?","options":["A. Stocky, cyanotic ('blue bloater')","B. Thin, barrel-chested with pursed-lip breathing ('pink puffer')","C. Normal body habitus with no distinguishing features","D. Obese with peripheral edema"],"correct":1,"rationale":"Emphysema classically produces a thin, barrel-chested appearance with pursed-lip breathing, nicknamed 'pink puffer.'","difficulty":"Medium"},{"id":"c04_q07","question":"What is the 'hypoxic drive' theory?","options":["A. The (outdated) teaching that COPD patients rely on hypoxia to drive breathing and that oxygen causes respiratory arrest","B. A current, evidence-based mechanism explaining all COPD hypercapnia","C. A treatment protocol for asthma","D. A stroke scale component"],"correct":0,"rationale":"The hypoxic drive theory is the traditional but outdated teaching that oxygen administration removes COPD patients' respiratory drive.","difficulty":"Easy"},{"id":"c04_q08","question":"What actually causes oxygen-induced hypercapnia in COPD, per current evidence?","options":["A. Loss of respiratory drive from oxygen administration","B. Primarily ventilation-perfusion mismatch and increased dead space","C. Increased cardiac output","D. Bronchospasm caused by oxygen"],"correct":1,"rationale":"Current evidence attributes oxygen-induced hypercapnia in COPD mainly to V/Q mismatch and increased dead space, not loss of respiratory drive.","difficulty":"Hard"},{"id":"c04_q09","question":"What is the current recommended SpO2 target for titrated oxygen therapy in acute COPD exacerbation?","options":["A. 95-100%","B. 88-92%","C. 70-80%","D. No target — maximize oxygen delivery always"],"correct":1,"rationale":"Current guidance recommends titrated oxygen targeting roughly 88-92% SpO2 in acute COPD exacerbation.","difficulty":"Medium"},{"id":"c04_q10","question":"Should oxygen be withheld from a hypoxic COPD patient out of fear of hypoxic drive?","options":["A. Yes, always withhold oxygen from hypoxic COPD patients","B. No — withholding oxygen creates real risk of harmful, prolonged tissue hypoxia and is not current best practice","C. Only withhold if the patient requests it","D. Only withhold in patients over 80"],"correct":1,"rationale":"Deliberate under-oxygenation due to hypoxic-drive fears is not supported by current evidence and risks harmful tissue hypoxia.","difficulty":"Medium"},{"id":"c04_q11","question":"Why is a 'silent chest' in an asthma patient more concerning than a loud wheeze?","options":["A. It means the patient is improving and moving more air","B. It means too little air is moving to produce noise, signaling near-complete airway obstruction","C. It has no clinical significance","D. It only occurs in mild asthma"],"correct":1,"rationale":"A silent chest reflects minimal air movement — a more ominous finding than a loud wheeze, which at least indicates airflow.","difficulty":"Medium"},{"id":"c04_q12","question":"Which findings suggest severe asthma distress requiring rapid escalation?","options":["A. Ability to speak in full sentences and mild wheeze","B. Inability to speak in full sentences, accessory muscle use, altered mental status, or silent chest","C. Normal mental status and loud wheeze only","D. Mild cough without wheeze"],"correct":1,"rationale":"Inability to speak in full sentences, accessory muscle use, altered mental status, and a silent chest are all signs of severe distress warranting rapid escalation.","difficulty":"Medium"},{"id":"c04_q13","question":"An asthma patient's wheeze suddenly becomes much quieter while their distress visibly worsens. How should this be interpreted?","options":["A. As reassuring improvement","B. As a warning sign of worsening obstruction (approaching silent chest), not improvement","C. As unrelated to their respiratory status","D. As an indication to discontinue bronchodilator therapy"],"correct":1,"rationale":"A quieting wheeze with worsening distress mirrors the pediatric respiratory-failure pattern — it signals worsening obstruction, not improvement, and should prompt escalation.","difficulty":"Hard"},{"id":"c04_q14","question":"What is the field management priority for acute COPD exacerbation regarding oxygen?","options":["A. Titrated oxygen therapy targeting ~88-92% SpO2","B. Maximal oxygen delivery regardless of saturation","C. No oxygen under any circumstances","D. Oxygen only if the patient requests it"],"correct":0,"rationale":"Titrated oxygen to a target of roughly 88-92% SpO2 balances avoiding hypoxia against avoiding unnecessary hyperoxia in COPD exacerbation.","difficulty":"Medium"},{"id":"c04_q15","question":"A patient has both a chronic productive cough with cyanotic appearance and a thin, barrel-chested build with pursed-lip breathing. What does this suggest?","options":["A. Pure emphysema only","B. Overlapping features of chronic bronchitis and emphysema, both under the COPD umbrella","C. This presentation is impossible in a single patient","D. Pure asthma with no COPD component"],"correct":1,"rationale":"Chronic bronchitis and emphysema are classic teaching archetypes; many real COPD patients have overlapping features of both.","difficulty":"Hard"}]},"c05":{"chapter":"c05","questions":[{"id":"c05_q01","question":"What defines preeclampsia?","options":["A. Any blood pressure elevation during pregnancy","B. New-onset hypertension after 20 weeks gestation plus proteinuria, or hypertension plus other organ dysfunction","C. Seizures occurring during pregnancy","D. Gestational diabetes"],"correct":1,"rationale":"Preeclampsia requires new-onset hypertension (typically after 20 weeks) plus proteinuria, or hypertension plus evidence of other organ dysfunction.","difficulty":"Easy"},{"id":"c05_q02","question":"Is preeclampsia simply 'high blood pressure in pregnancy'?","options":["A. Yes, that is the complete definition","B. No — it is a systemic condition that can progress toward severe complications including eclampsia","C. It refers only to blood pressure after delivery","D. It only occurs in the first trimester"],"correct":1,"rationale":"Preeclampsia reflects a broader systemic process, not isolated blood pressure elevation, and can progress to severe complications.","difficulty":"Medium"},{"id":"c05_q03","question":"What defines eclampsia?","options":["A. Preeclampsia plus new seizures or coma not attributable to another cause","B. Any seizure during pregnancy regardless of blood pressure","C. Hypertension alone without other findings","D. Gestational diabetes with seizures"],"correct":0,"rationale":"Eclampsia is defined as preeclampsia with the addition of new seizures or coma that cannot be attributed to another cause.","difficulty":"Easy"},{"id":"c05_q04","question":"What medication is the definitive hospital/ALS treatment for eclamptic seizures?","options":["A. A benzodiazepine alone","B. Magnesium sulfate, per local protocol","C. Insulin","D. Epinephrine"],"correct":1,"rationale":"Magnesium sulfate is the definitive treatment for eclamptic seizures, distinct from typical benzodiazepine-first seizure management.","difficulty":"Medium"},{"id":"c05_q05","question":"Which finding suggests liver involvement in worsening preeclampsia?","options":["A. Right upper quadrant or epigastric pain","B. Ankle swelling alone","C. Mild headache only","D. Normal blood pressure"],"correct":0,"rationale":"Right upper quadrant or epigastric pain suggests liver involvement and is a warning sign of worsening preeclampsia.","difficulty":"Medium"},{"id":"c05_q06","question":"Which of the following is a warning sign of worsening preeclampsia?","options":["A. Severe or persistent headache with visual disturbances","B. Mild fatigue with normal blood pressure","C. Normal proteinuria and normal blood pressure","D. Mild nausea without other findings"],"correct":0,"rationale":"Severe/persistent headache and visual disturbances are recognized warning signs that preeclampsia may be worsening toward severe disease or eclampsia.","difficulty":"Medium"},{"id":"c05_q07","question":"Why is left lateral positioning used for a pregnant patient late in pregnancy?","options":["A. To avoid aortocaval compression from the gravid uterus, which reduces venous return","B. It has no physiologic benefit and is purely for comfort","C. To reduce fetal heart rate","D. To prevent preeclampsia from developing"],"correct":0,"rationale":"Left lateral positioning (or manual uterine displacement) helps avoid aortocaval compression, improving venous return and cardiac output.","difficulty":"Medium"},{"id":"c05_q08","question":"Why should stimulation (bright lights, loud noise) be minimized in a patient with severe preeclampsia?","options":["A. Stimulation can precipitate a seizure in severe preeclampsia","B. It has no clinical relevance","C. It only matters postpartum","D. It is purely a comfort measure with no seizure risk"],"correct":0,"rationale":"Minimizing external stimulation is a recognized precaution in severe preeclampsia because such stimulation can precipitate a seizure.","difficulty":"Medium"},{"id":"c05_q09","question":"What is the field management for a pregnant patient with suspected preeclampsia?","options":["A. Left lateral positioning, minimize stimulation, monitor BP, transport to obstetric-capable facility","B. Supine positioning with no monitoring","C. Withhold transport until symptoms resolve","D. Immediate magnesium sulfate administration by BLS providers"],"correct":0,"rationale":"Field management includes positioning, minimizing stimulation, close BP monitoring, and transport to an obstetric-capable facility.","difficulty":"Medium"},{"id":"c05_q10","question":"What is the field management for an active eclamptic seizure?","options":["A. Standard seizure airway/injury precautions, left lateral positioning once feasible, minimize stimulation, rapid transport","B. Immediate defibrillation","C. Withhold all intervention until hospital arrival","D. Prone positioning throughout"],"correct":0,"rationale":"Eclamptic seizure management follows standard seizure precautions with pregnancy-specific positioning and stimulation considerations, plus rapid transport.","difficulty":"Medium"},{"id":"c05_q11","question":"How should a new seizure in a pregnant patient past 20 weeks be treated until proven otherwise?","options":["A. As a routine seizure unrelated to pregnancy","B. As possible eclampsia","C. As a psychiatric event","D. As a normal finding requiring no action"],"correct":1,"rationale":"A new seizure in this context should be treated as possible eclampsia until proven otherwise, given the severity of the condition.","difficulty":"Medium"},{"id":"c05_q12","question":"A 32-week pregnant patient reports sudden significant facial and hand swelling along with a blood pressure of 158/102 mmHg. What should this raise concern for?","options":["A. Normal pregnancy-related swelling requiring no further evaluation","B. Possible preeclampsia, given the combination of hypertension and sudden significant edema","C. Definite eclampsia, since edema is present","D. A cardiac arrhythmia unrelated to pregnancy"],"correct":1,"rationale":"Sudden significant swelling combined with markedly elevated blood pressure late in pregnancy is a recognized warning sign of preeclampsia.","difficulty":"Hard"},{"id":"c05_q13","question":"A pregnant patient with known preeclampsia develops a generalized seizure. What should ongoing field priorities include after the seizure resolves?","options":["A. No further monitoring is needed once the seizure stops","B. Continued monitoring for repeat seizure and worsening signs, maintaining left lateral positioning during transport","C. Immediate discharge from care","D. Placing the patient supine for the remainder of transport"],"correct":1,"rationale":"After an eclamptic seizure, ongoing monitoring for recurrence and worsening severe-preeclampsia signs is essential, along with maintaining left lateral positioning.","difficulty":"Medium"},{"id":"c05_q14","question":"Why is it important not to dismiss a pregnant patient's severe headache as a routine complaint?","options":["A. Because severe headache is a recognized warning sign of worsening preeclampsia","B. Headaches in pregnancy are never clinically significant","C. Headache is only relevant if accompanied by fever","D. Headache in pregnancy always indicates labor"],"correct":0,"rationale":"A severe or persistent headache is a warning sign that should prompt evaluation for preeclampsia rather than dismissal as routine.","difficulty":"Medium"},{"id":"c05_q15","question":"What distinguishes eclampsia from preeclampsia?","options":["A. Eclampsia requires proteinuria while preeclampsia does not","B. Eclampsia is preeclampsia plus new seizures or coma not attributable to another cause","C. Eclampsia occurs before 20 weeks gestation while preeclampsia occurs after","D. There is no meaningful distinction between the two"],"correct":1,"rationale":"Eclampsia is specifically defined as preeclampsia with the addition of new seizures or coma, representing a severe progression of the same process.","difficulty":"Medium"}]},"c06":{"chapter":"c06","questions":[{"id":"c06_q01","question":"What should be assessed before approaching a patient in behavioral crisis?","options":["A. Scene safety from a distance — weapons, exits, patient affect","B. Nothing — approach immediately to begin assessment","C. Only the chief complaint reported by dispatch","D. The patient's insurance status"],"correct":0,"rationale":"Scene safety assessment from a distance precedes patient contact in behavioral emergencies, given the elevated risk of unpredictable violence.","difficulty":"Easy"},{"id":"c06_q02","question":"What should happen when a credible safety concern is identified on a behavioral call?","options":["A. Proceed with patient contact regardless","B. Involve law enforcement per local protocol before approaching","C. Ignore the concern if the call seems urgent","D. Wait indefinitely with no action"],"correct":1,"rationale":"Credible safety concerns should prompt law enforcement involvement per local protocol before EMS approaches the patient.","difficulty":"Easy"},{"id":"c06_q03","question":"What does SEA-3 stand for?","options":["A. Safety, Emotional state, Appearance, Activity, Speech","B. Scene, Exam, Assessment, Airway, Attitude","C. Signs, Events, Allergies, Age, Activity","D. Safety, Escalation, Anxiety, Agitation, Awareness"],"correct":0,"rationale":"SEA-3 stands for Safety, Emotional state, Appearance, Activity, and Speech.","difficulty":"Medium"},{"id":"c06_q04","question":"What is assessed under 'Appearance' in the SEA-3 framework?","options":["A. Grooming, hygiene, and dress as clues to functioning","B. Blood pressure and heart rate","C. Pupil size","D. Skin color only"],"correct":0,"rationale":"Appearance in SEA-3 refers to grooming, hygiene, and dress, which can indicate a patient's level of functioning.","difficulty":"Medium"},{"id":"c06_q05","question":"What is assessed under 'Activity' in the SEA-3 framework?","options":["A. Psychomotor activity — agitation, retardation, restlessness","B. Recent physical exercise history","C. Employment status","D. Medication compliance"],"correct":0,"rationale":"Activity in SEA-3 refers to psychomotor activity level, such as agitation or retardation.","difficulty":"Medium"},{"id":"c06_q06","question":"What type of questioning is preferred during de-escalation?","options":["A. Rapid-fire closed questions","B. Open-ended questions","C. No questions at all","D. Only yes/no questions"],"correct":1,"rationale":"Open-ended questions are preferred during de-escalation, as they invite the patient to share more and feel less interrogated.","difficulty":"Easy"},{"id":"c06_q07","question":"Should a provider argue with or directly challenge a patient's delusional content?","options":["A. Yes, to correct the misperception","B. No — avoid arguing with or directly challenging delusional content","C. Only if the delusion seems dangerous","D. Only during transport"],"correct":1,"rationale":"De-escalation avoids arguing with or challenging delusional content directly, as this tends to increase agitation rather than help.","difficulty":"Medium"},{"id":"c06_q08","question":"What is the primary goal of field de-escalation?","options":["A. To resolve the underlying psychiatric condition","B. To reduce the patient's perceived threat level and build cooperation for safe assessment and transport","C. To convince the patient they are wrong","D. To sedate the patient immediately"],"correct":1,"rationale":"De-escalation aims to reduce perceived threat and build cooperation, not to treat or resolve the psychiatric condition itself in the field.","difficulty":"Medium"},{"id":"c06_q09","question":"When is physical restraint an appropriate first response in a behavioral emergency?","options":["A. It is always the first response for agitated patients","B. It is a last resort, used only after de-escalation fails and the patient poses immediate danger","C. It should be used for every behavioral call to prevent injury","D. It is never appropriate under any circumstances"],"correct":1,"rationale":"Restraint is reserved for situations where de-escalation has failed and immediate danger exists — not a first response.","difficulty":"Medium"},{"id":"c06_q10","question":"What is abandonment in the EMS context?","options":["A. Refusing to transport a patient who declines care","B. Terminating patient care without ensuring an equal or higher level of care continues","C. Documenting a patient's refusal of care","D. Calling for additional resources on scene"],"correct":1,"rationale":"Abandonment specifically means stopping care without transferring the patient to an equal or higher level of care.","difficulty":"Medium"},{"id":"c06_q11","question":"What distinction matters when a patient refuses care?","options":["A. Whether the patient competently refuses (with informed-refusal documentation) versus lacking capacity to refuse","B. Only whether the patient is polite about refusing","C. Whether the refusal happens indoors or outdoors","D. There is no meaningful distinction to make"],"correct":0,"rationale":"Distinguishing a competent, informed refusal from a refusal by a patient lacking capacity is central to avoiding both inappropriate care and abandonment.","difficulty":"Hard"},{"id":"c06_q12","question":"A patient shows disorganized speech, poor grooming, and marked psychomotor agitation together. How should this combination be interpreted?","options":["A. As no more significant than any single finding alone","B. As a higher-risk overall picture than any one finding in isolation","C. As evidence the patient is exaggerating symptoms","D. As irrelevant to behavioral risk assessment"],"correct":1,"rationale":"The SEA-3 framework's value comes from viewing findings together — multiple concerning findings combined paint a higher-risk picture than any single element alone.","difficulty":"Hard"},{"id":"c06_q13","question":"Why is scene safety assessment from a distance emphasized in behavioral emergencies specifically?","options":["A. Because agitated, psychotic, or intoxicated patients can become unpredictably violent, and provider safety is a prerequisite for helping the patient","B. Because behavioral patients are never dangerous","C. Because it is only a formality with no real safety benefit","D. Because it delays care unnecessarily and should be skipped when possible"],"correct":0,"rationale":"Behavioral emergencies carry elevated unpredictability risk; assessing safety before approach protects providers so they can actually deliver care.","difficulty":"Medium"},{"id":"c06_q14","question":"What non-verbal de-escalation techniques are recommended?","options":["A. Maintaining a non-threatening posture and appropriate distance, avoiding sudden movements","B. Standing very close and making direct, prolonged eye contact","C. Crossing arms and standing directly in front of the patient","D. Moving quickly to physically guide the patient"],"correct":0,"rationale":"Non-threatening posture, appropriate distance, and avoiding sudden movements are core non-verbal de-escalation techniques.","difficulty":"Medium"},{"id":"c06_q15","question":"A behavioral-emergency patient competently and clearly refuses transport after a thorough capacity assessment and informed-refusal discussion. What should the provider do?","options":["A. Physically restrain and transport against the patient's will regardless of capacity","B. Document the informed refusal per protocol and provide appropriate resources/follow-up guidance, respecting the patient's autonomy","C. Abandon the patient without any documentation","D. Ignore the refusal and repeat the same questions indefinitely"],"correct":1,"rationale":"A competent, informed refusal should be respected and properly documented — this is different from abandonment, which involves terminating care inappropriately without ensuring continuity for a patient who needs it.","difficulty":"Hard"}]},"c07":{"chapter":"c07","questions":[{"id":"c07_q01","question":"What is a delusion?","options":["A. A false sensory perception with no external stimulus","B. A fixed, false belief that persists despite clear evidence against it","C. A normal variation in mood","D. A memory impairment"],"correct":1,"rationale":"A delusion is a fixed, false belief maintained despite contrary evidence — distinct from a hallucination, which is a sensory phenomenon.","difficulty":"Easy"},{"id":"c07_q02","question":"What is a hallucination?","options":["A. A fixed, false belief","B. A false sensory perception with no external stimulus","C. A memory of a past traumatic event","D. A mood disturbance"],"correct":1,"rationale":"A hallucination is a false sensory perception (e.g., hearing or seeing something not actually present) — distinct from a delusion, which is a belief.","difficulty":"Easy"},{"id":"c07_q03","question":"What is the core distinction between a delusion and a hallucination?","options":["A. Delusion = belief; hallucination = sensory perception","B. They are interchangeable terms for the same phenomenon","C. Delusion only occurs in mood disorders; hallucination only in schizophrenia","D. Delusion is always visual; hallucination is always auditory"],"correct":0,"rationale":"The key distinction is that a delusion is a belief phenomenon, while a hallucination is a sensory phenomenon.","difficulty":"Medium"},{"id":"c07_q04","question":"What causes can produce psychotic symptoms?","options":["A. Only primary psychotic disorders like schizophrenia","B. Primary psychotic disorders, mood disorders with psychotic features, or organic/medical causes","C. Only substance intoxication","D. Psychotic symptoms have no identifiable causes"],"correct":1,"rationale":"Psychotic symptoms can arise from primary psychotic disorders, mood disorders with psychotic features, or organic/medical causes such as substance use or delirium.","difficulty":"Medium"},{"id":"c07_q05","question":"Are prehospital providers expected to diagnose the underlying cause of psychotic symptoms?","options":["A. Yes, definitive diagnosis is a required field skill","B. No — the priority is safe assessment, ruling out organic/reversible causes when feasible, and safe transport","C. Only paramedics are expected to diagnose, not EMTs","D. Diagnosis is irrelevant to prehospital care"],"correct":1,"rationale":"Field providers focus on safe assessment and recognition, not definitive psychiatric diagnosis.","difficulty":"Medium"},{"id":"c07_q06","question":"What are core features of a major depressive episode?","options":["A. Persistent low mood, loss of interest/pleasure, sleep/appetite changes, low energy","B. Elevated mood and decreased need for sleep","C. Recurrent panic episodes with tachycardia","D. Re-experiencing symptoms following trauma"],"correct":0,"rationale":"A major depressive episode is characterized by persistent low mood, anhedonia, sleep/appetite changes, and low energy.","difficulty":"Easy"},{"id":"c07_q07","question":"What are core features of a manic episode?","options":["A. Persistent low mood and low energy","B. Elevated or irritable mood, decreased need for sleep, rapid/pressured speech, grandiosity, risky behavior","C. Recurrent discrete episodes of fear with physical symptoms","D. Avoidance and hyperarousal following trauma"],"correct":1,"rationale":"A manic episode features elevated/irritable mood, reduced sleep need, pressured speech, grandiosity, and risky/impulsive behavior.","difficulty":"Medium"},{"id":"c07_q08","question":"Why is mania field-relevant beyond the mood elevation itself?","options":["A. Impaired judgment during mania can create acute safety risks","B. Mania has no impact on safety or behavior","C. Manic patients are always cooperative","D. Mania only affects sleep patterns"],"correct":0,"rationale":"Impaired judgment during mania can lead to reckless behavior and occasional aggression, creating field-relevant safety considerations.","difficulty":"Medium"},{"id":"c07_q09","question":"What symptoms characterize a panic attack?","options":["A. Recurrent, discrete episodes of intense fear with tachycardia, dyspnea, chest tightness, sense of impending doom","B. Persistent low mood over weeks","C. Fixed false beliefs","D. Memory impairment"],"correct":0,"rationale":"Panic attacks are discrete episodes of intense fear accompanied by physical symptoms including tachycardia, dyspnea, and chest tightness.","difficulty":"Easy"},{"id":"c07_q10","question":"A patient with known panic disorder presents with chest pain and dyspnea. What is the correct approach?","options":["A. Assume it is a panic attack based on history and skip medical evaluation","B. Still rule out true medical emergencies (ECG, vitals, glucose) rather than assuming panic disorder from history alone","C. Refuse to treat since the patient has a psychiatric history","D. Only assess mental status, not vital signs"],"correct":1,"rationale":"Panic attacks can mimic or coexist with genuine medical emergencies, so appropriate medical rule-out is still required despite a known panic disorder history.","difficulty":"Hard"},{"id":"c07_q11","question":"What are core features of PTSD?","options":["A. Re-experiencing symptoms, avoidance, negative mood/cognition changes, hyperarousal following trauma","B. Elevated mood and grandiosity","C. Fixed false beliefs without sensory changes","D. Recurrent discrete panic episodes only"],"correct":0,"rationale":"PTSD is defined by re-experiencing, avoidance, negative mood/cognition changes, and hyperarousal symptoms following a traumatic event.","difficulty":"Medium"},{"id":"c07_q12","question":"Why might aspects of an EMS encounter trigger or worsen PTSD symptoms?","options":["A. Uniforms, restraint, or physical contact can serve as trauma reminders","B. EMS encounters have no relationship to PTSD symptoms","C. Only ambulance sirens can trigger PTSD symptoms","D. PTSD symptoms cannot be triggered by external events"],"correct":0,"rationale":"Certain aspects of the EMS encounter can serve as trauma reminders for PTSD patients, making calm explanation of actions beneficial when feasible.","difficulty":"Medium"},{"id":"c07_q13","question":"Does asking a patient directly about suicidal thoughts increase their risk of suicide?","options":["A. Yes, asking plants the idea","B. No — direct, non-judgmental questioning does not increase risk and is appropriate when indicated","C. Only increases risk in adolescents","D. Only increases risk if asked more than once"],"correct":1,"rationale":"Evidence and standard teaching indicate that asking directly about suicidal ideation does not increase risk — it is an appropriate and necessary assessment question.","difficulty":"Medium"},{"id":"c07_q14","question":"What factors make a suicidal patient a high-risk presentation?","options":["A. A specific plan, access to lethal means, or a prior attempt history","B. Any mention of sadness without further detail","C. A history of seeking therapy","D. Being over the age of 65"],"correct":0,"rationale":"A specific plan, access to lethal means, and prior attempt history are recognized high-risk factors warranting careful safety consideration and transport.","difficulty":"Medium"},{"id":"c07_q15","question":"A patient describes hearing voices commanding them to act, while also holding an unshakeable belief that neighbors are monitoring them through the walls. What phenomena are present?","options":["A. Only a delusion (the monitoring belief) — the voices are a memory","B. Both a hallucination (hearing voices) and a delusion (the monitoring belief)","C. Only a hallucination — beliefs are not part of psychosis","D. Neither — this is a normal stress response"],"correct":1,"rationale":"Hearing voices with no external source is a hallucination; the fixed false belief of being monitored despite no evidence is a delusion — both can co-occur in a psychotic presentation.","difficulty":"Hard"}]},"c08":{"chapter":"c08","questions":[{"id":"c08_q01","question":"Which personality disorders fall under DSM-5-TR Cluster A?","options":["A. Paranoid, schizoid, schizotypal","B. Antisocial, borderline, histrionic, narcissistic","C. Avoidant, dependent, obsessive-compulsive","D. Bipolar and major depressive"],"correct":0,"rationale":"Cluster A ('odd/eccentric') includes paranoid, schizoid, and schizotypal personality disorders.","difficulty":"Medium"},{"id":"c08_q02","question":"Which personality disorders fall under DSM-5-TR Cluster B?","options":["A. Paranoid, schizoid, schizotypal","B. Antisocial, borderline, histrionic, narcissistic","C. Avoidant, dependent, obsessive-compulsive","D. Panic and PTSD"],"correct":1,"rationale":"Cluster B ('dramatic/emotional/erratic') includes antisocial, borderline, histrionic, and narcissistic personality disorders.","difficulty":"Medium"},{"id":"c08_q03","question":"Which personality disorders fall under DSM-5-TR Cluster C?","options":["A. Paranoid, schizoid, schizotypal","B. Antisocial, borderline, histrionic, narcissistic","C. Avoidant, dependent, obsessive-compulsive","D. Schizophrenia spectrum"],"correct":2,"rationale":"Cluster C ('anxious/fearful') includes avoidant, dependent, and obsessive-compulsive personality disorders.","difficulty":"Medium"},{"id":"c08_q04","question":"Are field providers expected to diagnose a patient's specific personality disorder?","options":["A. Yes, this is a required field skill","B. No — this is recognition-level exam vocabulary; field care focuses on calm, consistent, non-judgmental care","C. Only paramedics diagnose personality disorders","D. Personality disorder diagnosis is irrelevant to any EMS context"],"correct":1,"rationale":"This framework is recognition-level material; providers are not expected to diagnose, only to maintain consistent calm care.","difficulty":"Medium"},{"id":"c08_q05","question":"When does delirium tremens (DTs) classically begin relative to the last drink?","options":["A. Within the first few hours","B. 48-96 hours after the last drink","C. Only after 2 weeks","D. DTs occurs only during active drinking"],"correct":1,"rationale":"DTs classically begins 48-96 hours after the last drink, later than milder withdrawal symptoms which can start within hours.","difficulty":"Medium"},{"id":"c08_q06","question":"What are the features of delirium tremens?","options":["A. Severe confusion, autonomic instability, tremor, visual/tactile hallucinations","B. Mild anxiety and tremor only","C. Isolated hypertension without other findings","D. Painless, asymptomatic confusion"],"correct":0,"rationale":"DTs features severe confusion/disorientation, autonomic instability (tachycardia, hypertension, fever, diaphoresis), tremor, and hallucinations.","difficulty":"Medium"},{"id":"c08_q07","question":"Is delirium tremens a life-threatening condition?","options":["A. No, it always resolves without treatment","B. Yes — it carries meaningful mortality risk if untreated","C. Only in patients under 30","D. Only if hallucinations are visual, not tactile"],"correct":1,"rationale":"DTs is a true medical emergency with meaningful mortality risk, requiring prompt recognition and treatment.","difficulty":"Medium"},{"id":"c08_q08","question":"What is the classic presentation of stimulant intoxication?","options":["A. Pinpoint pupils and respiratory depression","B. Agitation, tachycardia, hypertension, diaphoresis, dilated pupils","C. Slow heart rate and constricted pupils","D. Isolated nausea without other findings"],"correct":1,"rationale":"Stimulant intoxication classically presents with agitation, tachycardia, hypertension, diaphoresis, and dilated pupils.","difficulty":"Medium"},{"id":"c08_q09","question":"What is the classic presentation of opioid intoxication?","options":["A. Agitation and dilated pupils","B. Respiratory depression, pinpoint pupils, altered mental status","C. Hypertension and tachycardia","D. Hyperthermia and diaphoresis"],"correct":1,"rationale":"Opioid intoxication classically presents with respiratory depression, pinpoint (miotic) pupils, and altered mental status.","difficulty":"Easy"},{"id":"c08_q10","question":"Why should vital signs and glucose still be checked in a patient with an obvious substance-related presentation?","options":["A. It is unnecessary once a substance cause is presumed","B. Substance-related presentations can coexist with trauma, psychiatric illness, or an unrelated medical emergency","C. Vital signs are only relevant for cardiac patients","D. Glucose is irrelevant to substance-related presentations"],"correct":1,"rationale":"A presumed substance cause does not exclude a coexisting or alternative medical problem, so standard assessment continues.","difficulty":"Medium"},{"id":"c08_q11","question":"What cardiac risk is associated with eating disorders?","options":["A. Arrhythmia from electrolyte disturbances (e.g., hypokalemia from purging or malnutrition)","B. No cardiac risk is associated with eating disorders","C. Only hypertension, never arrhythmia","D. Risk only occurs in male patients"],"correct":0,"rationale":"Electrolyte disturbances (like hypokalemia) from purging behaviors or malnutrition create real cardiac arrhythmia risk in eating disorder patients.","difficulty":"Medium"},{"id":"c08_q12","question":"A patient with a known eating disorder reports palpitations and dizziness. How should this be evaluated?","options":["A. Dismissed as anxiety related to their eating disorder","B. Evaluated with the same seriousness as any other patient, including ECG/monitoring where available, given real arrhythmia risk","C. Ignored unless the patient loses consciousness","D. Treated only with reassurance and no assessment"],"correct":1,"rationale":"Cardiac symptoms in eating disorder patients reflect a genuine medical risk and should be evaluated thoroughly, not dismissed as purely psychiatric.","difficulty":"Hard"},{"id":"c08_q13","question":"Why do high-risk substance-related presentations require heightened vigilance beyond standard de-escalation?","options":["A. Intoxicated or withdrawing patients can deteriorate quickly and unpredictably","B. These patients are always calm and predictable","C. Vigilance is unnecessary once de-escalation begins","D. Only trauma patients require vigilance"],"correct":0,"rationale":"Because intoxicated/withdrawing patients can change status rapidly, heightened vigilance is added to standard de-escalation practices.","difficulty":"Medium"},{"id":"c08_q14","question":"A patient is 60 hours out from their last alcoholic drink and now shows severe confusion, tremor, tachycardia, hypertension, and visual hallucinations. What should this be recognized as?","options":["A. Mild, expected alcohol withdrawal requiring only reassurance","B. Delirium tremens — a life-threatening emergency requiring prompt recognition and supportive care","C. A primary psychotic disorder unrelated to alcohol use","D. Normal anxiety with no medical significance"],"correct":1,"rationale":"The 48-96 hour timing plus severe confusion, autonomic instability, and hallucinations are classic for DTs, a life-threatening emergency distinct from mild withdrawal.","difficulty":"Hard"},{"id":"c08_q15","question":"What common approach reduces escalation risk across personality-disorder, substance-related, and DTs presentations?","options":["A. Consistent, calm, non-judgmental care regardless of the underlying condition","B. Confrontational questioning to establish authority","C. Avoiding all interaction with the patient","D. Immediate physical restraint in every case"],"correct":0,"rationale":"Calm, consistent, non-judgmental care is the common thread that reduces escalation risk across these varied high-risk presentations.","difficulty":"Medium"}]},"c09":{"chapter":"c09","questions":[{"id":"c09_q01","question":"What is delirium?","options":["A. A chronic, progressive decline developing over months to years","B. An acute-onset, fluctuating disturbance in attention/awareness developing over hours to days, often reversible","C. A permanent cognitive impairment with no reversible causes","D. A normal part of aging requiring no evaluation"],"correct":1,"rationale":"Delirium is acute, fluctuating, and often reversible once the underlying cause is treated.","difficulty":"Easy"},{"id":"c09_q02","question":"What is dementia?","options":["A. An acute, fluctuating disturbance developing over hours","B. A chronic, progressive decline in cognitive function developing over months to years, generally not reversible","C. A condition always caused by medication effects","D. Always caused by infection"],"correct":1,"rationale":"Dementia is a chronic, progressive cognitive decline, generally not reversible, unlike delirium.","difficulty":"Easy"},{"id":"c09_q03","question":"Can delirium and dementia coexist in the same patient?","options":["A. No, they are mutually exclusive","B. Yes — a patient with baseline dementia can develop superimposed delirium from an acute illness","C. Only in patients under 65","D. Only if the patient has no prior cognitive history"],"correct":1,"rationale":"Delirium can be superimposed on baseline dementia, which is part of why distinguishing acute change from chronic baseline matters.","difficulty":"Medium"},{"id":"c09_q04","question":"How should acute confusion in a geriatric patient with a previously normal cognitive baseline be treated by default?","options":["A. As expected age-related decline requiring no further workup","B. As delirium until proven otherwise, prompting a search for a reversible cause","C. As a new diagnosis of dementia to be confirmed in the field","D. As a purely psychiatric condition"],"correct":1,"rationale":"New acute confusion in a previously cognitively normal older adult should default to a delirium workup, not an assumption of dementia or normal aging.","difficulty":"Medium"},{"id":"c09_q05","question":"What should a sudden worsening of confusion in a known dementia patient prompt?","options":["A. No action, since dementia patients are expected to fluctuate","B. A delirium workup, since this is not simply 'their dementia getting worse today'","C. Immediate psychiatric referral only","D. Assumption of a new dementia diagnosis"],"correct":1,"rationale":"A sudden change in a dementia patient's baseline should prompt consideration of superimposed delirium and its reversible causes.","difficulty":"Medium"},{"id":"c09_q06","question":"Which infections classically present with confusion as a primary or only symptom in older adults?","options":["A. Common cold and sinusitis","B. Urinary tract infection and pneumonia","C. Only meningitis","D. Infections never present with confusion"],"correct":1,"rationale":"UTI and pneumonia are classic infections that can present primarily or only as confusion in geriatric patients.","difficulty":"Medium"},{"id":"c09_q07","question":"Which of the following is a surprisingly common precipitant of delirium in older adults?","options":["A. Urinary retention or constipation","B. Regular exercise","C. Adequate hydration","D. Normal sleep patterns"],"correct":0,"rationale":"Urinary retention and constipation are often-overlooked but common precipitants of geriatric delirium.","difficulty":"Hard"},{"id":"c09_q08","question":"What should be checked immediately in an acutely confused geriatric patient?","options":["A. Blood glucose","B. Vaccination history","C. Recent dental visits","D. Employment status"],"correct":0,"rationale":"A glucose check is a core, fast, high-value step in evaluating acute confusion in any patient, including geriatric patients.","difficulty":"Easy"},{"id":"c09_q09","question":"What is a 'silent MI'?","options":["A. A myocardial infarction presenting without chest pain, instead as confusion, weakness, or shortness of breath","B. An MI that never causes any symptoms at all","C. An MI that only occurs in young patients","D. A minor, clinically insignificant cardiac event"],"correct":0,"rationale":"A silent MI presents atypically without chest pain, more common in older adults, and may show as confusion, weakness, or dyspnea alone.","difficulty":"Medium"},{"id":"c09_q10","question":"How might infection present atypically in an older adult?","options":["A. With an exaggerated fever response","B. Without fever, due to a blunted febrile response","C. Identically to younger patients in all cases","D. With no other symptoms possible"],"correct":1,"rationale":"Older adults often have a blunted febrile response, so infection can present without the expected fever.","difficulty":"Medium"},{"id":"c09_q11","question":"How might an acute abdomen present atypically in an older adult?","options":["A. With more severe pain than in younger patients","B. With minimal pain despite significant underlying pathology","C. Identically to a young, healthy adult","D. Acute abdomen cannot occur in older adults"],"correct":1,"rationale":"Older adults may have minimal pain despite significant intra-abdominal pathology, warranting a lower threshold of suspicion.","difficulty":"Medium"},{"id":"c09_q12","question":"Why does an older adult's own personal baseline matter more than a generic 'normal for age' assumption?","options":["A. It doesn't matter — all older adults should be assessed identically","B. The patient's own baseline (per caregiver report) is the most useful reference point for determining what's abnormal today","C. Baseline information is only relevant for pediatric patients","D. Baseline assessment replaces the need for a glucose check"],"correct":1,"rationale":"Comparing to the patient's own known baseline, rather than a generic assumption, is the most accurate way to identify a true acute change.","difficulty":"Medium"},{"id":"c09_q13","question":"An 82-year-old with known mild dementia (per family) is found more confused than usual, with a low-grade fever and new urinary symptoms. What should this prompt?","options":["A. Assumption that this is simply dementia progression, no further workup needed","B. A delirium workup, given the acute change from baseline and possible UTI as a reversible cause","C. Immediate diagnosis of a new psychiatric condition","D. No action since the patient has a known dementia diagnosis"],"correct":1,"rationale":"Acute worsening from a known dementia baseline, combined with signs suggesting infection, should prompt a delirium workup rather than dismissal as dementia progression.","difficulty":"Hard"},{"id":"c09_q14","question":"A 79-year-old presents with only mild fatigue and confusion, no chest pain, but is later found to be having a myocardial infarction. What does this illustrate?","options":["A. Older adults always present with classic MI symptoms","B. The atypical presentation phenomenon — a lower threshold of suspicion is warranted in geriatric patients","C. MI cannot occur without chest pain in any patient","D. This presentation should be dismissed as unrelated to cardiac disease"],"correct":1,"rationale":"This scenario illustrates 'silent MI' and the broader principle that geriatric patients often present atypically, requiring a lower threshold of clinical suspicion.","difficulty":"Hard"},{"id":"c09_q15","question":"What distinguishes the field approach to 'mild-seeming' symptoms in a geriatric patient from a younger adult?","options":["A. No difference — the same threshold of suspicion applies to all ages","B. A lower threshold of suspicion and broader differential are warranted, since atypical presentations can mask serious conditions","C. Geriatric patients should always be assumed to be exaggerating symptoms","D. Mild symptoms in geriatric patients can always be safely dismissed"],"correct":1,"rationale":"Given the tendency toward atypical presentation in older adults, providers should maintain a lower threshold of suspicion for serious underlying conditions.","difficulty":"Medium"}]},"c10":{"chapter":"c10","questions":[{"id":"c10_q01","question":"What is polypharmacy typically defined as?","options":["A. Taking any prescription medication","B. Taking five or more medications","C. Taking only over-the-counter medications","D. Taking medications from more than one pharmacy"],"correct":1,"rationale":"Polypharmacy is typically defined as taking five or more medications, increasing risk of interactions and side effects.","difficulty":"Easy"},{"id":"c10_q02","question":"What medication classes carry particular fall risk in older adults?","options":["A. Sedatives/hypnotics and some psychiatric medications","B. Vitamins and supplements","C. Topical creams","D. Eye drops"],"correct":0,"rationale":"Sedatives, hypnotics, and certain psychiatric medications increase fall risk through sedation or impaired balance.","difficulty":"Medium"},{"id":"c10_q03","question":"What medication classes carry particular bleeding risk after trauma?","options":["A. Antibiotics","B. Anticoagulants and antiplatelet medications","C. Antihistamines","D. Antacids"],"correct":1,"rationale":"Anticoagulant and antiplatelet medications increase bleeding risk after trauma, including minor head injury.","difficulty":"Easy"},{"id":"c10_q04","question":"Should a geriatric fall be assumed to be purely mechanical without further investigation?","options":["A. Yes, falls in older adults are always mechanical","B. No — falls can be the presenting symptom of a medical emergency (arrhythmia, stroke, hypoglycemia, etc.)","C. Only if the patient is under 75","D. Only if there were no witnesses"],"correct":1,"rationale":"A fall should not be assumed purely mechanical; it may be the presenting symptom of an underlying medical emergency.","difficulty":"Medium"},{"id":"c10_q05","question":"What should be asked about the circumstances of a geriatric fall?","options":["A. Witnessed vs. unwitnessed, preceding symptoms, ability to recall the event","B. Only the exact time of day","C. Only whether the patient was wearing shoes","D. Nothing beyond confirming the fall occurred"],"correct":0,"rationale":"A thorough fall history includes whether it was witnessed, any preceding warning symptoms, and the patient's recall of the event.","difficulty":"Medium"},{"id":"c10_q06","question":"Why might occult injury be more likely to be missed in older adults after a fall?","options":["A. Older adults may have a blunted pain response","B. Older adults always report pain accurately","C. Occult injury cannot occur in geriatric patients","D. Older adults are less likely to have any injury"],"correct":0,"rationale":"A blunted pain response in older adults can mask significant injury, making thorough exam important regardless of reported pain.","difficulty":"Medium"},{"id":"c10_q07","question":"Why is anticoagulant use plus head injury (even minor) a significant field red flag?","options":["A. It carries meaningfully elevated risk of intracranial hemorrhage with possible delayed symptom onset","B. Anticoagulants have no effect on head injury risk","C. It only matters for injuries above the neck in adults under 50","D. This combination is not clinically significant"],"correct":0,"rationale":"Anticoagulated patients face elevated intracranial hemorrhage risk after even minor head trauma, and symptoms can be delayed.","difficulty":"Medium"},{"id":"c10_q08","question":"Does a normal initial neurologic exam exclude a developing intracranial bleed in an anticoagulated patient after head injury?","options":["A. Yes, a normal exam rules out any bleed","B. No — a normal initial exam does not exclude a developing bleed","C. Only if the patient is under 60","D. Only if no anticoagulant is involved"],"correct":1,"rationale":"Intracranial hemorrhage in an anticoagulated patient can develop with delayed onset, so an initially normal exam does not exclude it.","difficulty":"Hard"},{"id":"c10_q09","question":"What general findings may raise concern for elder abuse or neglect?","options":["A. Injury-mechanism inconsistency, neglect signs, unexplained/patterned bruising, controlling caregiver behavior","B. A clean, well-maintained living environment","C. A caregiver who welcomes private conversation with the patient","D. Consistent, corroborated injury history"],"correct":0,"rationale":"These findings are recognized general categories that may raise concern for elder abuse or neglect, similar to pediatric maltreatment recognition.","difficulty":"Medium"},{"id":"c10_q10","question":"Is any single finding diagnostic of elder abuse?","options":["A. Yes, bruising alone is diagnostic","B. No — no single finding is diagnostic; the EMS role is recognition and objective documentation","C. Yes, but only in patients with dementia","D. Yes, if the caregiver seems nervous"],"correct":1,"rationale":"As with pediatric maltreatment, no single finding confirms elder abuse; providers document objectively and let appropriate professionals evaluate.","difficulty":"Medium"},{"id":"c10_q11","question":"Are EMS providers mandatory reporters of suspected elder abuse?","options":["A. No, reporting is optional","B. Yes, in essentially all jurisdictions","C. Only if the patient requests it","D. Only social workers are mandatory reporters"],"correct":1,"rationale":"EMS providers are mandatory reporters of suspected elder abuse in essentially all jurisdictions.","difficulty":"Easy"},{"id":"c10_q12","question":"What is the correct EMS approach when elder abuse is suspected?","options":["A. Confront the caregiver directly to obtain a confession","B. Provide standard care, document objectively, communicate calmly and non-accusatorially, and report through appropriate channels","C. Refuse to treat the patient until the situation is clarified","D. Make a definitive determination of abuse before transport"],"correct":1,"rationale":"The EMS role is recognition and reporting, not investigation or confrontation — mirroring the approach to pediatric maltreatment.","difficulty":"Medium"},{"id":"c10_q13","question":"A caregiver insists on answering every question for an alert, oriented geriatric patient and will not leave the room. What should this prompt?","options":["A. No concern — caregivers should always answer for patients","B. Consideration as a potential concern-raising finding, to be documented objectively rather than confronted directly","C. Immediate accusation of the caregiver","D. Refusal to provide care until the caregiver leaves"],"correct":1,"rationale":"A controlling caregiver dynamic is a recognized concern-raising finding that should be documented objectively rather than acted on with direct confrontation.","difficulty":"Hard"},{"id":"c10_q14","question":"A geriatric patient on warfarin reports a minor bump to the head with no current symptoms. What is the correct approach?","options":["A. No transport needed since there are no symptoms","B. Recognize the elevated intracranial hemorrhage risk from anticoagulation despite the minor mechanism and current absence of symptoms, and communicate this clearly at handoff","C. Assume the medication is irrelevant to this injury","D. Delay documentation of the anticoagulant use"],"correct":1,"rationale":"Anticoagulant use with head injury — even seemingly minor and currently asymptomatic — carries meaningful bleed risk that should be evaluated and clearly communicated.","difficulty":"Hard"},{"id":"c10_q15","question":"A patient reports feeling dizzy and having heart palpitations just before falling. How should this fall be approached differently from a simple trip?","options":["A. Identically, since all falls are treated the same regardless of preceding symptoms","B. As a potential medical cause of the fall (e.g., arrhythmia), warranting cardiac evaluation in addition to injury assessment","C. As purely a trauma case with no cardiac relevance","D. As unrelated to any medical condition"],"correct":1,"rationale":"Preceding symptoms like dizziness and palpitations suggest the fall may be a symptom of an underlying medical cause (e.g., arrhythmia), requiring broader evaluation beyond just the traumatic injury.","difficulty":"Medium"}]},"c11":{"chapter":"c11","questions":[{"id":"c11_q01","question":"What is a toxidrome?","options":["A. A recognizable cluster of signs/symptoms associated with a category of toxic exposure","B. A specific antidote for a poison","C. A type of laboratory test","D. A rare, single-symptom presentation"],"correct":0,"rationale":"A toxidrome is a symptom cluster that lets providers act on a recognizable pattern without knowing the exact substance.","difficulty":"Easy"},{"id":"c11_q02","question":"What is the opioid toxidrome?","options":["A. Respiratory depression, pinpoint pupils, altered mental status","B. Agitation, tachycardia, dilated pupils","C. Bradycardia with excessive secretions","D. Dry, flushed skin with urinary retention"],"correct":0,"rationale":"The opioid toxidrome is respiratory depression, pinpoint (miotic) pupils, and altered mental status.","difficulty":"Easy"},{"id":"c11_q03","question":"What is the sympathomimetic (stimulant) toxidrome?","options":["A. Bradycardia and pinpoint pupils","B. Agitation, tachycardia, hypertension, diaphoresis, dilated pupils","C. Excessive salivation and lacrimation","D. Dry skin and urinary retention alone"],"correct":1,"rationale":"Sympathomimetic toxidrome features agitation, tachycardia, hypertension, diaphoresis, and dilated pupils.","difficulty":"Medium"},{"id":"c11_q04","question":"What findings characterize the anticholinergic toxidrome?","options":["A. Altered mental status, dilated pupils, dry flushed skin, tachycardia, urinary retention","B. Excessive secretions and bradycardia","C. Pinpoint pupils and respiratory depression","D. Normal mental status with hypotension"],"correct":0,"rationale":"The anticholinergic toxidrome ('hot as a hare, dry as a bone, red as a beet, blind as a bat, mad as a hatter') includes altered mental status, dilated pupils, dry flushed skin, tachycardia, and urinary retention.","difficulty":"Medium"},{"id":"c11_q05","question":"What is the cholinergic toxidrome associated with?","options":["A. Opioid medications","B. Organophosphate exposure","C. Antihistamine overdose","D. Cocaine use"],"correct":1,"rationale":"The cholinergic toxidrome (excessive secretions, bradycardia, muscle twitching) is classically associated with organophosphate exposure.","difficulty":"Medium"},{"id":"c11_q06","question":"What is the field priority order for suspected poisoning/overdose?","options":["A. Identify the exact substance first, before any other action","B. Scene safety first, then support ABCs, identify substance/amount/time when possible, check glucose","C. Transport immediately with no on-scene assessment","D. Wait for poison control before taking any action"],"correct":1,"rationale":"Scene safety and ABC support take priority over exact substance identification, with glucose checked regardless of presumed cause.","difficulty":"Medium"},{"id":"c11_q07","question":"What distinguishes heat exhaustion from heat stroke?","options":["A. Heat stroke involves altered mental status plus significantly elevated core temperature; heat exhaustion has normal-to-mildly-altered mental status","B. Heat exhaustion is always more severe than heat stroke","C. Heat stroke never involves elevated temperature","D. There is no meaningful clinical distinction"],"correct":0,"rationale":"Heat stroke is the life-threatening endpoint defined by significant altered mental status plus significantly elevated core temperature, distinguishing it from milder heat exhaustion.","difficulty":"Medium"},{"id":"c11_q08","question":"Does the presence of sweating rule out heat stroke?","options":["A. Yes, heat stroke patients never sweat","B. No — some heat stroke patients still sweat, especially with exertional causes","C. Only in patients over 65","D. Sweating is irrelevant to heat illness diagnosis"],"correct":1,"rationale":"Sweating does not exclude heat stroke; altered mental status plus significantly elevated temperature is the defining combination regardless of sweating status.","difficulty":"Hard"},{"id":"c11_q09","question":"What is the appropriate field management for heat exhaustion (normal-to-mildly-altered mental status)?","options":["A. Cooling, rest, and fluids (oral if tolerated and alert)","B. Aggressive ice-water immersion only","C. No treatment needed","D. Immediate advanced airway management"],"correct":0,"rationale":"Heat exhaustion is managed with cooling, rest, and fluids, distinguishing it from the aggressive cooling needed for heat stroke.","difficulty":"Medium"},{"id":"c11_q10","question":"What features characterize mild hypothermia?","options":["A. Absent shivering and unresponsiveness","B. Shivering, mild confusion, intact coordination","C. Cardiac arrest","D. Severe muscle rigidity with no shivering"],"correct":1,"rationale":"Mild hypothermia presents with shivering, mild confusion, and intact coordination, distinguishing it from more severe stages.","difficulty":"Medium"},{"id":"c11_q11","question":"What features characterize severe hypothermia?","options":["A. Vigorous shivering with clear mentation","B. Absent shivering, significantly altered/unresponsive mental status, risk of cardiac arrhythmia and arrest","C. Mild confusion only, with normal cardiac rhythm","D. Normal vital signs with intact coordination"],"correct":1,"rationale":"Severe hypothermia is marked by absent shivering, severe mental status changes, and significant cardiac risk.","difficulty":"Medium"},{"id":"c11_q12","question":"Why must a severely hypothermic patient be handled gently?","options":["A. Rough movement can trigger a fatal arrhythmia in a severely hypothermic heart","B. Gentle handling has no physiologic basis and is purely a comfort measure","C. Rough handling only matters for trauma patients, not hypothermia","D. Hypothermic patients cannot develop arrhythmias"],"correct":0,"rationale":"A severely hypothermic heart is prone to arrhythmia, and rough movement/handling can precipitate a fatal rhythm disturbance.","difficulty":"Medium"},{"id":"c11_q13","question":"Should resuscitation be withheld from a hypothermic patient found in apparent cardiac arrest?","options":["A. Yes, hypothermic arrest patients cannot be resuscitated","B. No — hypothermia can mimic death, and patients have survived prolonged downtime with good outcomes after rewarming; resuscitate per protocol","C. Only attempt resuscitation if the patient is under 40","D. Resuscitation should never be attempted in cold environments"],"correct":1,"rationale":"Hypothermia's protective, death-mimicking effect means resuscitation efforts should generally proceed per protocol rather than being presumed futile based on presentation alone.","difficulty":"Hard"},{"id":"c11_q14","question":"A patient found unresponsive with pinpoint pupils and a respiratory rate of 4/min near drug paraphernalia. What toxidrome does this match, and what is the priority?","options":["A. Anticholinergic toxidrome; priority is IV fluids","B. Opioid toxidrome; priority is airway/ventilation support","C. Cholinergic toxidrome; priority is atropine only","D. Sympathomimetic toxidrome; priority is sedation"],"correct":1,"rationale":"Pinpoint pupils and severe respiratory depression match the opioid toxidrome, making airway/ventilation support the immediate priority.","difficulty":"Medium"},{"id":"c11_q15","question":"A hiker in hot weather has a temperature of 105°F, is confused, and is still visibly sweating. Should the sweating change the diagnosis of heat stroke?","options":["A. Yes, sweating rules out heat stroke by definition","B. No — altered mental status plus significantly elevated temperature still meets the definition of heat stroke regardless of sweating","C. Sweating means this must be heat exhaustion instead","D. Sweating is not relevant to any heat illness assessment"],"correct":1,"rationale":"Sweating does not exclude heat stroke; the combination of altered mental status and significantly elevated core temperature defines heat stroke regardless of sweating status.","difficulty":"Hard"}]},"c12":{"chapter":"c12","questions":[{"id":"c12_q01","question":"What is sepsis?","options":["A. A localized skin infection","B. A life-threatening response to infection that can progress rapidly to septic shock","C. A chronic autoimmune condition","D. A type of allergic reaction"],"correct":1,"rationale":"Sepsis is a life-threatening systemic response to infection with potential to progress to septic shock.","difficulty":"Easy"},{"id":"c12_q02","question":"Can hypothermia, rather than fever, be a sign of sepsis?","options":["A. No, sepsis always causes fever","B. Yes — both fever and hypothermia can indicate sepsis; a low temperature with infection is not reassuring","C. Only in pediatric patients","D. Hypothermia rules out any infectious cause"],"correct":1,"rationale":"Both fever and hypothermia can be seen in sepsis; a low temperature should not be treated as reassuring in the setting of suspected infection.","difficulty":"Medium"},{"id":"c12_q03","question":"What systemic signs, combined with a suspected infection source, suggest sepsis?","options":["A. Fever/hypothermia, tachycardia, tachypnea, altered mental status","B. Isolated mild headache with normal vitals","C. Normal mental status and normal heart rate","D. Improved appetite and energy"],"correct":0,"rationale":"These systemic findings combined with a suspected infection source raise concern for sepsis.","difficulty":"Medium"},{"id":"c12_q04","question":"Why is sepsis considered as time-sensitive as stroke or trauma?","options":["A. Outcomes worsen with delayed recognition and treatment, since early antibiotics/fluids are time-sensitive","B. Sepsis has no time-sensitive component","C. Sepsis only matters if treated within a week","D. Sepsis resolves on its own regardless of treatment timing"],"correct":0,"rationale":"Time-sensitive treatment (early antibiotics, fluid resuscitation) drives outcomes in sepsis, similar to stroke and trauma.","difficulty":"Medium"},{"id":"c12_q05","question":"How can sepsis present atypically in older adults?","options":["A. With dramatic high fever always present","B. Confusion as the primary sign, without a dramatic fever","C. Identically to younger patients in all cases","D. Sepsis cannot occur in older adults"],"correct":1,"rationale":"Consistent with geriatric atypical presentation patterns, sepsis may present primarily as confusion in older adults.","difficulty":"Medium"},{"id":"c12_q06","question":"What is melena, and what does it suggest?","options":["A. Bright red blood per rectum, suggesting lower GI bleeding","B. Black, tarry, foul-smelling stool, suggesting upper GI bleeding","C. Clear vomit with no blood","D. A type of skin rash"],"correct":1,"rationale":"Melena is black, tarry stool classically associated with upper GI bleeding.","difficulty":"Easy"},{"id":"c12_q07","question":"What is hematochezia, and what does it typically suggest?","options":["A. Black, tarry stool from upper GI bleeding","B. Bright red blood per rectum, typically lower GI bleeding (though a brisk upper bleed can also cause it)","C. Vomiting without blood","D. A urinary symptom unrelated to GI bleeding"],"correct":1,"rationale":"Hematochezia is bright red rectal bleeding, typically from a lower GI source, though brisk upper GI bleeds can also present this way.","difficulty":"Medium"},{"id":"c12_q08","question":"What should be assessed in significant GI bleeding beyond the visible amount of blood?","options":["A. Perfusion status, since significant bleeding can cause hypovolemic shock","B. Only the patient's dietary history","C. Only recent medication changes","D. Nothing further is needed once bleeding is confirmed"],"correct":0,"rationale":"Perfusion assessment is critical since significant GI bleeding can lead to hypovolemic shock, which may not correlate directly with visible blood volume.","difficulty":"Medium"},{"id":"c12_q09","question":"What is the classic presentation pattern of bowel obstruction?","options":["A. Colicky abdominal pain, distension, vomiting, absence of bowel movements/flatus","B. Painless abdominal fullness with normal bowel function","C. Isolated diarrhea with no pain","D. Chest pain radiating to the back"],"correct":0,"rationale":"Bowel obstruction classically presents with colicky pain, distension, vomiting, and absent bowel movements/flatus.","difficulty":"Medium"},{"id":"c12_q10","question":"What is the correct field management for suspected bowel obstruction?","options":["A. Encourage oral fluids to prevent dehydration","B. Supportive care (IV fluids, antiemetics per protocol), no oral intake, prompt transport","C. No treatment needed until symptoms resolve","D. Administer a laxative in the field"],"correct":1,"rationale":"Bowel obstruction is a surgical emergency managed with supportive care and no oral intake, with prompt transport.","difficulty":"Medium"},{"id":"c12_q11","question":"What is the classic presentation of acute renal colic?","options":["A. Painless flank fullness","B. Sudden, severe, colicky flank pain radiating to the groin, with the patient unable to find a comfortable position","C. Chronic, dull back pain relieved by rest","D. Bilateral leg swelling"],"correct":1,"rationale":"Renal colic classically causes sudden severe colicky flank pain, often radiating to the groin, with restless patient movement.","difficulty":"Medium"},{"id":"c12_q12","question":"What dangerous condition should be considered before assuming flank pain is simple renal colic, especially in an older patient?","options":["A. Ruptured or dissecting abdominal aortic aneurysm (AAA)","B. Common cold","C. Simple muscle strain only","D. Mild dehydration"],"correct":0,"rationale":"AAA is a critical mimic of renal colic, especially in older patients with vascular risk factors, and must be considered before assuming a benign cause.","difficulty":"Hard"},{"id":"c12_q13","question":"What does 'pain out of proportion to exam findings' classically suggest?","options":["A. The patient is exaggerating their symptoms","B. A more dangerous underlying process (e.g., mesenteric ischemia, compartment syndrome)","C. A benign, self-limited condition","D. No clinical significance"],"correct":1,"rationale":"Pain out of proportion to exam findings is a classic red flag for serious underlying pathology, not a sign of exaggeration.","difficulty":"Hard"},{"id":"c12_q14","question":"Why is a general 'red flag' mindset valuable across all medical complaints?","options":["A. Because atypical and subtle presentations of serious illness are common, and this mindset catches what a specific checklist might miss","B. Because red flags only apply to trauma patients","C. Because all patients present identically for the same condition","D. Because red flags replace the need for vital sign assessment"],"correct":0,"rationale":"A systematic red-flag mindset helps recognize serious illness across varied and atypical presentations that a narrow, complaint-specific checklist might miss.","difficulty":"Medium"},{"id":"c12_q15","question":"A 74-year-old with a urinary tract infection presents with new confusion, a temperature of 96.2°F, and a heart rate of 118 bpm. What should this raise concern for?","options":["A. Nothing concerning, since there is no fever","B. Possible sepsis — hypothermia plus tachycardia and altered mental status with a known infection source is a concerning pattern, not reassuring","C. A purely psychiatric event unrelated to the UTI","D. Simple dehydration requiring no further evaluation"],"correct":1,"rationale":"Hypothermia (not fever), tachycardia, and altered mental status with a known infection source together suggest sepsis — a low temperature does not exclude this diagnosis.","difficulty":"Hard"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"The Resolved Deficit","presentation":"A 68-year-old man had sudden right-sided facial droop and slurred speech about 40 minutes ago while at a family lunch. By the time EMS arrives, his speech is clear and his face appears symmetric. He feels fine and wants to cancel the ambulance.","vitals":{"bp":"148/86 mmHg","hr":"78 bpm","glucose":"98 mg/dL","exam":"Currently normal facial symmetry and speech"},"question":"What is the appropriate approach to this patient?","options":["A: Cancel transport since the exam is now normal.","B: Treat this as a possible TIA with the same urgency as an active stroke, document the last-known-well/onset time precisely, and transport with hospital notification.","C: Advise the patient to see his primary doctor within the week.","D: Transport only if symptoms recur during the encounter."],"correct":1,"explanation":"A resolved facial droop and speech abnormality is classic for a possible TIA, which cannot be reliably distinguished from an evolving stroke in the field and carries meaningful short-term risk of a subsequent completed stroke. This should be treated with the same urgency as an active stroke, with precise onset-time documentation and prompt transport.","clinicalPearl":"A resolved deficit is not a reason to relax — it's a reason to document the timeline precisely and transport with full urgency."},{"id":"c01_s02","title":"Confusion With a Normal Glucose Twist","presentation":"A 74-year-old woman is found by family with new left arm weakness and confusion. Initial impression suggests possible stroke. On scene, her blood glucose reads 42 mg/dL.","vitals":{"bp":"132/78 mmHg","hr":"92 bpm","glucose":"42 mg/dL","exam":"Left arm weakness, confusion"},"question":"What is the correct next step?","options":["A: Proceed directly to stroke-alert transport without addressing the glucose value.","B: Treat the hypoglycemia per protocol first, since it is a well-known, rapidly correctable stroke mimic, and reassess neurologic status afterward.","C: Ignore the glucose reading since the presentation looks like a clear stroke.","D: Withhold treatment until arrival at the hospital."],"correct":1,"explanation":"Hypoglycemia is a well-known stroke mimic that is rapidly correctable in the field. Treating the hypoglycemia and reassessing neurologic status is the correct next step before finalizing the working diagnosis and destination decision — a focal deficit that resolves with glucose correction is not treated as a stroke alert.","clinicalPearl":"Always check glucose before you commit to a stroke diagnosis in the field — a fixable stroke mimic can save this patient a stroke-center transport they don't need."},{"id":"c01_s03","title":"Gaze Deviation and Neglect","presentation":"A 59-year-old man has sudden onset of right gaze deviation, severe left face and arm weakness, and does not acknowledge that his left arm is weak when asked. Local EMS protocol uses an LVO-screening scale to determine bypass eligibility to an endovascular-capable stroke center.","vitals":{"bp":"168/94 mmHg","hr":"88 bpm","glucose":"110 mg/dL","exam":"Gaze deviation, severe left face+arm weakness, neglect of left arm"},"question":"What should this constellation of findings prompt?","options":["A: A routine transport to the nearest hospital regardless of capability.","B: Application of the LVO-screening scale per protocol, since these findings (gaze deviation, combined severe face+arm weakness, neglect) suggest possible large-vessel occlusion, potentially justifying bypass to an endovascular-capable center.","C: Assumption that this cannot be a stroke because the deficit is too severe.","D: Delaying the stroke alert until arrival at the hospital."],"correct":1,"explanation":"Gaze deviation, severe combined face and arm weakness, and neglect of the affected limb are LVO-suspicious findings. Per local protocol using an LVO-screening scale, this presentation may justify bypassing a closer, non-endovascular-capable hospital in favor of an endovascular-capable stroke center.","clinicalPearl":"Gaze deviation plus neglect plus severe combined weakness is the pattern that makes an LVO-screening scale worth applying — it can change where this patient needs to go."}]},"c02":{"chapter":"c02","cases":[{"id":"c02_s01","title":"The Already-Stopped Seizure","presentation":"A 34-year-old man with known epilepsy is found postictal by coworkers after a witnessed generalized seizure that lasted about 90 seconds and has since stopped. He is confused but gradually becoming more oriented over the next few minutes.","vitals":{"glucose":"104 mg/dL","hr":"96 bpm","appearance":"Postictal, gradually clearing"},"question":"What is the correct field management?","options":["A: Administer a benzodiazepine to stop the seizure.","B: Protect and monitor, confirm glucose is normal, and allow the postictal state to clear while transporting.","C: Restrain the patient to prevent another seizure.","D: Delay transport until the patient is fully back to baseline on scene."],"correct":1,"explanation":"This is a brief, self-terminated seizure with a normally clearing postictal state in a patient with known epilepsy — no seizure-stopping medication is needed since the seizure has already resolved. Confirming glucose and monitoring for gradual improvement while transporting is appropriate.","clinicalPearl":"A seizure that's already over doesn't need to be 'stopped' — confirm glucose, protect, and let the postictal state clear en route."},{"id":"c02_s02","title":"Confusion With a Hidden Cause","presentation":"A 52-year-old woman with type 1 diabetes is found confused and diaphoretic by her spouse. There is no witnessed seizure. She is oriented to name only.","vitals":{"glucose":"38 mg/dL","hr":"110 bpm","skin":"Diaphoretic"},"question":"What is the most appropriate first action?","options":["A: Assume a primary psychiatric cause and proceed to a mental health facility.","B: Treat the hypoglycemia per protocol, given the low glucose reading and diaphoresis, then reassess mental status.","C: Perform a full neurologic exam before any treatment.","D: Wait to see if she improves spontaneously without intervention."],"correct":1,"explanation":"Diaphoresis and confusion with a documented glucose of 38 mg/dL point to hypoglycemia as the cause of altered mental status — consistent with the AEIOU-TIPS framework's emphasis on checking and treating glucose early. Treating the hypoglycemia is the priority before further workup.","clinicalPearl":"Diaphoresis plus confusion in a diabetic patient is hypoglycemia until proven otherwise — treat first, then reassess."},{"id":"c02_s03","title":"Six Minutes and Counting","presentation":"A 45-year-old man is having continuous generalized tonic-clonic seizure activity. Bystanders report it began approximately 6 minutes before EMS arrival, and it is still ongoing.","vitals":{"duration":"6+ minutes, ongoing","spo2":"89% during active seizure"},"question":"How should this presentation be classified and managed?","options":["A: A normal seizure requiring only observation.","B: Status epilepticus — a time-critical emergency requiring airway/oxygen support, glucose check, and escalation per local ALS protocol with rapid transport.","C: A postictal state requiring no intervention.","D: A psychiatric event requiring police involvement rather than EMS treatment."],"correct":1,"explanation":"Continuous seizure activity exceeding 5 minutes meets the definition of status epilepticus, a time-critical emergency. Field priorities are airway protection, oxygen, a glucose check, and escalation per local ALS protocol (e.g., benzodiazepine per protocol) with rapid transport.","clinicalPearl":"Once a seizure crosses the 5-minute mark, stop waiting and start escalating — status epilepticus doesn't resolve itself reliably."}]},"c03":{"chapter":"c03","cases":[{"id":"c03_s01","title":"Shaky and Sweaty","presentation":"A 29-year-old woman with type 1 diabetes is found shaky, diaphoretic, and anxious after skipping breakfast before a workout. She is alert and able to swallow safely.","vitals":{"glucose":"52 mg/dL","hr":"104 bpm","appearance":"Alert, diaphoretic, shaky"},"question":"What is the appropriate field treatment?","options":["A: IM glucagon, since she is diabetic.","B: Oral glucose, since she is alert, cooperative, and able to swallow safely.","C: IV dextrose only, bypassing oral options.","D: No treatment needed since symptoms are mild."],"correct":1,"explanation":"This is mild hypoglycemia in an alert patient with intact airway reflexes who can safely swallow — oral glucose is the appropriate first-line treatment rather than IM glucagon or IV dextrose, which are reserved for patients who cannot safely take oral glucose.","clinicalPearl":"If they're awake and can swallow safely, oral glucose is simpler and just as effective as IV or IM routes."},{"id":"c03_s02","title":"Vomiting With a Near-Normal Glucose","presentation":"A 41-year-old man with type 2 diabetes on an SGLT2-inhibitor medication presents with two days of vomiting, abdominal pain, and unusually deep, rapid breathing. His glucose reads 175 mg/dL.","vitals":{"glucose":"175 mg/dL","rr":"28/min, deep pattern","breath":"Fruity odor noted"},"question":"What should this presentation raise suspicion for, despite the near-normal glucose?","options":["A: This cannot be a diabetic emergency since the glucose is not significantly elevated.","B: Euglycemic DKA, given the SGLT2-inhibitor use, Kussmaul-pattern breathing, fruity breath odor, and vomiting/abdominal pain.","C: Simple viral gastroenteritis unrelated to his diabetes.","D: HHS, given his type 2 diabetes history."],"correct":1,"explanation":"SGLT2-inhibitor use combined with Kussmaul respirations, fruity breath odor, and vomiting/abdominal pain is the classic presentation of euglycemic DKA — a normal or near-normal glucose does not rule out DKA in this context, and roughly 10% of DKA presents this way.","clinicalPearl":"SGLT2 inhibitor plus a DKA-looking picture with a normal-ish glucose is the textbook setup for euglycemic DKA — don't let the glucose number reassure you."},{"id":"c03_s03","title":"Days of Decline","presentation":"An 78-year-old woman with type 2 diabetes has become progressively more confused and lethargic over three days, with poor oral intake and profound dry mucous membranes. Her glucose reads 720 mg/dL.","vitals":{"glucose":"720 mg/dL","appearance":"Obtunded, severely dehydrated","rr":"Near-normal pattern"},"question":"What does this presentation most likely represent, and what is the field management priority?","options":["A: DKA — administer field insulin immediately.","B: HHS — provide supportive care (oxygen, IV fluids per protocol, monitoring), protect the airway, and transport rapidly for definitive hospital treatment.","C: Simple hypoglycemia — administer oral glucose.","D: A primary psychiatric condition unrelated to her diabetes."],"correct":1,"explanation":"Severe hyperglycemia, profound dehydration, slower multi-day onset, prominent obtundation, and a near-normal respiratory pattern (rather than Kussmaul) in an older type 2 diabetic patient are classic for HHS rather than DKA. Field management is supportive care and rapid transport — insulin administration is a hospital-level intervention, not a field one.","clinicalPearl":"Slow onset, severe dehydration, profound confusion, and sky-high glucose without Kussmaul breathing points toward HHS, not DKA — support and transport, don't try to fix the glucose in the field."}]},"c04":{"chapter":"c04","cases":[{"id":"c04_s01","title":"The Quiet Chest","presentation":"A 24-year-old woman with known asthma has been wheezing loudly for the past hour. On reassessment, the wheeze is now much quieter, and she appears more distressed, using accessory muscles heavily and unable to speak more than one word at a time.","vitals":{"rr":"34/min","spo2":"89% on room air","appearance":"Severe distress, one-word speech"},"question":"How should the quieter wheeze be interpreted?","options":["A: As a sign of improvement — the wheeze is quieter, so escalate down.","B: As a warning sign of worsening obstruction approaching a silent chest, requiring immediate escalation of treatment and transport.","C: As unrelated to her respiratory status.","D: As an indication that bronchodilator therapy should be stopped."],"correct":1,"explanation":"A quieting wheeze combined with worsening distress, accessory muscle use, and inability to speak in full sentences indicates worsening airway obstruction — not improvement. This pattern (mirroring the pediatric respiratory-failure teaching point) should prompt immediate escalation rather than reassurance.","clinicalPearl":"A quieter wheeze with more distress is a red flag, not relief — check for a developing silent chest before you relax."},{"id":"c04_s02","title":"The Hesitant Oxygen Decision","presentation":"A 68-year-old man with known COPD presents with increased dyspnea and an SpO2 of 84% on room air. A new EMT hesitates to apply oxygen, citing concern about 'knocking out his hypoxic drive.'","vitals":{"spo2":"84% room air","rr":"26/min","appearance":"Increased work of breathing"},"question":"What is the correct approach to oxygen administration here?","options":["A: Withhold oxygen entirely to avoid suppressing his respiratory drive.","B: Apply titrated oxygen targeting approximately 88-92% SpO2 — withholding oxygen from a hypoxic patient risks harmful tissue hypoxia and is not supported by current evidence.","C: Apply 100% oxygen with no titration.","D: Delay oxygen until arrival at the hospital."],"correct":1,"explanation":"The 'hypoxic drive' concern is an outdated oversimplification. Current guidance is titrated oxygen therapy to a target of roughly 88-92% SpO2 in COPD exacerbation — enough to correct dangerous hypoxia without unnecessary over-oxygenation. Withholding oxygen due to hypoxic-drive fears creates real risk of harmful tissue hypoxia.","clinicalPearl":"Don't withhold oxygen from a hypoxic COPD patient — titrate to 88-92%, don't avoid treatment altogether."},{"id":"c04_s03","title":"Blue Bloater vs. Pink Puffer","presentation":"Two patients present with dyspnea and known COPD. Patient A is stocky with a chronic productive cough and cyanotic lips. Patient B is thin, barrel-chested, and breathing through pursed lips.","vitals":{"patientA":"Productive cough, cyanotic, stocky build","patientB":"Thin, barrel chest, pursed-lip breathing"},"question":"What classic COPD phenotypes do these two presentations represent?","options":["A: Both patients have identical presentations with no distinguishing features.","B: Patient A fits the classic 'blue bloater' (chronic bronchitis) pattern; Patient B fits the classic 'pink puffer' (emphysema) pattern — both are under the COPD umbrella and often overlap in practice.","C: Patient A has asthma; Patient B has pneumonia.","D: These presentations are unrelated to COPD."],"correct":1,"explanation":"Patient A's productive cough and cyanotic, stocky appearance is classic for chronic bronchitis ('blue bloater'); Patient B's thin, barrel-chested build with pursed-lip breathing is classic for emphysema ('pink puffer'). Both fall under COPD, and real patients often show overlapping features of both classic archetypes.","clinicalPearl":"Blue bloater and pink puffer are teaching archetypes, not strict categories — most real COPD patients show a mix of both patterns."}]},"c05":{"chapter":"c05","cases":[{"id":"c05_s01","title":"Headache and Vision Changes at 34 Weeks","presentation":"A 29-year-old woman at 34 weeks gestation reports a severe headache and 'seeing spots' for the past hour. Her blood pressure reads 162/108 mmHg. She has no prior history of hypertension.","vitals":{"bp":"162/108 mmHg","gestation":"34 weeks","symptoms":"Severe headache, visual spots"},"question":"How should this presentation be managed?","options":["A: Reassure her that headaches are common in pregnancy and no action is needed.","B: Treat as suspected preeclampsia — position in left lateral tilt, minimize stimulation, monitor BP closely, and transport to an obstetric-capable facility.","C: Administer an oral analgesic and observe without transport.","D: Delay any action until the headache worsens further."],"correct":1,"explanation":"New-onset severe headache and visual disturbances combined with markedly elevated blood pressure past 20 weeks gestation are classic warning signs of preeclampsia. This should prompt left lateral positioning, minimizing stimulation, close BP monitoring, and transport to a facility with obstetric capability — not reassurance or delay.","clinicalPearl":"Headache plus visual changes plus high blood pressure in pregnancy is a preeclampsia pattern until proven otherwise."},{"id":"c05_s02","title":"Seizure at 37 Weeks","presentation":"A 33-year-old woman at 37 weeks gestation, with a known diagnosis of preeclampsia, is witnessed having a generalized tonic-clonic seizure that is now ongoing for about 90 seconds.","vitals":{"gestation":"37 weeks","activity":"Active generalized seizure","history":"Known preeclampsia"},"question":"What is the correct field approach?","options":["A: Place the patient supine and wait for the seizure to resolve on its own with no positioning considerations.","B: Apply standard seizure airway/injury precautions, use left lateral positioning once feasible, minimize stimulation, and transport rapidly — this is eclampsia until proven otherwise.","C: Delay any intervention since seizures in pregnancy are expected and benign.","D: Administer oral glucose as the primary intervention."],"correct":1,"explanation":"A new seizure in a patient with known preeclampsia meets the definition of eclampsia — a true obstetric emergency. Field management follows standard seizure precautions (airway protection, injury prevention) with pregnancy-specific left lateral positioning once feasible, minimized stimulation, and rapid transport; magnesium sulfate is the definitive treatment per local ALS protocol.","clinicalPearl":"A seizure in a preeclamptic patient is eclampsia until proven otherwise — treat it as the true obstetric emergency it is."},{"id":"c05_s03","title":"Epigastric Pain Overlooked","presentation":"A 26-year-old woman at 31 weeks gestation presents with epigastric pain that she and her family initially attribute to heartburn. Her blood pressure reads 150/98 mmHg, which is new for her.","vitals":{"bp":"150/98 mmHg","gestation":"31 weeks","symptoms":"Epigastric pain, attributed to heartburn by family"},"question":"How should the epigastric pain be interpreted in this context?","options":["A: As simple heartburn requiring no further evaluation, per the family's assessment.","B: As a possible sign of liver involvement in worsening preeclampsia, given the new hypertension — this should not be dismissed as routine heartburn.","C: As unrelated to her pregnancy or blood pressure.","D: As a sign of labor onset requiring no blood pressure monitoring."],"correct":1,"explanation":"Right upper quadrant or epigastric pain combined with new hypertension in pregnancy should raise concern for liver involvement in worsening preeclampsia, not be dismissed as simple heartburn. This warrants treating the situation as a potential obstetric emergency with appropriate monitoring and transport.","clinicalPearl":"Epigastric pain plus new hypertension in pregnancy is not 'just heartburn' — it can be a preeclampsia warning sign."}]},"c06":{"chapter":"c06","cases":[{"id":"c06_s01","title":"Weapon Visible on Approach","presentation":"EMS is dispatched for a 'person acting erratically.' On approach, the crew observes the patient pacing on the porch, shouting, and appears to be holding a knife.","vitals":{"scene":"Weapon visible, patient agitated and shouting"},"question":"What is the correct first action?","options":["A: Approach immediately to begin a medical assessment.","B: Stage at a safe distance and involve law enforcement per local protocol before any approach.","C: Call out to the patient to drop the weapon and walk toward them.","D: Attempt de-escalation techniques while standing close to the patient."],"correct":1,"explanation":"A visible weapon and an agitated, shouting patient represent a credible scene-safety concern. The correct response is to stage at a safe distance and involve law enforcement per local protocol before any provider approaches — provider safety must be established before patient contact can safely occur.","clinicalPearl":"A visible weapon changes everything — stage and call for law enforcement before you get close, no matter how urgent the call sounds."},{"id":"c06_s02","title":"SEA-3 in Practice","presentation":"EMS is called to check on a 45-year-old man reported as 'not himself.' On scene, he is disheveled, has not bathed in what appears to be days, paces continuously, and speaks in a rapid, tangential, difficult-to-follow manner.","vitals":{"appearance":"Disheveled, poor hygiene","activity":"Continuous pacing","speech":"Rapid, tangential"},"question":"How should this presentation be organized using the SEA-3 framework?","options":["A: These findings are unrelated and should be assessed independently with no combined significance.","B: Appearance (disheveled/poor hygiene), Activity (pacing), and Speech (rapid, tangential) together suggest a higher-risk overall picture than any single finding alone, warranting careful, calm assessment.","C: This presentation requires no further behavioral assessment since no weapon is present.","D: This is simply a medical complaint requiring no behavioral framework."],"correct":1,"explanation":"Using SEA-3, the poor grooming/hygiene (Appearance), continuous pacing (Activity), and rapid tangential speech (Speech) together paint a more complete and concerning clinical picture than any single finding alone, guiding a careful, calm, structured assessment.","clinicalPearl":"SEA-3 findings compound — several concerning findings together tell you more than any one finding does alone."},{"id":"c06_s03","title":"Respecting a Competent Refusal","presentation":"A 38-year-old woman called EMS during a panic attack that has since resolved. She is alert, oriented, and coherent, and after discussing risks and benefits, clearly and repeatedly declines transport to the hospital.","vitals":{"mentalStatus":"Alert, oriented x4, coherent","decision":"Repeated, clear refusal after risk/benefit discussion"},"question":"What is the correct approach?","options":["A: Physically restrain and transport her against her wishes.","B: Document the informed refusal per protocol, provide appropriate resources/follow-up guidance, and respect her autonomy as a competent patient.","C: Leave without any documentation or resource information, considering the call complete.","D: Continue to ask the same questions repeatedly until she agrees to transport."],"correct":1,"explanation":"This patient demonstrates capacity (alert, oriented, coherent) and has made a clear, informed decision to refuse transport. The correct approach is to document the informed refusal per protocol and provide appropriate resources — respecting her autonomy. Leaving without documentation, however, would risk being interpreted as inadequate care, distinct from abandonment (which involves an incompetent or higher-need patient losing continuity of care).","clinicalPearl":"A competent, informed refusal isn't abandonment — but skipping the documentation and resource-sharing step is still bad practice."}]},"c07":{"chapter":"c07","cases":[{"id":"c07_s01","title":"Voices and Beliefs","presentation":"A 27-year-old man reports hearing voices telling him to leave his apartment, and separately states with complete conviction that his neighbors have installed cameras to spy on him, despite no evidence of this.","vitals":{"mentalStatus":"Alert, oriented to self only","affect":"Guarded, suspicious"},"question":"How should these two findings be classified?","options":["A: Both findings are delusions.","B: The voices are a hallucination; the belief about being watched is a delusion.","C: Both findings are hallucinations.","D: Neither finding is clinically significant."],"correct":1,"explanation":"Hearing voices with no external source is a hallucination (a false sensory perception); the fixed, evidence-resistant belief about being surveilled is a delusion (a false belief). Field management for both is the same calm, non-confrontational, non-arguing approach, with attention to safe assessment and transport.","clinicalPearl":"Voices = hallucination (perception); unshakeable belief = delusion (belief) — different phenomena, same calm approach."},{"id":"c07_s02","title":"Chest Tightness With a Panic History","presentation":"A 31-year-old woman with a known history of panic disorder calls EMS for sudden chest tightness, rapid breathing, dizziness, and a feeling of impending doom. She has had similar episodes before that resolved without treatment.","vitals":{"hr":"128 bpm","rr":"26/min","spo2":"97%","ecg":"Not yet obtained"},"question":"What is the correct approach given her panic disorder history?","options":["A: Assume this is another panic attack and skip further evaluation given her history.","B: Still perform a medical rule-out (ECG, vitals, glucose) rather than assuming panic disorder from history alone, since panic-like symptoms can mimic or coexist with real medical emergencies.","C: Refuse care since panic disorder is a psychiatric, not medical, condition.","D: Transport without any assessment since her history is already known."],"correct":1,"explanation":"Even with a known panic disorder history, chest tightness, tachycardia, and dyspnea warrant a proper medical rule-out (ECG, vital signs, glucose) rather than assuming the presentation is 'just' a panic attack, since true medical emergencies can present identically or coexist with panic symptoms.","clinicalPearl":"A panic disorder history doesn't exempt a patient from a cardiac rule-out — treat the symptoms, not just the label."},{"id":"c07_s03","title":"The Direct Question","presentation":"A 22-year-old man appears withdrawn and tearful after a recent breakup, describing feeling hopeless. A new EMT hesitates to ask about suicidal thoughts, worried that asking might 'give him the idea.'","vitals":{"affect":"Tearful, withdrawn","mentalStatus":"Alert, oriented"},"question":"What is the correct approach to assessing suicide risk here?","options":["A: Avoid the topic entirely to prevent 'planting the idea.'","B: Ask directly and non-judgmentally about suicidal thoughts — this does not increase risk and is an appropriate, necessary assessment step.","C: Only ask if the patient brings it up first.","D: Assume there is no risk since he has not mentioned self-harm."],"correct":1,"explanation":"Direct, non-judgmental questioning about suicidal ideation does not increase risk — this is a well-established finding and standard EMS teaching. It is an appropriate and necessary part of assessing a patient presenting with hopelessness and low mood.","clinicalPearl":"Asking about suicide doesn't cause it — avoiding the question just means you might miss a high-risk patient."}]},"c08":{"chapter":"c08","cases":[{"id":"c08_s01","title":"Three Days Since the Last Drink","presentation":"A 52-year-old man with a history of heavy alcohol use is found by family severely confused, tremulous, diaphoretic, and reportedly 'seeing bugs crawling on the walls.' Family reports his last drink was about 72 hours ago.","vitals":{"hr":"128 bpm","bp":"168/98 mmHg","temp":"38.6°C","appearance":"Severely confused, tremulous, diaphoretic"},"question":"What should this presentation be recognized as, and how should it be managed?","options":["A: Mild, expected alcohol withdrawal requiring only reassurance and observation.","B: Delirium tremens — a life-threatening emergency requiring prompt recognition, supportive care (IV access, monitoring), and transport.","C: A primary psychiatric break unrelated to his alcohol use.","D: A normal finding requiring no intervention."],"correct":1,"explanation":"Severe confusion, autonomic instability (tachycardia, hypertension, fever, diaphoresis), tremor, and tactile hallucinations beginning 72 hours after the last drink are classic for delirium tremens — a true, life-threatening medical emergency, not simple withdrawal to be managed with reassurance alone.","clinicalPearl":"DTs shows up days later, not hours later — and it's a real medical emergency, not just 'bad withdrawal.'"},{"id":"c08_s02","title":"Pinpoint Pupils and Slow Breathing","presentation":"A 24-year-old man is found unresponsive with slow, shallow respirations and pinpoint pupils near a scene with drug paraphernalia present.","vitals":{"rr":"6/min, shallow","pupils":"Pinpoint, bilateral","spo2":"82% room air"},"question":"What is the correct field priority?","options":["A: Focus primarily on obtaining a full medication history before intervening.","B: Treat as opioid intoxication and prioritize airway/ventilation support immediately, since this is fundamentally a respiratory emergency.","C: Assume a primary cardiac event and prepare for defibrillation.","D: Wait for family to arrive before starting any intervention."],"correct":1,"explanation":"Pinpoint pupils, respiratory depression, and altered mental status near drug paraphernalia are classic for opioid intoxication. This is fundamentally a respiratory/airway emergency, and ventilatory support is the immediate priority (with naloxone administration per local protocol as adjunct treatment).","clinicalPearl":"Pinpoint pupils plus slow breathing is a breathing emergency first — support ventilation, don't wait on history-taking."},{"id":"c08_s03","title":"Palpitations in a Patient With Anorexia","presentation":"A 19-year-old woman with a known history of anorexia nervosa reports palpitations and lightheadedness. A new EMT suggests this is 'just anxiety' given her psychiatric history and considers skipping cardiac assessment.","vitals":{"hr":"irregular, 118 bpm","appearance":"Thin, fatigued"},"question":"What is the correct approach?","options":["A: Treat this as anxiety related to her eating disorder and skip cardiac evaluation.","B: Evaluate her cardiac symptoms with the same seriousness as any other patient, including ECG/monitoring where available, given the real arrhythmia risk from electrolyte disturbances in eating disorders.","C: Refuse assessment since her presentation is primarily psychiatric.","D: Only check her weight and skip vital signs."],"correct":1,"explanation":"Patients with eating disorders carry genuine cardiac arrhythmia risk from electrolyte disturbances such as hypokalemia. Palpitations and lightheadedness in this population should be evaluated with full medical seriousness, including ECG monitoring where available, rather than being dismissed as purely anxiety-related.","clinicalPearl":"Eating disorder plus cardiac symptoms is a real medical emergency risk — don't let the psychiatric history distract from a genuine arrhythmia workup."}]},"c09":{"chapter":"c09","cases":[{"id":"c09_s01","title":"Sudden Confusion, Normal Baseline","presentation":"An 84-year-old woman, described by her daughter as 'sharp as a tack' until this morning, is now acutely confused, unable to recognize familiar family members, with symptoms fluctuating over the past several hours.","vitals":{"glucose":"88 mg/dL","hr":"104 bpm","temp":"38.2°C","appearance":"Acutely confused, fluctuating"},"question":"How should this presentation be classified and approached?","options":["A: As new-onset dementia, since she is elderly and confused.","B: As delirium until proven otherwise, given the acute onset and fluctuating course in a patient with a previously normal baseline — actively search for a reversible cause.","C: As normal aging requiring no further evaluation.","D: As a purely psychiatric presentation."],"correct":1,"explanation":"Acute onset, fluctuating confusion in a patient with a documented normal cognitive baseline is delirium until proven otherwise — not a new dementia diagnosis made in the field. The mild fever and tachycardia should prompt investigation for a reversible cause such as infection.","clinicalPearl":"A previously sharp patient who's suddenly confused is delirium until proven otherwise — go looking for the reversible cause."},{"id":"c09_s02","title":"Worsening in a Known Dementia Patient","presentation":"A 78-year-old man with known moderate dementia is brought in by his caregiver, who reports he is 'much more confused than his usual self' over the past day, along with new urinary urgency and mild suprapubic discomfort.","vitals":{"baseline":"Moderate dementia per caregiver, previously stable","appearance":"More confused than usual baseline","symptoms":"New urinary urgency, suprapubic discomfort"},"question":"What is the correct interpretation of this acute change?","options":["A: This is simply his dementia progressing naturally and requires no further workup.","B: This represents a possible superimposed delirium — likely triggered by a urinary tract infection given the new urinary symptoms — and warrants evaluation rather than dismissal.","C: This is unrelated to his cognitive baseline and requires no action.","D: This should be treated only as a behavioral emergency."],"correct":1,"explanation":"A sudden worsening from a known, stable dementia baseline — especially with new urinary symptoms suggesting a possible UTI — should be recognized as possible superimposed delirium rather than simply attributed to dementia progression. UTI is a classic reversible cause of delirium in older adults.","clinicalPearl":"Known dementia doesn't mean 'nothing to investigate' when a caregiver reports a real change from baseline — look for a delirium trigger like UTI."},{"id":"c09_s03","title":"No Chest Pain, But Something's Wrong","presentation":"A 81-year-old man reports only mild fatigue and slight shortness of breath for the past day, with no chest pain. His family says he 'just doesn't seem himself.'","vitals":{"hr":"96 bpm, irregular","rr":"20/min","appearance":"Mildly fatigued, no distress"},"question":"Should the absence of chest pain reassure the provider that this is not a cardiac event?","options":["A: Yes, absence of chest pain reliably rules out MI at any age.","B: No — older adults can present with 'silent MI' (confusion, weakness, or dyspnea alone, without chest pain), so this warrants full cardiac evaluation despite the mild-seeming presentation.","C: Yes, but only in patients under 70.","D: The family's report is irrelevant to the clinical picture."],"correct":1,"explanation":"Older adults frequently present with 'silent MI' — myocardial infarction without chest pain, instead showing as vague symptoms like fatigue, weakness, or mild dyspnea. The family's observation that he 'doesn't seem himself,' combined with an irregular heart rate, warrants full cardiac evaluation despite the deceptively mild presentation.","clinicalPearl":"No chest pain doesn't mean no heart attack in an older patient — a vague 'not himself' complaint deserves a full workup."}]},"c10":{"chapter":"c10","cases":[{"id":"c10_s01","title":"Dizzy Before the Fall","presentation":"An 80-year-old man fell in his kitchen. He tells you he felt lightheaded and had heart palpitations just before he went down, and doesn't recall hitting the floor.","vitals":{"hr":"irregular, 132 bpm","bp":"108/68 mmHg","glucose":"102 mg/dL"},"question":"How should this fall be approached?","options":["A: As a simple mechanical trip requiring only wound care.","B: As a possible medical cause of the fall (e.g., cardiac arrhythmia), given the preceding dizziness and palpitations — investigate the cardiac cause in addition to any injury.","C: As unrelated to any cardiac issue since he is currently conscious.","D: As a psychiatric event."],"correct":1,"explanation":"Preceding dizziness and palpitations, along with an irregular, rapid heart rate, suggest this fall may have been caused by a cardiac arrhythmia rather than a simple mechanical trip. The fall should be treated as a potential symptom of an underlying medical emergency, with full cardiac evaluation alongside injury assessment.","clinicalPearl":"Ask what happened right before the fall — preceding symptoms can reveal a medical cause you'd otherwise miss."},{"id":"c10_s02","title":"Minor Bump, Major Medication","presentation":"A 76-year-old woman on warfarin for atrial fibrillation reports a minor bump to her forehead after tripping on a rug. She feels completely fine and has no current neurologic complaints.","vitals":{"mentalStatus":"Alert, oriented x4, no deficits","medication":"Warfarin for atrial fibrillation"},"question":"What is the correct approach given her anticoagulant use?","options":["A: No further concern needed since she feels fine and the bump was minor.","B: Recognize the elevated intracranial hemorrhage risk from anticoagulation despite the minor mechanism and reassuring current exam, and communicate this clearly to the receiving facility.","C: Discontinue her warfarin immediately in the field.","D: Assume anticoagulant use is irrelevant to a minor head bump."],"correct":1,"explanation":"Anticoagulant use combined with head injury — even a seemingly minor bump with a currently normal exam — carries meaningfully elevated risk of intracranial hemorrhage that can develop with delayed onset. This should be clearly flagged and communicated at handoff rather than dismissed based on the reassuring initial presentation.","clinicalPearl":"A normal exam right after a minor head bump doesn't rule out a bleed in a patient on blood thinners — always flag the anticoagulant history."},{"id":"c10_s03","title":"A Caregiver Who Won't Step Away","presentation":"EMS is called for an 88-year-old woman with a new bruise pattern on her upper arms that seems inconsistent with the reported mechanism (a fall from standing). Her adult son insists on staying in the room and answers every question before she can respond, despite her being alert and able to speak.","vitals":{"mentalStatus":"Alert, oriented","exam":"Bruise pattern on bilateral upper arms, inconsistent with reported fall mechanism"},"question":"What is the correct approach to this situation?","options":["A: Confront the son directly about the inconsistent bruising and controlling behavior.","B: Provide standard medical care, document the objective findings (bruise pattern, mechanism inconsistency, caregiver behavior) factually, and report reasonable suspicion through appropriate channels per local policy.","C: Ignore the findings since the patient has not directly stated any concern.","D: Refuse to treat the patient until the son leaves the room."],"correct":1,"explanation":"Bruise pattern inconsistent with the stated mechanism, combined with a caregiver who won't allow the patient to answer independently, are recognized concern-raising findings for possible elder abuse. The correct EMS response is standard care, objective documentation, and reporting through appropriate channels — not direct confrontation or assumption of guilt.","clinicalPearl":"Recognize and report, don't investigate or accuse — document exactly what you see and let the appropriate channel handle it from there."}]},"c11":{"chapter":"c11","cases":[{"id":"c11_s01","title":"Pinpoint Pupils in an Alley","presentation":"A 29-year-old man is found unresponsive in an alley with a respiratory rate of 4/min, pinpoint pupils, and drug paraphernalia nearby.","vitals":{"rr":"4/min","pupils":"Pinpoint, bilateral","spo2":"78% room air"},"question":"What toxidrome does this match, and what is the field priority?","options":["A: Anticholinergic toxidrome — administer IV fluids as the priority.","B: Opioid toxidrome — prioritize airway/ventilation support immediately, since this is fundamentally a respiratory emergency.","C: Cholinergic toxidrome — administer atropine as the sole intervention.","D: Sympathomimetic toxidrome — sedate the patient."],"correct":1,"explanation":"Pinpoint pupils, severe respiratory depression, and altered mental status match the opioid toxidrome. This is fundamentally a respiratory emergency, so airway/ventilation support is the immediate priority, with naloxone as an adjunct per local protocol.","clinicalPearl":"Recognize the pattern and act — pinpoint pupils plus slow breathing means ventilate first, identify the exact substance later."},{"id":"c11_s02","title":"Confused and Sweating on the Trail","presentation":"A 34-year-old hiker is found confused and stumbling on a hot afternoon. She is still visibly sweating, and her core temperature reads 105.2°F (40.7°C).","vitals":{"temp":"105.2°F (40.7°C)","mentalStatus":"Confused, stumbling","skin":"Sweating"},"question":"Does the presence of sweating change the diagnosis?","options":["A: Yes, sweating rules out heat stroke and this should be treated as heat exhaustion.","B: No — altered mental status combined with a significantly elevated core temperature still meets the definition of heat stroke, regardless of sweating. Begin aggressive cooling and rapid transport.","C: Sweating means this is not a heat-related illness at all.","D: This finding is irrelevant to field management."],"correct":1,"explanation":"The presence of sweating does not rule out heat stroke — some heat stroke patients, especially with exertional causes, continue to sweat. The defining combination is altered mental status plus significantly elevated core temperature, both present here. This is heat stroke, a true emergency requiring aggressive cooling and rapid transport.","clinicalPearl":"Don't let sweating fool you — confused plus very hot is heat stroke, sweaty or not."},{"id":"c11_s03","title":"Found Cold and Unresponsive","presentation":"A 58-year-old man is found unresponsive outdoors after an unknown period of cold exposure. He has no palpable pulse and no visible respirations. His core temperature reads 79°F (26°C).","vitals":{"temp":"79°F (26°C)","pulse":"None palpable","breathing":"None visible"},"question":"What is the correct field approach?","options":["A: Withhold resuscitation since the patient is severely hypothermic and appears dead.","B: Begin resuscitation per protocol, handling the patient gently — severe hypothermia can mimic death, and patients have survived with good outcomes after rewarming.","C: Immediately declare death without further assessment.","D: Move the patient rapidly and vigorously to the ambulance to begin transport as fast as possible."],"correct":1,"explanation":"Severe hypothermia can mimic death, and patients have survived prolonged downtime with good neurologic outcomes after rewarming — resuscitation should generally proceed per local protocol rather than being presumed futile. The patient should also be handled gently throughout, since rough movement can trigger a fatal arrhythmia in a severely hypothermic heart.","clinicalPearl":"Not dead until warm and dead — resuscitate a hypothermic arrest patient per protocol, and handle them gently while you do."}]},"c12":{"chapter":"c12","cases":[{"id":"c12_s01","title":"Low Temperature, High Concern","presentation":"A 71-year-old man with a known productive cough for three days is found confused, with a temperature of 95.8°F, heart rate of 122 bpm, and respiratory rate of 26/min. His family says he seemed fine yesterday.","vitals":{"temp":"95.8°F (35.4°C)","hr":"122 bpm","rr":"26/min","appearance":"New confusion"},"question":"How should the low temperature be interpreted in this context?","options":["A: As reassuring, since he does not have a fever.","B: As a possible sign of sepsis — hypothermia combined with tachycardia, tachypnea, and altered mental status in the setting of a likely respiratory infection is a concerning pattern, not a reassuring one.","C: As unrelated to his cough and breathing symptoms.","D: As simple age-related temperature dysregulation requiring no action."],"correct":1,"explanation":"A low temperature in a patient with a likely infection source (productive cough) combined with tachycardia, tachypnea, and new altered mental status is a concerning sepsis pattern — hypothermia, not just fever, can indicate sepsis. This should prompt supportive care and rapid transport with early hospital notification.","clinicalPearl":"A low temperature with signs of infection is not reassuring — it can be sepsis just as much as a fever can."},{"id":"c12_s02","title":"Black, Tarry Stool","presentation":"A 63-year-old man reports several days of black, tarry, foul-smelling stools and now feels lightheaded when standing. He appears pale.","vitals":{"hr":"116 bpm (supine), 138 bpm (standing)","bp":"98/62 mmHg (supine)","appearance":"Pale"},"question":"What does this presentation suggest, and what is the priority?","options":["A: A benign dietary issue unrelated to bleeding.","B: Melena suggesting upper GI bleeding — assess perfusion status (not just the visible history) and treat for possible hypovolemic shock per protocol.","C: A urinary tract problem requiring no GI evaluation.","D: No action needed since there is no visible active bleeding right now."],"correct":1,"explanation":"Black, tarry, foul-smelling stool (melena) is classic for upper GI bleeding. The positional heart rate change and low-normal blood pressure suggest significant blood loss with early compensated shock — perfusion status, not just the history of visible bleeding, should guide the urgency of field management.","clinicalPearl":"Melena plus orthostatic vital sign changes means real blood loss — treat the shock, not just the stool description."},{"id":"c12_s03","title":"Flank Pain in an At-Risk Patient","presentation":"A 68-year-old man with a history of hypertension and smoking presents with sudden, severe left flank pain radiating to his groin. He is restless, unable to find a comfortable position, and reports similar pain to a prior kidney stone.","vitals":{"bp":"156/94 mmHg","hr":"108 bpm","appearance":"Restless, unable to find comfortable position"},"question":"Should this presentation be assumed to be a recurrence of renal colic given his prior history?","options":["A: Yes, since he has a prior history of similar pain, no further consideration is needed.","B: No — while renal colic is plausible, his age and vascular risk factors (hypertension, smoking history) warrant considering a dangerous mimic such as ruptured or dissecting abdominal aortic aneurysm before settling on a benign diagnosis.","C: This presentation requires no urgency regardless of the cause.","D: This is clearly a psychiatric presentation given his restlessness."],"correct":1,"explanation":"Although the presentation is consistent with renal colic and matches the patient's prior history, his age and vascular risk factors (hypertension, smoking) mean a dangerous mimic like AAA must be considered rather than assumed away based on prior similar episodes. Field providers should maintain vigilance and monitor closely rather than treating this as routinely benign.","clinicalPearl":"A prior kidney stone history doesn't rule out AAA today — in an older vascular-risk patient, flank pain deserves a broader differential every time."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"Suspected Stroke Field Recognition and Transport Decision","description":"Sequence for recognizing suspected stroke, ruling out a correctable mimic, and deciding on transport destination.","steps":["Identify a new focal neurologic deficit (current or recently resolved) using a validated stroke scale (e.g., CPSS: facial droop, arm drift, speech abnormality).","Check blood glucose immediately; treat hypoglycemia per protocol if present and reassess neurologic status.","Determine and precisely document the last-known-well time from the patient/bystanders.","Assess for LVO-suspicious findings (gaze deviation, severe combined face+arm weakness, neglect/denial) using a local LVO-screening scale if available.","Provide early hospital notification ('stroke alert') so the receiving facility can prepare.","Transport per local destination protocol — nearest stroke-capable hospital, or bypass to an endovascular-capable center if LVO screen is positive and system design supports it.","Reassess neurologic status serially en route without delaying transport for an extensive exam."]}]},"c02":{"chapter":"c02","algorithms":[{"id":"c02_alg01","title":"Seizure and Altered Mental Status Field Approach","description":"Sequence for assessing and managing a seizing or newly altered adult patient.","steps":["If actively seizing: protect the airway with positioning and suction as needed (never place anything in the mouth), protect the patient from injury, and time the seizure.","Check blood glucose as soon as feasible; treat hypoglycemia per protocol if present.","If the seizure resolves in under 5 minutes: provide postictal supportive care, monitor for gradual improvement, and transport.","If seizure activity reaches 5 minutes or repeats without return to baseline: treat as status epilepticus — escalate per local ALS protocol (airway/oxygen support, benzodiazepine per protocol) and transport rapidly.","If altered but not seizing: check glucose immediately, then work through AEIOU-TIPS for reversible causes.","Gather a focused history from bystanders/family: medications, known seizure disorder, substance use, recent illness or head injury.","Reassess mental status trend continuously; a lack of gradual improvement warrants continued investigation and prompt transport."]}]},"c03":{"chapter":"c03","algorithms":[{"id":"c03_alg01","title":"Suspected Diabetic Emergency Field Approach","description":"Sequence for evaluating altered mental status, vomiting, abdominal pain, or unexplained rapid breathing in a known or possible diabetic patient.","steps":["Check blood glucose immediately in any altered, vomiting, or unusually tachypneic patient with known or suspected diabetes.","If glucose is low: treat hypoglycemia per protocol (oral glucose if awake/cooperative; IV dextrose or IM glucagon per protocol if not) and reassess.","If glucose is high or only mildly elevated with Kussmaul respirations, fruity breath odor, vomiting/abdominal pain, and dehydration: suspect DKA, including euglycemic DKA if glucose is near-normal.","If glucose is very high with profound dehydration, slower onset, minimal respiratory compensation, and prominent altered mental status/obtundation: suspect HHS.","For suspected DKA or HHS: provide supportive care (oxygen as needed, IV access and isotonic fluids per protocol, cardiac monitoring), protect the airway given vomiting risk.","Transport rapidly for definitive hospital treatment (insulin, careful fluid/electrolyte correction) — do not attempt to correct DKA/HHS glucose with field insulin."]}]},"c04":{"chapter":"c04","algorithms":[{"id":"c04_alg01","title":"Acute Asthma/COPD Exacerbation Field Approach","description":"Sequence for assessing and managing an acute asthma or COPD exacerbation.","steps":["Assess severity: ability to speak in full sentences, accessory muscle use, and wheeze intensity — remember a silent chest is more severe than a loud wheeze, not less.","For mild-moderate distress: administer bronchodilator therapy per protocol, position of comfort, monitor closely.","For severe distress or signs of impending failure (altered mental status, exhaustion, silent chest): escalate rapidly, prepare for ventilatory support, transport rapidly.","If known or suspected COPD: apply titrated oxygen targeting approximately 88-92% SpO2 — do not withhold oxygen from a hypoxic patient out of hypoxic-drive concerns.","Reassess frequently; treat a quieting wheeze with worsening distress as a warning sign, not reassurance."]}]},"c05":{"chapter":"c05","algorithms":[{"id":"c05_alg01","title":"Suspected Preeclampsia/Eclampsia Field Approach","description":"Sequence for assessing and managing a pregnant patient with suspected preeclampsia or an active eclamptic seizure.","steps":["Identify hypertension in a pregnant patient (typically past 20 weeks gestation).","Screen for warning signs: proteinuria history, severe/persistent headache, visual disturbances, right upper quadrant/epigastric pain, sudden significant swelling.","If preeclampsia is suspected: position in left lateral tilt or with manual uterine displacement, minimize stimulation, monitor blood pressure closely.","If a new seizure or coma occurs in this patient: treat as eclampsia — apply standard seizure airway and injury-prevention precautions.","Once the seizure allows, position in left lateral tilt; continue to minimize stimulation.","Transport rapidly to an obstetric-capable facility; magnesium sulfate administration for eclampsia follows local ALS protocol.","Continue monitoring for repeat seizure and worsening signs throughout transport."]}]},"c06":{"chapter":"c06","algorithms":[{"id":"c06_alg01","title":"Behavioral Emergency Field Approach","description":"Sequence for safely assessing and de-escalating a patient in behavioral crisis.","steps":["Assess scene safety from a distance before approaching: weapons, exits, patient affect.","If a credible safety concern exists, involve law enforcement per local protocol before approaching.","Once the scene is safe, approach calmly and apply the SEA-3 framework: Safety, Emotional state, Appearance, Activity, Speech.","Apply de-escalation technique: open-ended questions, non-threatening posture and distance, calm even tone, avoid arguing with delusional content.","If de-escalation succeeds: complete assessment and transport with a continued calm approach.","If de-escalation fails and the patient poses immediate danger to self or others: apply restraint per local protocol as a last resort, with appropriate monitoring and documentation.","If the patient refuses care: assess capacity, follow informed-refusal protocol, and ensure continuity of care to avoid abandonment."]}]},"c07":{"chapter":"c07","algorithms":[{"id":"c07_alg01","title":"Psychotic/Mood Disorder and Suicide Risk Field Approach","description":"Sequence for recognizing and safely managing psychotic symptoms, mood disorder presentations, and suicide risk.","steps":["Assess scene safety and check vital signs/glucose to screen for organic/reversible causes when feasible.","For panic-like presentations (chest tightness, dyspnea, tachycardia, fear): perform a proper medical rule-out (ECG, vitals, glucose) rather than assuming panic disorder from history alone.","For psychotic symptoms (delusions, hallucinations): approach calmly, avoid arguing with or challenging the content, and proceed with safe assessment and transport.","For mood symptoms (depressive or manic presentation): assess for safety risks — impaired judgment/risk-taking in mania, suicidal ideation in depression.","Ask directly and non-judgmentally about suicidal ideation when indicated — this does not increase risk.","If suicidal ideation is present with a specific plan, access to lethal means, or prior attempt history: treat as high-risk, apply scene safety considerations, and transport per local protocol."]}]},"c08":{"chapter":"c08","algorithms":[{"id":"c08_alg01","title":"High-Risk Substance-Related and Eating-Disorder Presentation Field Approach","description":"Sequence for recognizing and managing high-risk substance-related and eating-disorder-associated presentations.","steps":["Assess scene safety and obtain vital signs/glucose regardless of a presumed substance or psychiatric cause.","If severe confusion, autonomic instability, tremor, and hallucinations appear roughly 48-96+ hours after last alcohol use: recognize as possible delirium tremens — treat as a life-threatening emergency with supportive care, IV access, monitoring, and transport.","If pinpoint pupils, respiratory depression, and altered mental status are present: recognize as possible opioid intoxication — prioritize airway/ventilation support.","If agitation, tachycardia, hypertension, diaphoresis, and dilated pupils are present: recognize as possible stimulant intoxication — monitor closely for cardiac risk.","If the patient has a known or suspected eating disorder and reports cardiac symptoms (palpitations, syncope, chest discomfort): evaluate with full medical seriousness, including ECG/monitoring where available.","For personality-disorder-associated presentations: maintain calm, consistent, non-judgmental care without attempting a field diagnosis.","Apply core de-escalation principles with heightened vigilance for rapid deterioration across all high-risk presentations."]}]},"c09":{"chapter":"c09","algorithms":[{"id":"c09_alg01","title":"Geriatric Acute Confusion Field Approach","description":"Sequence for evaluating a geriatric patient with new or worsening confusion.","steps":["Establish the patient's cognitive/functional baseline from a caregiver or family member — do not assume based on presentation to an unfamiliar provider alone.","Determine whether the confusion is new or represents an acute change from that baseline.","If new or acutely changed: treat as delirium until proven otherwise.","Check blood glucose immediately.","Search for reversible causes: infection (UTI, pneumonia), medication effects/polypharmacy, hypoxia, electrolyte disturbance, dehydration, urinary retention/constipation, pain, unfamiliar environment/sensory deprivation.","Consider atypical presentations of serious underlying conditions (silent MI, afebrile infection, painless acute abdomen) even when symptoms seem mild.","Transport for evaluation; do not dismiss acute confusion as simply dementia progression or normal aging in the field."]}]},"c10":{"chapter":"c10","algorithms":[{"id":"c10_alg01","title":"Geriatric Fall Assessment Field Approach","description":"Sequence for assessing a geriatric patient after a fall, considering both traumatic and underlying medical causes.","steps":["Ask about the circumstances of the fall: witnessed vs. unwitnessed, any preceding symptoms (dizziness, palpitations, chest discomfort), and ability to recall the event.","Check vital signs and blood glucose to screen for a medical cause of the fall.","Review the patient's medication list, specifically asking about anticoagulant/antiplatelet use.","Perform a thorough injury exam, keeping in mind that older adults may have a blunted pain response masking occult injury.","If anticoagulant use is present with any head injury, treat as elevated intracranial hemorrhage risk regardless of the initial exam, and communicate this clearly at handoff.","If findings suggest a medical cause (arrhythmia, orthostatic hypotension, hypoglycemia, infection), evaluate and manage accordingly rather than treating the fall as purely mechanical."]}]},"c11":{"chapter":"c11","algorithms":[{"id":"c11_alg01","title":"Suspected Toxic Exposure Field Approach","description":"Sequence for assessing and managing a suspected poisoning or overdose.","steps":["Ensure scene safety, especially for exposures involving unknown chemicals or gases.","Support airway, breathing, and circulation as the priority over exact substance identification.","Identify the substance, amount, and time of exposure when possible; bring containers/pills to the hospital.","Check blood glucose regardless of a presumed toxic cause.","Recognize toxidrome patterns (opioid, sympathomimetic, anticholinergic, cholinergic) to guide urgency and specific interventions (e.g., naloxone for opioid toxidrome per protocol).","Transport promptly with all identified substances/containers accompanying the patient."]},{"id":"c11_alg02","title":"Heat and Cold Environmental Emergency Field Approach","description":"Sequence for assessing and managing heat-related and cold-related environmental emergencies.","steps":["Remove the patient from the ongoing environmental extreme.","Assess mental status and estimate severity along the relevant spectrum (heat cramps → exhaustion → stroke; mild → moderate → severe hypothermia).","For heat illness: if altered mental status plus significantly elevated core temperature is present, treat as heat stroke — begin aggressive cooling and rapid transport regardless of sweating status.","For milder heat illness (cramps, exhaustion): rest, cooling, and fluids (oral if tolerated and alert).","For cold illness: handle the patient gently, especially if severe hypothermia is suspected, given arrhythmia risk with rough movement.","Apply passive/active external rewarming appropriate to severity.","For a hypothermic patient in apparent cardiac arrest: provide resuscitation per protocol rather than presuming futility, since hypothermia can mimic death.","Transport promptly with a lower threshold for more severe classifications on either spectrum."]}]},"c12":{"chapter":"c12","algorithms":[{"id":"c12_alg01","title":"Suspected Sepsis Field Recognition and Management","description":"Sequence for recognizing and managing suspected sepsis in the field.","steps":["Identify a suspected or known infection source (respiratory, urinary, wound, etc.).","Check temperature — recognize that both fever and hypothermia can indicate sepsis.","Assess for tachycardia, tachypnea, and altered mental status.","Assess perfusion for signs of progression toward septic shock (delayed capillary refill, cool/mottled or warm/flushed skin, hypotension).","If the pattern fits sepsis: provide supportive care (oxygen as needed, IV access and fluids per protocol, cardiac monitoring).","Transport rapidly with early hospital notification, given the time-sensitive nature of sepsis treatment.","Maintain heightened suspicion in older adults, who may present atypically (e.g., confusion without dramatic fever)."]},{"id":"c12_alg02","title":"Abdominal/Flank Pain Field Differential Approach","description":"Sequence for evaluating abdominal or flank pain with attention to dangerous mimics.","steps":["Characterize the pain: location, radiation, quality (colicky vs. constant), and associated symptoms (vomiting, hematuria, bowel changes).","Assess vital signs and perfusion status.","If GI bleeding signs present (hematemesis, melena, hematochezia): assess perfusion for hypovolemic shock and treat per protocol.","If bowel obstruction pattern present (colicky pain, distension, vomiting, no BM/flatus): provide supportive care, no oral intake, prompt transport.","If flank pain present: consider renal colic, but evaluate for dangerous mimics — especially AAA in older/vascular-risk patients, and pyelonephritis with systemic infection signs.","Apply the general red-flag framework (pain out of proportion to exam, inability to find a comfortable position, altered mental status) regardless of the presumed diagnosis.","Transport promptly, especially when red flags or dangerous mimics cannot be confidently excluded in the field."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"Prehospital Stroke Scale Comparison","headers":["Scale","What It Adds","Components Checked","Primary Use"],"rows":[["CPSS (Cincinnati Prehospital Stroke Scale)","Baseline stroke screening","Facial droop, arm drift, speech abnormality","General stroke recognition"],["LAPSS (Los Angeles Prehospital Stroke Screen)","Adds exclusion criteria (age, glucose, symptom duration, prior seizure/wheelchair history)","Facial droop, grip strength, arm drift, plus exclusion criteria","General stroke recognition with mimic screening"],["RACE (Rapid Arterial oCclusion Evaluation)","Adds LVO-sensitive items","Facial palsy, arm motor, leg motor, gaze deviation, aphasia/agnosia","Large-vessel occlusion (LVO) screening"],["FAST-ED","Adds eye deviation and denial/neglect to FAST","Face, Arm, Speech, Time + Eye deviation, Denial/neglect","Large-vessel occlusion (LVO) screening"]]},{"id":"c01_t02","title":"Ischemic vs. Hemorrhagic Stroke — Field Perspective","headers":["Feature","Ischemic Stroke","Hemorrhagic Stroke"],"rows":[["Mechanism","Obstruction (clot) blocking blood flow","Bleeding into or around brain tissue"],["Relative frequency","Majority of strokes","Minority of strokes"],["Field distinguishability by symptoms","Not reliably distinguishable from hemorrhagic by symptoms alone","Not reliably distinguishable from ischemic by symptoms alone"],["Determination method","Hospital imaging (CT/MRI)","Hospital imaging (CT/MRI)"],["Field priority","Same: recognize, check glucose, document LKW time, transport rapidly","Same: recognize, check glucose, document LKW time, transport rapidly"]]}]},"c02":{"chapter":"c02","tables":[{"id":"c02_t01","title":"AEIOU-TIPS: Reversible Causes of Altered Mental Status","headers":["Letter","Cause"],"rows":[["A","Alcohol"],["E","Epilepsy/seizure (postictal state)"],["I","Insulin (hypoglycemia or hyperglycemia)"],["O","Overdose/opioids"],["U","Uremia/metabolic derangement"],["T","Trauma/temperature (hyperthermia/hypothermia)"],["I","Infection"],["P","Psychiatric"],["S","Stroke/shock"]]}]},"c03":{"chapter":"c03","tables":[{"id":"c03_t01","title":"DKA vs. HHS Comparison","headers":["Feature","DKA","HHS"],"rows":[["Glucose","≥200 mg/dL typically (can be <200 mg/dL — euglycemic DKA, ~10% of cases)","Often >600 mg/dL"],["Ketosis","Present — beta-hydroxybutyrate ≥3.0 mmol/L or urine ketones ≥2+","Minimal or absent"],["Acid-base status","Metabolic acidosis — pH <7.3 and/or bicarbonate <18 mEq/L","Near-normal pH/bicarbonate"],["Osmolality","Variable, less central to diagnosis","Significant hyperosmolality — >320 mOsm/kg"],["Typical patient","More classic in type 1 diabetes, but occurs in type 2 as well","More typical in older adults with type 2 diabetes"],["Onset","Faster, often over hours","Slower, often over days"],["Classic exam findings","Kussmaul respirations, fruity breath, vomiting/abdominal pain","Profound dehydration, prominent altered mental status/obtundation"],["Field management","Supportive care, IV fluids per protocol, airway protection, rapid transport","Supportive care, IV fluids per protocol, airway protection, rapid transport"]]},{"id":"c03_t02","title":"Hypoglycemia Symptom Progression","headers":["Severity","Findings"],"rows":[["Mild","Shakiness, diaphoresis, hunger, anxiety"],["Moderate","Irritability, poor coordination, difficulty concentrating"],["Severe","Confusion, combativeness, seizure, unresponsiveness"]]}]},"c04":{"chapter":"c04","tables":[{"id":"c04_t01","title":"Asthma: Current GINA Step Framework vs. Legacy Phase Language","headers":["GINA 2025 Step (Current)","Symptom Control Pattern","Legacy 'Phase' Language (Historical)","Legacy Phase Description"],"rows":[["Step 1","Symptoms 1-2 days/week or less","Phase 1","Resolves spontaneously or with bronchodilators within 1-2 hours"],["Step 2","Symptoms <3-5 days/week, normal/slightly reduced lung function","Phase 2","Does not respond to bronchodilators alone; needs anti-inflammatory treatment"],["Step 3","Symptoms most days, night waking ≥1x/week, or reduced lung function","Phase 3","More refractory, escalating severity toward respiratory compromise"],["Step 4","Daily symptoms, night waking ≥1x/week, low lung function, or recent exacerbation","Phase 4","Severe, treatment-refractory presentation approaching respiratory failure"]]},{"id":"c04_t02","title":"Chronic Bronchitis vs. Emphysema — Classic Presentations","headers":["Feature","Chronic Bronchitis ('Blue Bloater')","Emphysema ('Pink Puffer')"],"rows":[["Strongest association","Cigarette-smoke exposure","Cigarette-smoke exposure"],["Classic cough","Chronic productive cough","Minimal productive cough"],["Classic body habitus","Stockier build","Thin, barrel-chested"],["Classic color","Cyanotic ('blue')","Pink, with pursed-lip breathing"],["Note","Real patients often show overlapping features of both","Real patients often show overlapping features of both"]]}]},"c05":{"chapter":"c05","tables":[{"id":"c05_t01","title":"Preeclampsia vs. Eclampsia","headers":["Feature","Preeclampsia","Eclampsia"],"rows":[["Core definition","New-onset hypertension (typically >20 weeks) + proteinuria, or hypertension + other organ dysfunction","Preeclampsia + new seizures or coma not attributable to another cause"],["Seizure activity","Absent","Present (defining feature)"],["Warning signs","Severe headache, visual disturbance, RUQ/epigastric pain, sudden edema","Same warning signs, plus active or recent seizure/coma"],["Field priority","Left lateral positioning, minimize stimulation, monitor BP, transport","Seizure precautions, left lateral positioning once feasible, minimize stimulation, rapid transport"],["Definitive treatment","Hospital-level management, often including magnesium sulfate for severe disease","Magnesium sulfate (per local ALS protocol)"]]}]},"c06":{"chapter":"c06","tables":[{"id":"c06_t01","title":"SEA-3 Behavioral Assessment Framework","headers":["Component","What It Assesses"],"rows":[["Safety","Scene and patient safety — weapons, exits, escalation risk"],["Emotional state","Observable mood/affect"],["Appearance","Grooming, hygiene, dress as clues to functioning"],["Activity","Psychomotor activity — agitation, retardation, restlessness"],["Speech","Rate, volume, coherence, content"]]}]},"c07":{"chapter":"c07","tables":[{"id":"c07_t01","title":"Delusion vs. Hallucination","headers":["Feature","Delusion","Hallucination"],"rows":[["Type of phenomenon","False belief","False sensory perception"],["Example","Fixed conviction of being surveilled without evidence","Hearing voices or seeing things with no external stimulus"],["Persists despite evidence?","Yes, by definition","Not applicable — a perception, not a belief"],["Field approach","Calm, non-confrontational; avoid arguing with the content","Calm, non-confrontational; avoid arguing with the content"]]},{"id":"c07_t02","title":"Major Depressive Episode vs. Manic Episode — Field Recognition","headers":["Feature","Major Depressive Episode","Manic Episode"],"rows":[["Mood","Persistent low mood","Elevated or irritable mood"],["Energy/sleep","Low energy, sleep disturbance","Decreased need for sleep"],["Speech","Often slowed","Rapid, pressured"],["Key risk","Suicidal ideation","Impaired judgment, risky/impulsive behavior"]]}]},"c08":{"chapter":"c08","tables":[{"id":"c08_t01","title":"DSM-5-TR Personality Disorder Clusters","headers":["Cluster","Description","Disorders Included"],"rows":[["Cluster A","Odd/eccentric","Paranoid, schizoid, schizotypal"],["Cluster B","Dramatic/emotional/erratic","Antisocial, borderline, histrionic, narcissistic"],["Cluster C","Anxious/fearful","Avoidant, dependent, obsessive-compulsive"]]},{"id":"c08_t02","title":"Substance Intoxication Patterns — Field Recognition","headers":["Class","Classic Findings","Field Priority"],"rows":[["Opioids","Respiratory depression, pinpoint pupils, altered mental status","Airway/ventilation support (naloxone per protocol)"],["Stimulants","Agitation, tachycardia, hypertension, diaphoresis, dilated pupils","Monitor for cardiac risk, calm approach"],["Alcohol/sedative withdrawal","Tremor, anxiety progressing to seizures/DTs (48-96+ hrs)","Supportive care, monitor for DTs, transport"]]}]},"c09":{"chapter":"c09","tables":[{"id":"c09_t01","title":"Delirium vs. Dementia","headers":["Feature","Delirium","Dementia"],"rows":[["Onset","Acute — hours to days","Chronic — months to years"],["Course","Fluctuating","Slowly progressive, generally stable day-to-day"],["Reversibility","Often reversible once cause is treated","Generally not reversible"],["Attention/awareness","Prominently impaired, fluctuates","Relatively preserved until later stages"],["Common causes","Infection, medication effects, hypoxia, electrolyte disturbance, dehydration, urinary retention/constipation, pain","Neurodegenerative disease (e.g., Alzheimer's), vascular changes, other chronic processes"],["Field default","Assume delirium for any new/acute confusion until proven otherwise","Known, stable baseline — sudden worsening should prompt a delirium workup, not be assumed as dementia progression"]]},{"id":"c09_t02","title":"Atypical Geriatric Presentations of Common Conditions","headers":["Condition","Classic Presentation","Atypical Geriatric Presentation"],"rows":[["Myocardial infarction","Chest pain","Confusion, weakness, or dyspnea alone ('silent MI')"],["Infection","Fever","Absent or blunted fever response"],["Acute abdomen","Significant pain","Minimal pain despite significant pathology"]]}]},"c10":{"chapter":"c10","tables":[{"id":"c10_t01","title":"Mechanical Fall vs. Fall With Possible Medical Cause","headers":["Feature","More Consistent With Mechanical Fall","More Consistent With Medical Cause"],"rows":[["Preceding symptoms","None reported — clear trip/slip mechanism","Dizziness, palpitations, chest discomfort, or vision changes before the fall"],["Recall of event","Patient recalls the trip/slip clearly","Patient cannot recall the moment of the fall (possible loss of consciousness)"],["Vital signs","Normal","Arrhythmia, hypotension, or hypoxia present"],["Glucose","Normal","Low or markedly abnormal"],["Field approach","Standard injury assessment and care","Full medical workup (cardiac, glucose, infection screen) in addition to injury assessment"]]},{"id":"c10_t02","title":"High-Risk Medication Classes in Geriatric Trauma","headers":["Medication Class","Key Risk","Field Relevance"],"rows":[["Anticoagulants / antiplatelets","Bleeding, including intracranial hemorrhage","Elevated risk after even minor head injury; can present with delayed symptoms"],["Sedatives/hypnotics","Fall risk from sedation/impaired balance","Consider as a contributing factor in unexplained falls"],["Antihypertensives","Orthostatic hypotension","Consider as a cause of dizziness/fall, especially with position changes"]]}]},"c11":{"chapter":"c11","tables":[{"id":"c11_t01","title":"Common Adult Toxidromes","headers":["Toxidrome","Key Findings","Example Exposure"],"rows":[["Opioid","Respiratory depression, pinpoint pupils, altered mental status","Opioid medications/drugs"],["Sympathomimetic (stimulant)","Agitation, tachycardia, hypertension, diaphoresis, dilated pupils","Cocaine, amphetamines"],["Anticholinergic","Altered mental status, dilated pupils, dry flushed skin, tachycardia, urinary retention","Antihistamines, certain plants/medications"],["Cholinergic","Excessive secretions (salivation, lacrimation, urination, defecation, GI upset), bradycardia, muscle twitching","Organophosphate pesticides"]]},{"id":"c11_t02","title":"Heat Illness Spectrum","headers":["Stage","Mental Status","Core Temperature","Field Management"],"rows":[["Heat cramps","Normal","Usually normal","Rest, fluids, gentle stretching"],["Heat exhaustion","Normal to mildly altered","Elevated, not extreme","Cooling, rest, fluids (oral if tolerated/alert)"],["Heat stroke","Significantly altered (confusion, seizure, coma)","Significantly elevated","Aggressive cooling, rapid transport — sweating does not exclude"]]},{"id":"c11_t03","title":"Hypothermia Spectrum","headers":["Stage","Shivering","Mental Status","Key Risk"],"rows":[["Mild","Present","Mild confusion, intact coordination","Low"],["Moderate","May stop","Worsening confusion, muscle rigidity","Slowed heart rate/breathing"],["Severe","Absent","Significantly altered/unresponsive","Cardiac arrhythmia and arrest; handle gently"]]}]},"c12":{"chapter":"c12","tables":[{"id":"c12_t01","title":"GI Bleeding Presentations","headers":["Presentation","Description","Typical Source"],"rows":[["Hematemesis","Vomiting blood, may look like coffee grounds if partially digested","Upper GI"],["Melena","Black, tarry, foul-smelling stool","Upper GI"],["Hematochezia","Bright red blood per rectum","Typically lower GI (brisk upper GI bleed can also present this way)"]]},{"id":"c12_t02","title":"General Medical Red Flags — 'Sicker Than They Look'","headers":["Red Flag","Why It Matters"],"rows":[["Altered mental status","Can signal a wide range of serious underlying causes regardless of chief complaint"],["Vital signs out of proportion to apparent severity","Tachycardia/tachypnea disproportionate to the complaint suggests a more serious process"],["Pain out of proportion to exam findings","Classic marker for conditions like mesenteric ischemia or compartment syndrome"],["Inability to find a comfortable position","Contrasts with peritoneal irritation (patient lies still); seen in renal colic and other conditions"],["'This feels different/worse than usual'","A chronic-condition patient's own comparison to their baseline is a valuable, often-overlooked signal"]]}]}}};
